                            if (method_predicate) |pred| try instance_member_predicates.put(self.gpa, member_name, pred);
                        } else {
                            try instance_members.append(self.gpa, method_member);
                            if (method_predicate) |pred| try instance_member_predicates.put(self.gpa, member_name, pred);
                        }
