                                    static_members.items,
                                    static_string_idx,
                                    static_number_idx,
                                    static_symbol_idx,
                                ) catch return error.OutOfMemory
                            else
                                self.interner.internObjectTypeWithIndexAndSymbol(
                                    instance_members.items,
                                    string_idx,
                                    number_idx,
                                    symbol_idx,
                                ) catch return error.OutOfMemory;
                            // Register the partial class type under
