                        // alias-decl time. Re-evaluate the mapped
                        // body now under the outer-parameter
                        // substitution so `Partial<{x: number}>`
                        // returns `{ x?: number }`.
                        if (info.body_node != hir_mod.none_node_id and
                            self.hir.kindOf(info.body_node) == .mapped_type)
                        {
                            try self.pushNarrowScope();
                            defer self.popNarrowScope();
                            // Push T → arg_t into the narrow scope so
                            // type-refs inside the mapped body
                            // resolve through `lookupNarrow`.
                            for (info.params, 0..) |param_t, idx| {
                                if (idx >= args.len) break;
                                const tp = self.interner.pool.type_parameter_payloads.items[self.interner.pool.payloadOf(param_t)];
                                const arg_t = subs.get(param_t) orelse continue;
                                try self.recordNarrow(tp.name, arg_t);
                            }
                            const mapped_t = self.evalMappedType(info.body_node) catch info.body;
                            if (allow_alias_display and mapped_t != info.body) {
                                try self.registerAliasDisplayName(mapped_t, r.name, alias_arg_list.items);
                            }
                            return mapped_t;
                        }
                        if (info.body_node != hir_mod.none_node_id and
                            (self.hir.kindOf(info.body_node) == .conditional_type or
                                self.hir.kindOf(info.body_node) == .template_literal_type or
                                self.hir.kindOf(info.body_node) == .type_ref or
                                self.hir.kindOf(info.body_node) == .intersection_type or
                                self.hir.kindOf(info.body_node) == .union_type or
                                self.hir.kindOf(info.body_node) == .indexed_access_type or
                                self.hir.kindOf(info.body_node) == .keyof_type))
                        {
                            try self.pushNarrowScope();
                            defer self.popNarrowScope();
                            for (info.params) |param_t| {
                                if (param_t >= self.interner.pool.typeCount()) continue;
                                if (!self.interner.pool.flagsOf(param_t).is_type_parameter) continue;
                                const tp = self.interner.pool.type_parameter_payloads.items[self.interner.pool.payloadOf(param_t)];
                                const arg_t = subs.get(param_t) orelse continue;
                                try self.recordNarrow(tp.name, arg_t);
                            }
                            const eval_t = self.lowererLowerWithTypeParams(info.body_node) catch info.body;
                            if (allow_alias_display and eval_t != info.body) {
                                try self.registerAliasDisplayName(eval_t, r.name, alias_arg_list.items);
                            }
                            return eval_t;
                        }
                        const instantiated = self.substituteType(info.body, &subs) catch info.body;
                        try self.copyMemberPredicatesFromReceiver(instantiated, info.body);
                        if (allow_alias_display and instantiated != info.body) {
                            try self.registerAliasDisplayName(instantiated, r.name, alias_arg_list.items);
                        }
                        return instantiated;
                    }
                    const name_str = self.string_interner.get(r.name);
                    if (try self.importedTypeRefForLocal(r.name, type_node)) |t| return t;
                    try self.ensureForwardVisibleTypeDeclChecked(type_node, r.name);
                    if (self.typeRefNameExists(r.name) or self.visibleTypeDeclarationExistsAt(type_node, r.name)) {
                        return self.lowerer.lower(type_node);
                    }
                    const args = hir_mod.typeRefArgs(self.hir, type_node);
                    try self.reportUnresolvedCallTypeArgumentNodes(args);
                    for (args) |arg| _ = try self.lowererLowerWithTypeParams(arg);
                    if (!self.typeRefNameAcceptsTypeArgsAt(type_node, r.name, name_str)) {
                        try self.reportCannotFindNameOnce(type_node, r.name);
                    }
                    return types.Primitive.any;
                }
            },
            .typeof_type => {
                // `type T = typeof x` — query the value-namespace for
                // the identifier's TypeId. We reuse the same lookup
                // path identifier expressions go through, so the
                // result honors module-level scoping + nested scopes.
                const tt = hir_mod.typeofTypeOf(self.hir, type_node);
                if (self.hir.kindOf(tt.operand) == .type_ref) {
                    if (try self.virtualCommonJsImportTypeMember(tt.operand, .value)) |import_value_t| return import_value_t;
                }
                if (self.hir.kindOf(tt.operand) == .identifier) {
                    const name = hir_mod.identifierOf(self.hir, tt.operand).name;
                    const raw = self.string_interner.get(name);
                    if (std.mem.startsWith(u8, raw, "Symbol.")) {
                        return types.Primitive.symbol_t;
                    }
                    if (std.mem.eql(u8, raw, "string") or
                        std.mem.eql(u8, raw, "number") or
                        std.mem.eql(u8, raw, "boolean") or
                        std.mem.eql(u8, raw, "bigint") or
                        std.mem.eql(u8, raw, "symbol") or
                        std.mem.eql(u8, raw, "object") or
                        std.mem.eql(u8, raw, "any") or
                        std.mem.eql(u8, raw, "unknown") or
                        std.mem.eql(u8, raw, "never") or
                        std.mem.eql(u8, raw, "void"))
                    {
                        try self.reportTypeOnlyUsedAsValueOnce(tt.operand, name);
                        return types.Primitive.any;
                    }
                    if (self.lookupNarrow(name)) |narrow_t| {
                        if (narrow_t < self.interner.pool.typeCount() and self.interner.pool.flagsOf(narrow_t).is_type_parameter) {
                            const msg = try std.fmt.allocPrint(
                                self.diag_arena.allocator(),
                                "'{s}' only refers to a type, but is being used as a value here.",
                                .{raw},
                            );
                            try self.diagnostics.append(self.gpa, .{
                                .node = tt.operand,
                                .code = TsCodes.type_only_used_as_value,
                                .message = msg,
                            });
                            return types.Primitive.any;
                        }
                    }
                    if (std.mem.indexOfScalar(u8, raw, '.')) |_| {
                        if (try self.typeOfDottedValueReference(raw, type_node)) |dotted_t| {
                            return dotted_t;
                        }
                        if (try self.typeOfQualifiedNamespaceValue(raw, type_node)) |qualified_t| {
                            return qualified_t;
                        }
                        if (try self.reportMissingRootForUnresolvedTypeofDottedQuery(tt.operand, raw)) {
                            return types.Primitive.any;
                        }
                        // For dotted typeof queries (`typeof E.A`, `typeof Z.foo`)
                        // where the root binding IS visible (enum, import-equals
                        // alias, namespace) but the qualified lookup didn't yield
                        // a concrete TypeId, fall back to `any` WITHOUT routing
                        // through `typeOfIdentifier` — that path emits a bogus
                        // `TS2304 Cannot find name 'E.A'` for the full dotted
                        // string since the parser stored the qualified name as a
                        // single identifier. Mirrors tsc's silent fallback for
                        // `typeofAnExportedType.ts` / `typeofANonExportedType.ts`.
                        return types.Primitive.any;
                    }
                    if (self.typeofQueryReferencesOwnDeclaration(type_node, name)) {
                        // `var p: typeof p` — when a PRIOR `var p` declaration
                        // already exists in the same scope, tsc resolves the
                        // `typeof` to that prior binding's static type rather
                        // than treating it as a self-cycle. Mirrors upstream
                        // for `validMultipleVariableDeclarations.ts(25)` and
                        // similar redeclaration-typeof patterns.
                        if (self.priorVarDeclTypeForTypeofSelf(type_node, name)) |prior_t| return prior_t;
                        return types.Primitive.any;
                    }
                    const value_t = self.typeOfIdentifier(tt.operand);
                    try self.reportUnresolvedSimpleTypeofTypeArguments(tt.operand);
                    return value_t;
                }
                _ = try self.lowererLowerWithTypeParams(tt.operand);
                return types.Primitive.unknown;
            },
            .keyof_type => {
                // `keyof T` — re-resolve the operand through the
                // type-name aware path, then evaluate eagerly when
                // the result is a known object type.
                const k = hir_mod.keyofTypeOf(self.hir, type_node);
                const operand = try self.lowererLowerWithTypeParams(k.operand);
                var key_names: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
                defer key_names.deinit(self.gpa);
                if (try self.collectKeyofObjectKeys(operand, &key_names)) {
                    if (key_names.items.len == 0) return types.Primitive.never;
                    var lits: std.ArrayListUnmanaged(TypeId) = .empty;
                    defer lits.deinit(self.gpa);
                    for (key_names.items) |name| {
                        const lit = self.interner.internStringLiteral(name) catch continue;
                        try lits.append(self.gpa, lit);
                    }
                    if (lits.items.len == 1) return lits.items[0];
                    return self.interner.internUnion(lits.items) catch return error.OutOfMemory;
                }
                return self.interner.internKeyof(operand) catch return error.OutOfMemory;
            },
            .indexed_access_type => {
                // `T[K]` — resolve both sides through the narrow-aware
                // path. If T is now an object type and K is a known
                // string literal, return the matching member directly.
                // If K is a union of string literals (typically from
                // `keyof T`), distribute the indexed access over each
                // member, yielding the union of value types.
                const ia = hir_mod.indexedAccessTypeOf(self.hir, type_node);
                const obj = try self.lowererLowerWithTypeParams(ia.object);
                const idx = try self.lowererLowerWithTypeParams(ia.index);
                try self.checkInvalidIndexedAccessType(ia.index, obj, idx);
                try self.checkInvalidMappedObjectIndexedAccessType(ia.object, ia.index);
                if (try self.resolveObjectIndexedAccessType(obj, idx)) |resolved| return resolved;
                return self.interner.internIndexedAccess(obj, idx) catch return error.OutOfMemory;
            },
            .conditional_type => {
                // `T extends U ? X : Y` — eagerly evaluate when neither
                // `T` nor `U` contains an unresolved type parameter.
                // Distributive: when `T` resolves to a union, distribute
                // the conditional across each member and union the
                // results.
                //
                // `[T] extends [U]` — the bracketed tuple-of-one form
                // suppresses distribution. We detect both sides being
                // single-element tuples and unwrap them, evaluating
                // non-distributively.
                //
                // `infer R` placeholders in the extends-side need to
                // be visible to the true-branch (`R`). We push a
                // narrow scope around the conditional, lower the
                // ext side first (registering each infer'd name), then
                // lower the branches.
                const c = hir_mod.conditionalTypeOf(self.hir, type_node);
                try self.checkConditionalInferConstraints(c.extends);
                try self.pushNarrowScope();
                defer self.popNarrowScope();

                // Detect `[T] extends [U]` — both sides are
                // single-element tuples. Unwrap and skip distribution.
                if (self.hir.kindOf(c.check) == .tuple_type and self.hir.kindOf(c.extends) == .tuple_type) {
                    const check_elems = hir_mod.tupleTypeElements(self.hir, c.check);
                    const ext_elems = hir_mod.tupleTypeElements(self.hir, c.extends);
                    if (check_elems.len == 1 and ext_elems.len == 1) {
                        const check = try self.lowererLowerWithTypeParams(check_elems[0]);
                        const ext = try self.lowererLowerWithTypeParams(ext_elems[0]);
                        try self.registerInferNames(ext_elems[0], ext);
                        const tt = try self.lowererLowerWithTypeParams(c.true_branch);
                        const ff = try self.lowererLowerWithTypeParams(c.false_branch);
                        // Non-distributing: evaluate as a single check
                        // (skipping the union-distribute branch).
                        return self.evalConditionalNonDistributing(check, ext, tt, ff, self.typeNodeContainsInfer(ext_elems[0]));
                    }
                }

                const check = try self.lowererLowerWithTypeParams(c.check);
                const ext = try self.lowererLowerWithTypeParams(c.extends);
                try self.registerInferNames(c.extends, ext);
                const tt = try self.lowererLowerWithTypeParams(c.true_branch);
                const ff = try self.lowererLowerWithTypeParams(c.false_branch);
                return self.evalConditional(check, ext, tt, ff, self.typeNodeContainsInfer(c.extends));
            },
            .mapped_type => {
                // `{ [K in T]: V }` — when `T` resolves to a known
                // string-literal union, materialize the result as an
                // object type with one property per literal. Each
                // property's type is the value template with `K`
                // substituted for that literal.
                return self.evalMappedType(type_node);
            },
            .array_type => {
                // `T[]` — recurse on the element through the
                // type-param-aware path so a bound parameter `T`
                // resolves to its TypeParameter id (not the base
                // lowerer's `unknown` placeholder for non-primitive
                // names). Without this, generic call-site inference
                // can't see the indexer pointing at `T` and `id<T>(x:
                // T[]): T[]` would lose `T` after lowering.
                const a = hir_mod.arrayTypeOf(self.hir, type_node);
                const element = try self.lowererLowerWithTypeParams(a.element);
                return self.interner.internArrayType(self.string_interner, element) catch error.OutOfMemory;
            },
            .fn_type, .constructor_type => {
                // `(x: T) => U` — same reasoning as array_type: the
                // base lowerer can't see in-scope type parameters,
                // so each param annotation and the return type need
                // to round-trip through `lowererLowerWithTypeParams`.
                const ft = hir_mod.fnTypeOf(self.hir, type_node);
                const ft_type_params = self.hir.childSlice(ft.type_params_start, ft.type_params_len);
                if (ft_type_params.len > 0) try self.pushNarrowScope();
                defer if (ft_type_params.len > 0) self.popNarrowScope();
                for (ft_type_params) |tp| {
                    if (self.hir.kindOf(tp) != .type_parameter) continue;
                    const tpp = hir_mod.typeParameterOf(self.hir, tp);
                    const placeholder = self.interner.internFreshTypeParameterWithFlags(
                        tpp.name,
                        types.Primitive.unknown,
                        types.Primitive.none,
                        types.Variance.fromHirBits(tpp.variance),
                        tpp.is_const,
                    ) catch return error.OutOfMemory;
                    self.hir.setType(tp, placeholder);
                    try self.recordNarrow(tpp.name, placeholder);
                }
                var captured_tp_ids: std.ArrayListUnmanaged(TypeId) = .empty;
                defer captured_tp_ids.deinit(self.gpa);
                for (ft_type_params) |tp| {
                    if (self.hir.kindOf(tp) != .type_parameter) continue;
                    const tpp = hir_mod.typeParameterOf(self.hir, tp);
                    const constraint: TypeId = if (tpp.constraint != hir_mod.none_node_id)
                        try self.lowererLowerWithTypeParams(tpp.constraint)
                    else
                        types.Primitive.unknown;
                    const def: TypeId = if (tpp.default != hir_mod.none_node_id)
                        try self.lowererLowerWithTypeParams(tpp.default)
                    else
                        types.Primitive.none;
                    const tp_id = if (tpp.constraint == hir_mod.none_node_id and tpp.default == hir_mod.none_node_id)
                        (self.lookupNarrow(tpp.name) orelse self.hir.typeOf(tp))
                    else
                        self.interner.internFreshTypeParameterWithFlags(
                            tpp.name,
                            constraint,
                            def,
                            types.Variance.fromHirBits(tpp.variance),
                            tpp.is_const,
                        ) catch return error.OutOfMemory;
                    self.hir.setType(tp, tp_id);
                    try self.recordNarrow(tpp.name, tp_id);
                    try captured_tp_ids.append(self.gpa, tp_id);
                }
                var fn_param_ts: std.ArrayListUnmanaged(TypeId) = .empty;
                defer fn_param_ts.deinit(self.gpa);
                var fn_param_omittable: std.ArrayListUnmanaged(bool) = .empty;
                defer fn_param_omittable.deinit(self.gpa);
                const fn_params = self.hir.childSlice(ft.params_start, @intCast(ft.params_len));
                var has_rest_param = false;
                var explicit_this_t: TypeId = types.Primitive.none;
                for (fn_params) |p| {
                    if (self.hir.kindOf(p) != .parameter) continue;
                    const pp = hir_mod.parameterOf(self.hir, p);
                    const is_this_param = self.isThisParameter(p);
                    if (pp.flags.is_rest and !is_this_param) has_rest_param = true;
                    var t = if (pp.type_annotation != hir_mod.none_node_id)
                        try self.lowererLowerWithTypeParams(pp.type_annotation)
                    else
                        types.Primitive.any;
                    // TS2370 — same rest-parameter check as the
                    // function-decl path. Function/constructor type
                    // expressions and interface call/method
                    // signatures all flow through this loop.
                    if (pp.flags.is_rest and !is_this_param and pp.type_annotation != hir_mod.none_node_id and
                        !self.restParamAnnotationLooksArrayLike(pp.type_annotation) and
                        !self.restParamTypeIsValidArrayLike(t))
                    {
                        try self.report(p, TsCodes.rest_parameter_must_be_array_type, "A rest parameter must be of an array type.");
                    }
                    if (pp.default_value != hir_mod.none_node_id) {
                        try self.report(p, TsCodes.parameter_initializer_implementation_only, "A parameter initializer is only allowed in a function or constructor implementation.");
                    }
                    if (pp.flags.is_optional or pp.default_value != hir_mod.none_node_id) {
                        t = self.unionWithUndefined(t) catch t;
                    }
                    if (is_this_param) {
                        explicit_this_t = t;
                        continue;
                    }
                    try fn_param_ts.append(self.gpa, t);
                    try fn_param_omittable.append(self.gpa, pp.flags.is_rest or pp.type_annotation == hir_mod.none_node_id or pp.flags.is_optional or pp.default_value != hir_mod.none_node_id or self.parameterTypeAllowsVoidOmission(t));
                }
                const is_predicate = ft.return_type != hir_mod.none_node_id and
                    self.hir.kindOf(ft.return_type) == .type_predicate_type;
                const ret_t = if (ft.return_type != hir_mod.none_node_id)
                    (if (is_predicate) types.Primitive.boolean_t else try self.lowererLowerWithTypeParams(ft.return_type))
                else
                    types.Primitive.any;
                const is_construct = self.hir.kindOf(type_node) == .constructor_type;
                const ft_payload = hir_mod.fnTypeOf(self.hir, type_node);
                const sig = self.interner.internSignatureWithAbstract(
                    fn_param_ts.items,
                    ret_t,
                    is_construct,
                    ft_payload.is_abstract_constructor,
                ) catch return error.OutOfMemory;
                try self.recordSignatureMinArgs(sig, fn_param_omittable.items);
                try self.recordSignatureParamNames(sig, fn_params);
                if (fn_param_ts.items.len == 1 and fn_params.len == 1 and self.hir.kindOf(fn_params[0]) == .parameter) {
                    const only_param = hir_mod.parameterOf(self.hir, fn_params[0]);
                    if (only_param.name != hir_mod.none_node_id and self.hir.kindOf(only_param.name) == .identifier) {
                        try self.appendSignatureParamNameOccurrence(sig, hir_mod.identifierOf(self.hir, only_param.name).name);
                    }
                }
                if (explicit_this_t != types.Primitive.none) try self.signature_this_params.put(self.gpa, sig, explicit_this_t);
                if (is_predicate) {
                    const pred = hir_mod.typePredicateOf(self.hir, ft.return_type);
                    const target_t: TypeId = if (pred.target_type != hir_mod.none_node_id)
                        (self.lowererLowerWithTypeParams(pred.target_type) catch types.Primitive.unknown)
                    else
                        types.Primitive.unknown;
                    try self.signature_predicates.put(self.gpa, sig, .{
                        .param_index = pred.param_index,
                        .target_type = target_t,
                        .target_node = pred.target_type,
                        .is_asserts = pred.is_asserts,
                    });
                }
                if (has_rest_param) try self.rest_signatures.put(self.gpa, sig, {});
                if (captured_tp_ids.items.len > 0) {
                    const owned = captured_tp_ids.toOwnedSlice(self.gpa) catch return error.OutOfMemory;
                    errdefer self.gpa.free(owned);
                    if (self.generic_signature_params.fetchRemove(sig)) |old| {
                        self.gpa.free(old.value);
                    }
                    try self.generic_signature_params.put(self.gpa, sig, owned);
                }
                return sig;
            },
            else => {},
        }
        return self.lowerer.lower(type_node);
    }

    fn literalNumberWithSourceSign(self: *Checker, node: NodeId) f64 {
        var value = hir_mod.literalNumberOf(self.hir, node);
        const src = self.source orelse return value;
        const sp = self.hir.spanOf(node);
        if (sp.start == 0 or sp.start > src.len) return value;
        var i: usize = sp.start;
        while (i > 0) {
            const c = src[i - 1];
            if (c == ' ' or c == '\t' or c == '\r' or c == '\n') {
                i -= 1;
                continue;
            }
            if (c == '-' and value > 0) value = -value;
            break;
        }
        return value;
    }

    fn typeofQueryReferencesOwnDeclaration(self: *Checker, type_node: NodeId, name: hir_mod.StringId) bool {
        var cur = type_node;
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k != .var_decl and k != .let_decl and k != .const_decl) continue;
            const v = hir_mod.varDeclOf(self.hir, cur);
            if (v.type_annotation != type_node) return false;
            if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) return false;
            return hir_mod.identifierOf(self.hir, v.name).name == name;
        }
        return false;
    }

    /// When a `typeof p` query targets the same `var p` it sits in, look
    /// for a PRIOR `var p` declaration in the enclosing block / namespace.
    /// Returns its concrete declared-or-inferred type so a redeclaration
    /// like `var p: typeof p;` (after `var p: Point;`) doesn't collapse
    /// to `any` and trigger a spurious TS2403.
    fn priorVarDeclTypeForTypeofSelf(
        self: *Checker,
        type_node: NodeId,
        name: hir_mod.StringId,
    ) ?TypeId {
        var cur = type_node;
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k != .var_decl and k != .let_decl and k != .const_decl) continue;
            const scope = self.hir.parentOf(cur);
            if (scope == hir_mod.none_node_id) return null;
            return self.previousVarDeclTypeInScope(scope, cur, name);
        }
        return null;
    }

    fn reportMissingRootForUnresolvedTypeofDottedQuery(
        self: *Checker,
        operand: NodeId,
        raw: []const u8,
    ) CheckError!bool {
        const dot = std.mem.indexOfScalar(u8, raw, '.') orelse return false;
        const root_raw = raw[0..dot];
        if (root_raw.len == 0) return false;
        const root_name = self.string_interner.intern(root_raw) catch return error.OutOfMemory;
        if (self.isBuiltinName(root_name)) return false;
        if (self.lookupNarrow(root_name) != null) return false;
        if ((try self.typeOfVisibleNameNoDiag(operand, root_name)) != null) return false;
        if (self.moduleNamespaceTypeForLocalImport(root_name, operand) catch null) |_| return false;
        if (self.virtualImportTypeForLocal(root_name, operand) catch null) |_| return false;
        if (self.virtualDefaultImportTypeForLocal(root_name, operand) catch null) |_| return false;
        if (self.globalAugmentedValueType(root_name, operand) catch null) |_| return false;
        if (self.enumDeclForNameAt(root_name, operand) != null) return false;
        const sp = self.hir.spanOf(operand);
        try self.reportCannotFindNameAtPosOnce(operand, sp.start, root_name);
        return true;
    }

    /// Walk type-argument node IDs and emit TS2304 for unresolved
    /// bare-name type references. Mirrors the behavior of
    /// `reportUnresolvedSimpleTypeofTypeArguments` but operates on
    /// already-parsed NodeId slices instead of scanning source text —
    /// used by call expressions and type refs that have parsed
    /// type-argument nodes.
    fn reportUnresolvedCallTypeArgumentNodes(self: *Checker, args: []const NodeId) CheckError!void {
        for (args) |arg| {
            if (self.hir.kindOf(arg) != .type_ref) continue;
            const r = hir_mod.typeRefOf(self.hir, arg);
            if (r.qualifier_len != 0) continue;
            const name_str = self.string_interner.get(r.name);
            if (isPrimitiveTypeNameText(name_str)) continue;
            if (self.lookupNarrow(r.name) != null) continue;
            if (self.isBuiltinName(r.name)) continue;
            if (self.typeRefNameExists(r.name) or self.visibleTypeDeclarationExistsAt(arg, r.name)) continue;
            if (self.typeRefNameAcceptsTypeArgsAt(arg, r.name, name_str)) continue;
            try self.reportCannotFindNameOnce(arg, r.name);
        }
    }

    fn isInstantiationExpressionCall(self: *Checker, node: NodeId) bool {
        if (self.hir.kindOf(node) != .call_expr) return false;
        if (hir_mod.callArgs(self.hir, node).len != 0) return false;
        if (hir_mod.callTypeArgs(self.hir, node).len == 0) return false;
        const src = self.source orelse return false;
        const sp = self.hir.spanOf(node);
        if (sp.end <= sp.start or sp.end > src.len) return false;
        return src[sp.end - 1] == '>';
    }

    fn reportUnresolvedSimpleTypeofTypeArguments(self: *Checker, operand: NodeId) CheckError!void {
        const src = self.source orelse return;
        const sp = self.hir.spanOf(operand);
        if (sp.end <= sp.start or sp.end > src.len) return;
        const text = src[sp.start..sp.end];
        const lt = std.mem.indexOfScalar(u8, text, '<') orelse return;
        const gt = std.mem.lastIndexOfScalar(u8, text, '>') orelse return;
        if (gt <= lt + 1) return;
        const args = text[lt + 1 .. gt];
        if (!simpleBareTypeArgumentList(args)) return;

        // `typeof Array<typeof x>` and similar — when the inner type
        // arguments include a TS type-operator keyword (`typeof`,
        // `keyof`, `infer`, `readonly`), the simple-name scanner here
        // would emit a bogus `Cannot find name 'typeof'`. The real
        // type-arg list was already parsed (the parser frees the
        // resulting node list), so reaching this fallback for a
        // keyword-bearing list means we've already accepted those
        // arguments syntactically; skip the bare-name diagnostic
        // entirely. Mirrors upstream tsc, which never emits TS2304
        // for the `typeof`/`keyof` token in this position.
        if (typeArgListContainsTypeKeyword(args)) return;

        var i: usize = 0;
        while (i < args.len) {
            while (i < args.len and !asciiIdentifierStart(args[i])) : (i += 1) {}
            if (i >= args.len) break;
            const name_start = i;
            i += 1;
            while (i < args.len and asciiIdentifierContinue(args[i])) : (i += 1) {}
            const raw_name = args[name_start..i];
            if (isPrimitiveTypeNameText(raw_name)) continue;
            if (isTypeOperatorKeywordText(raw_name)) continue;
            const name = self.string_interner.intern(raw_name) catch return error.OutOfMemory;
            if (self.lookupNarrow(name) != null) continue;
            if (self.typeRefNameExists(name) or self.visibleTypeDeclarationExistsAt(operand, name) or self.isBuiltinName(name)) continue;
            const pos = sp.start + @as(u32, @intCast(lt + 1 + name_start));
            try self.reportCannotFindNameAtPosOnce(operand, pos, name);
        }
    }

    fn typeArgListContainsTypeKeyword(text: []const u8) bool {
        var i: usize = 0;
        while (i < text.len) {
            while (i < text.len and !asciiIdentifierStart(text[i])) : (i += 1) {}
            if (i >= text.len) break;
            const name_start = i;
            i += 1;
            while (i < text.len and asciiIdentifierContinue(text[i])) : (i += 1) {}
            const word = text[name_start..i];
            if (isTypeOperatorKeywordText(word)) return true;
        }
        return false;
    }

    fn isTypeOperatorKeywordText(text: []const u8) bool {
        const kws = [_][]const u8{ "typeof", "keyof", "infer", "readonly", "unique" };
        for (kws) |kw| {
            if (std.mem.eql(u8, text, kw)) return true;
        }
        return false;
    }

    fn simpleBareTypeArgumentList(text: []const u8) bool {
        for (text) |c| {
            if (asciiIdentifierContinue(c) or c == ',' or c == ' ' or c == '\t' or c == '\r' or c == '\n') continue;
            return false;
        }
        return true;
    }

    fn asciiIdentifierStart(c: u8) bool {
        return (c >= 'A' and c <= 'Z') or (c >= 'a' and c <= 'z') or c == '_' or c == '$';
    }

    fn asciiIdentifierContinue(c: u8) bool {
        return asciiIdentifierStart(c) or (c >= '0' and c <= '9');
    }

    fn isPrimitiveTypeNameText(text: []const u8) bool {
        const names = [_][]const u8{
            "any",       "unknown",
            "never",     "void",
            "string",    "number",
            "boolean",   "bigint",
            "symbol",    "object",
            "undefined", "null",
        };
        for (names) |name| {
            if (std.mem.eql(u8, text, name)) return true;
        }
        return false;
    }

    fn resolveQualifiedTypeRef(self: *Checker, type_node: NodeId) CheckError!?TypeId {
        const r = hir_mod.typeRefOf(self.hir, type_node);
        const qualifiers = hir_mod.typeRefQualifier(self.hir, type_node);
        if (qualifiers.len == 0) return null;
        var path: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer path.deinit(self.gpa);
        for (qualifiers) |q| {
            if (self.hir.kindOf(q) != .identifier) return null;
            try path.append(self.gpa, hir_mod.identifierOf(self.hir, q).name);
        }
        if (try self.resolveQualifiedImportNamespaceTypeRef(type_node, path.items, r.name)) |t| return t;
        // Substitute leading `import alias = X.Y;` aliases so a qualified
        // type-ref like `alias.Point` resolves through the aliased
        // namespace path (`X.Y.Point`). Mirrors upstream behavior where
        // `import a = N;` lets `a.T` refer to `N.T`. Without this the
        // type-ref falls back to `unknown` and triggers a spurious
        // TS2403 against later `N.T` declarations of the same `var`.
        var alias_path: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer alias_path.deinit(self.gpa);
        var resolved_path: []const hir_mod.StringId = path.items;
        if (try self.appendImportEqualsNamespacePathForLocal(&alias_path, path.items[0], type_node)) {
            for (path.items[1..]) |seg| try alias_path.append(self.gpa, seg);
            resolved_path = alias_path.items;
        }
        const root = self.rootBlockFor(type_node);
        const root_stmts = if (root != hir_mod.none_node_id and self.hir.kindOf(root) == .block_stmt)
            hir_mod.blockStmts(self.hir, root)
        else
            return null;
        var relative_path: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer relative_path.deinit(self.gpa);
        const absolute_ns_node = self.findNamespaceByPath(root_stmts, resolved_path) orelse
            self.findGlobalAugmentedNamespaceByPath(root_stmts, resolved_path);
        const relative_ns_node = if (absolute_ns_node == null)
            try self.findRelativeNamespaceByPath(type_node, root_stmts, resolved_path, &relative_path)
        else
            null;
        const ns_node = absolute_ns_node orelse relative_ns_node orelse {
            // Fallback for `JSX.<Type>` qualified refs in fixtures that
            // reference the lib's `react.d.ts` via `/// <reference path
            // ="/.lib/react.d.ts" />` but never declare the JSX
            // namespace inline. Upstream tsc loads the lib's
            // `declare namespace JSX { interface Element {} ... }`
            // and resolves `JSX.Element` to the declared interface; we
            // don't load lib files, so the namespace lookup misses and
            // the result previously fell back to `unknown`. Synthesise
            // an empty named object type and register its display name
            // as the leaf identifier so diagnostics render
            // `'Element'` / `'IntrinsicAttributes'` instead of
            // `'unknown'`. Memoised via `type_names` so repeat lookups
            // reuse the same TypeId.
            if (resolved_path.len == 1 and
                std.mem.eql(u8, self.string_interner.get(resolved_path[0]), "JSX") and
                self.sourceHasReactJsxReference())
            {
                if (self.type_names.get(r.name)) |existing| return existing;
                const synth = self.interner.internObjectType(&.{}) catch return error.OutOfMemory;
                try self.type_names.put(self.gpa, r.name, synth);
                return synth;
            }
            return null;
        };
        const decl = self.findNamedTypeDeclInNamespace(ns_node, r.name) orelse return null;
        if (self.qualifiedDeclHasMissingRequiredTypeArgs(decl, r.args_len)) {
            // Match upstream TS shape — `Generic type 'Foo<T>' requires N
            // type argument(s).` — by rendering the param list and the
            // declared param count instead of the bare name + the count
            // suffix-only "type argument(s)" placeholder this branch
            // historically used. Source: §6.A exact-baseline ratchet.
            const params = self.typeParamNodesOfDecl(decl);
            var name_buf: std.ArrayListUnmanaged(u8) = .empty;
            defer name_buf.deinit(self.gpa);
            try name_buf.appendSlice(self.gpa, self.string_interner.get(r.name));
            try self.appendDeclTypeParameterListLabel(&name_buf, params);
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Generic type '{s}' requires {d} type argument(s).",
                .{ name_buf.items, params.len },
            );
            try self.diagnostics.append(self.gpa, .{
                .node = type_node,
                .code = TsCodes.generic_type_requires_args,
                .message = msg,
            });
        }
        const t = self.hir.typeOf(decl);
        if (t != types.Primitive.none and t != types.Primitive.unknown) return t;
        return switch (self.hir.kindOf(decl)) {
            .interface_decl => blk: {
                try self.checkInterfaceDecl(decl);
                const lowered = self.hir.typeOf(decl);
                break :blk if (lowered != types.Primitive.none) lowered else null;
            },
            .type_alias_decl => blk: {
                try self.checkTypeAliasDecl(decl);
                const lowered = self.hir.typeOf(decl);
                break :blk if (lowered != types.Primitive.none) lowered else null;
            },
            .class_decl, .class_expr => blk: {
                const c = hir_mod.classOf(self.hir, decl);
                if (c.name != hir_mod.none_node_id and self.hir.kindOf(c.name) == .identifier) {
                    const cid = hir_mod.identifierOf(self.hir, c.name);
                    if (self.class_instance_types.get(cid.name)) |ct| break :blk ct;
                }
                break :blk null;
            },
            .enum_decl => self.hir.typeOf(decl),
            else => null,
        };
    }

    fn reportCannotFindNamespaceForQualifiedTypeRef(self: *Checker, type_node: NodeId) CheckError!void {
        if (self.hir.kindOf(type_node) != .type_ref) return;
        const qualifiers = hir_mod.typeRefQualifier(self.hir, type_node);
        if (qualifiers.len == 0 or self.hir.kindOf(qualifiers[0]) != .identifier) return;
        const root_name = hir_mod.identifierOf(self.hir, qualifiers[0]).name;
        if (self.qualifiedTypeRefRootNamespaceExists(type_node, root_name) catch false) {
            // Root namespace exists, but the qualified-type lookup
            // came back empty — emit TS2339 `Property '<leaf>' does
            // not exist on type 'typeof <ns>'.` matching upstream
            // `genericTypeReferenceWithoutTypeArgument.d.ts(22,28)`
            // (`M.C` where M exists with only an `E` member). Only
            // fires for the single-qualifier-deep case (the most
            // common namespace-member miss) so we don't accidentally
            // shadow `cannot_find_namespace` on deeper chains.
            if (qualifiers.len == 1) {
                try self.reportMissingNamespaceMemberOnQualifiedTypeRef(type_node, root_name);
            }
            return;
        }
        const root_text = self.string_interner.get(root_name);
        // Suppress `Cannot find namespace 'JSX'.` when the fixture
        // references the react.d.ts triple-slash library — tsc treats
        // JSX as an ambient namespace provided by that lib and never
        // emits the diagnostic. Without this guard checkJsxChildrenProperty*
        // and tsxUnionTypeComponent* fixtures over-report TS2503.
        if (std.mem.eql(u8, root_text, "JSX") and self.sourceHasReactJsxReference()) return;
        const suggestion = self.namespaceSpellingSuggestion(root_name);
        const msg = if (suggestion) |suggested|
            try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Cannot find namespace '{s}'. Did you mean '{s}'?",
                .{ root_text, suggested },
            )
        else
            try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Cannot find namespace '{s}'.",
                .{root_text},
            );
        try self.diagnostics.append(self.gpa, .{
            .node = qualifiers[0],
            .code = if (suggestion != null) TsCodes.cannot_find_namespace_did_you_mean else TsCodes.cannot_find_namespace,
            .message = msg,
        });
    }

    /// Emit TS2339 on `<ns>.<leaf>` when `<ns>` is a known *ambient*
    /// namespace but no exported type declaration named `<leaf>` lives
    /// inside. Renders the same `Property '<leaf>' does not exist on
    /// type 'typeof <ns>'.` shape tsc emits in
    /// `genericTypeReferenceWithoutTypeArgument.d`. Only fires when
    /// the namespace was declared with `declare namespace M { ... }`
    /// (ambient): value namespaces surface a different TS2694
    /// `Namespace 'M' has no exported member 'X'.` diagnostic via
    /// `resolveQualifiedNamespaceMember` elsewhere. Skipped when
    /// `resolveQualifiedTypeRef` already returned a hit.
    fn reportMissingNamespaceMemberOnQualifiedTypeRef(
        self: *Checker,
        type_node: NodeId,
        root_name: hir_mod.StringId,
    ) CheckError!void {
        const r = hir_mod.typeRefOf(self.hir, type_node);
        const root = self.rootBlockFor(type_node);
        if (root == hir_mod.none_node_id) return;
        if (self.hir.kindOf(root) != .block_stmt) return;
        const root_stmts = hir_mod.blockStmts(self.hir, root);
        const path = [_]hir_mod.StringId{root_name};
        const ns_node = self.findNamespaceByPath(root_stmts, &path) orelse return;
        if (self.findNamedTypeDeclInNamespace(ns_node, r.name) != null) return;
        if (self.findNamedValueDeclInNamespace(ns_node, r.name) != null) return;
        const root_text = self.string_interner.get(root_name);
        const leaf_text = self.string_interner.get(r.name);
        // Anchor the diagnostic on the trailing leaf identifier (the
        // byte after the final `.`). Upstream tsc points at `C` in
        // `M.C` rather than at the start of the whole type-ref, so
        // the column matches the `(31,24)` baseline shape.
        const leaf_pos = self.qualifiedTypeRefLeafNamePos(type_node);
        if (self.namespaceDeclIsAmbient(ns_node)) {
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Property '{s}' does not exist on type 'typeof {s}'.",
                .{ leaf_text, root_text },
            );
            try self.diagnostics.append(self.gpa, .{
                .node = type_node,
                .pos = leaf_pos,
                .code = TsCodes.property_does_not_exist,
                .message = msg,
            });
            return;
        }
        // Non-ambient (value) namespace: upstream emits TS2694
        // `Namespace '<ns>' has no exported member '<leaf>'.` when a
        // qualified type-ref names a member that doesn't exist as a
        // type declaration in the namespace. Mirrors the
        // `parserRealSource*` cluster where `namespace TypeScript`
        // is opened repeatedly and members like `AST`, `NodeType`,
        // `ModuleDeclaration` are referenced but never declared as
        // types in any of the (truncated) fixture files.
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Namespace '{s}' has no exported member '{s}'.",
            .{ root_text, leaf_text },
        );
        try self.diagnostics.append(self.gpa, .{
            .node = type_node,
            .pos = leaf_pos,
            .code = TsCodes.namespace_no_exported_member,
            .message = msg,
        });
    }

    /// Approximate the ambient-context test for a namespace decl by
    /// scanning the source bytes immediately preceding the namespace
    /// keyword: an ambient namespace is prefixed by `declare ` (after
    /// optional `export `) in the source. `.d.ts` files are implicitly
    /// ambient even without a `declare` prefix; we treat the whole
    /// source as ambient when the first non-directive line starts with
    /// `declare ` (a quick heuristic that catches the conformance
    /// `genericTypeReferenceWithoutTypeArgument.d.ts` shape without
    /// adding a checker-wide ambient-file flag).
    fn namespaceDeclIsAmbient(self: *Checker, ns_node: NodeId) bool {
        const src = self.source orelse return false;
        const span = self.hir.spanOf(ns_node);
        if (span.start > src.len) return false;
        // Quick path: source starts with a sequence of `declare ` /
        // `// @directive` lines — treat as ambient (.d.ts shape).
        if (self.sourceIsImplicitlyAmbient()) return true;
        var i: usize = span.start;
        // Walk backward over the namespace identifier + whitespace.
        // Match `namespace` keyword; then check if `declare ` precedes
        // (after optional `export `).
        while (i > 0 and isAsciiWordChar(src[i - 1])) i -= 1;
        // Now `i` points to start of `namespace` keyword (or close to).
        // Skip back over whitespace.
        while (i > 0 and (src[i - 1] == ' ' or src[i - 1] == '\t')) i -= 1;
        // Optional `export ` prefix.
        if (i >= 7 and std.mem.eql(u8, src[i - 7 .. i], "export ")) {
            i -= 7;
            while (i > 0 and (src[i - 1] == ' ' or src[i - 1] == '\t')) i -= 1;
        }
        // Look for `declare ` immediately before.
        if (i >= 8 and std.mem.eql(u8, src[i - 8 .. i], "declare ")) return true;
        return false;
    }

    fn isAsciiWordChar(b: u8) bool {
        return (b >= 'a' and b <= 'z') or (b >= 'A' and b <= 'Z') or
            (b >= '0' and b <= '9') or b == '_' or b == '$';
    }

    /// Heuristic: a source is "implicitly ambient" (like a `.d.ts`)
    /// when its very first non-comment, non-directive statement
    /// begins with the `declare ` modifier. Used by the
    /// namespace-member miss path to differentiate the TS2339 vs
    /// TS2694 baseline shapes without plumbing a per-source flag.
    fn sourceIsImplicitlyAmbient(self: *Checker) bool {
        const src = self.source orelse return false;
        var i: usize = 0;
        while (i < src.len) {
            // Skip whitespace.
            while (i < src.len and (src[i] == ' ' or src[i] == '\t' or src[i] == '\n' or src[i] == '\r')) i += 1;
            if (i >= src.len) return false;
            // Skip line comments / directives.
            if (i + 1 < src.len and src[i] == '/' and src[i + 1] == '/') {
                while (i < src.len and src[i] != '\n') i += 1;
                continue;
            }
            // Skip block comments.
            if (i + 1 < src.len and src[i] == '/' and src[i + 1] == '*') {
                i += 2;
                while (i + 1 < src.len and !(src[i] == '*' and src[i + 1] == '/')) i += 1;
                i = @min(src.len, i + 2);
                continue;
            }
            // First real token. Check for `declare `.
            return i + 8 <= src.len and std.mem.eql(u8, src[i .. i + 8], "declare ");
        }
        return false;
    }

    /// Return the byte offset of the trailing leaf identifier in a
    /// qualified `Q.X` type-ref by scanning forward from the type-ref
    /// span start for the final `.`. Returns null when the span / `.`
    /// can't be located (the caller falls back to the type-ref start).
    fn qualifiedTypeRefLeafNamePos(self: *Checker, type_node: NodeId) ?u32 {
        const src = self.source orelse return null;
        const span = self.hir.spanOf(type_node);
        if (span.start >= src.len or span.end > src.len or span.end <= span.start) return null;
        const slice = src[span.start..span.end];
        // Walk from the right to find the final `.` so deeper chains
        // (`A.B.C`) anchor on the rightmost segment, matching tsc.
        var i: usize = slice.len;
        while (i > 0) : (i -= 1) {
            if (slice[i - 1] == '.') return @intCast(span.start + i);
        }
        return null;
    }

    fn namespaceSpellingSuggestion(self: *Checker, name: hir_mod.StringId) ?[]const u8 {
        const typo = self.string_interner.get(name);
        const threshold: usize = @min((typo.len * 4) / 10, @as(usize, 4));
        var best_name: []const u8 = "";
        var best_dist: usize = std.math.maxInt(usize);
        if (self.module) |module| {
            var it = module.root.namespaces.iterator();
            while (it.next()) |entry| {
                const cand = self.string_interner.get(entry.key_ptr.*);
                if (std.mem.eql(u8, cand, typo)) continue;
                const dist = levenshteinIcase(typo, cand);
                if (dist < best_dist) {
                    best_dist = dist;
                    best_name = cand;
                }
            }
        }
        if (best_name.len == 0 or best_dist > threshold) return null;
        return best_name;
    }

    fn qualifiedTypeRefRootNamespaceExists(self: *Checker, type_node: NodeId, root_name: hir_mod.StringId) CheckError!bool {
        if (self.module) |module| {
            if (module.root.namespaces.get(root_name) != null) return true;
        }
        if (self.ambientGlobalNamespaceRootExists(root_name)) return true;
        var import_path: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer import_path.deinit(self.gpa);
        if (try self.appendImportEqualsNamespacePathForLocal(&import_path, root_name, type_node)) return true;
        // Walk up enclosing namespace bodies + the source root so a
        // sibling `namespace M { … }` is visible to qualified-type
        // refs from within other namespaces. Mirrors `importStatements`
        // (a namespace alias declared in a sibling block).
        const one = [_]hir_mod.StringId{root_name};
        var cur = type_node;
        while (cur != hir_mod.none_node_id) {
            const stmts: []const NodeId = blk: {
                if (self.hir.kindOf(cur) == .block_stmt) break :blk hir_mod.blockStmts(self.hir, cur);
                if (self.hir.kindOf(cur) == .namespace_decl) break :blk hir_mod.namespaceBody(self.hir, cur);
                break :blk &[_]NodeId{};
            };
            if (stmts.len > 0 and self.findNamespaceByPath(stmts, &one) != null) return true;
            const parent = self.hir.parentOf(cur);
            if (parent == cur or parent == hir_mod.none_node_id) break;
            cur = parent;
        }
        // `import X from './x'` / `import { X } from './x'` /
        // `import * as X from './x'` (including `import type` variants)
        // all bind `X` as a name that can stand at the root of a
        // qualified TYPE reference. Without this, `import type ns from './ns'`
        // followed by `let c: ns.Class` over-reports TS2503. tsc treats
        // the binding as a type alias for the module's namespace; we
        // just need to confirm the binding exists in the current virtual
        // file section. Mirrors fixtures `enums` and
        // `filterNamespace_import` (both in conformance/externalModules/typeOnly).
        const root_block = self.rootBlockFor(type_node);
        if (root_block != hir_mod.none_node_id and self.hir.kindOf(root_block) == .block_stmt) {
            const has_sections = self.sourceHasVirtualFilenameSections();
            const anchor_section = if (has_sections) self.virtualSectionStartForNode(type_node) else 0;
            if (self.findGlobalAugmentedNamespaceByPath(hir_mod.blockStmts(self.hir, root_block), &one) != null) return true;
            for (hir_mod.blockStmts(self.hir, root_block)) |stmt| {
                if (self.hir.kindOf(stmt) != .import_decl) continue;
                if (has_sections and self.virtualSectionStartForNode(stmt) != anchor_section) continue;
                if (self.importDeclBindsLocal(stmt, root_name)) return true;
            }
        }
        return false;
    }

    fn ambientGlobalNamespaceRootExists(self: *Checker, root_name: hir_mod.StringId) bool {
        const root_text = self.string_interner.get(root_name);
        for (self.ambient_global_namespace_roots) |candidate| {
            if (std.mem.eql(u8, candidate, root_text)) return true;
        }
        return false;
    }

    fn resolveQualifiedImportNamespaceTypeRef(
        self: *Checker,
        type_node: NodeId,
        qualifiers: []const hir_mod.StringId,
        leaf_name: hir_mod.StringId,
    ) CheckError!?TypeId {
        if (qualifiers.len == 0) return null;
        var full_path: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer full_path.deinit(self.gpa);
        if (!try self.appendImportEqualsNamespacePathForLocal(&full_path, qualifiers[0], type_node)) {
            try full_path.append(self.gpa, qualifiers[0]);
        }
        for (qualifiers[1..]) |q| try full_path.append(self.gpa, q);
        if (full_path.items.len == 0) return null;
        const import_info = self.localImportModuleInfo(full_path.items[0], type_node) orelse return null;
        const namespace_path = if (import_info.exported_root) |exported_root| blk: {
            full_path.items[0] = exported_root;
            break :blk full_path.items;
        } else full_path.items[1..];
        return try self.virtualRelativeModuleExportType(type_node, import_info.specifier, namespace_path, leaf_name);
    }

    fn appendImportEqualsNamespacePathForLocal(
        self: *Checker,
        out: *std.ArrayListUnmanaged(hir_mod.StringId),
        local_name: hir_mod.StringId,
        anchor: NodeId,
    ) CheckError!bool {
        // Walk up enclosing scopes (namespace bodies + the source
        // root) so an `import a = A;` in `namespace E { … }` resolves
        // for type-refs inside that namespace. Mirrors the
        // `importStatements` fixture.
        var cur = anchor;
        while (cur != hir_mod.none_node_id) {
            const stmts: []const NodeId = blk: {
                if (self.hir.kindOf(cur) == .block_stmt) break :blk hir_mod.blockStmts(self.hir, cur);
                if (self.hir.kindOf(cur) == .namespace_decl) break :blk hir_mod.namespaceBody(self.hir, cur);
                break :blk &[_]NodeId{};
            };
            for (stmts) |raw_stmt| {
                const stmt = self.unwrapExportDecl(raw_stmt);
                if (self.hir.kindOf(stmt) != .import_decl) continue;
                const imp = hir_mod.importOf(self.hir, stmt);
                if (self.string_interner.get(imp.module).len != 0) continue;
                if (imp.default_binding == hir_mod.none_node_id or self.hir.kindOf(imp.default_binding) != .identifier) continue;
                if (hir_mod.identifierOf(self.hir, imp.default_binding).name != local_name) continue;
                if (imp.import_equals == hir_mod.none_node_id or self.hir.kindOf(imp.import_equals) != .type_ref) return false;
                const r = hir_mod.typeRefOf(self.hir, imp.import_equals);
                const qs = hir_mod.typeRefQualifier(self.hir, imp.import_equals);
                for (qs) |q| {
                    if (self.hir.kindOf(q) != .identifier) return false;
                    try out.append(self.gpa, hir_mod.identifierOf(self.hir, q).name);
                }
                try out.append(self.gpa, r.name);
                return true;
            }
            const parent = self.hir.parentOf(cur);
            if (parent == cur or parent == hir_mod.none_node_id) break;
            cur = parent;
        }
        return false;
    }

    const LocalImportModuleInfo = struct {
        specifier: hir_mod.StringId,
        /// `import { exported as local } from "./m"` binds an exported
        /// member of the target module, so `local.X` must resolve
        /// through the target's exported root. `import * as ns` binds
        /// the module namespace object itself, so the local name is not
        /// part of the exported path.
        exported_root: ?hir_mod.StringId = null,
    };

    fn localImportModuleInfo(self: *Checker, local_name: hir_mod.StringId, anchor: NodeId) ?LocalImportModuleInfo {
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        const has_sections = self.sourceHasVirtualFilenameSections();
        const anchor_section = if (has_sections) self.virtualSectionStartForNode(anchor) else 0;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            if (self.hir.kindOf(stmt) != .import_decl) continue;
            if (has_sections and self.virtualSectionStartForNode(stmt) != anchor_section) continue;
            const imp = hir_mod.importOf(self.hir, stmt);
            const spec = self.string_interner.get(imp.module);
            if (spec.len == 0) continue;
            if (imp.namespace_binding != hir_mod.none_node_id and self.hir.kindOf(imp.namespace_binding) == .identifier and
                hir_mod.identifierOf(self.hir, imp.namespace_binding).name == local_name)
            {
                return .{ .specifier = imp.module };
            }
            if (imp.default_binding != hir_mod.none_node_id and std.mem.startsWith(u8, spec, ".") and self.importDeclIsRequireAssignment(stmt) and
                self.hir.kindOf(imp.default_binding) == .identifier and
                hir_mod.identifierOf(self.hir, imp.default_binding).name == local_name)
            {
                return .{ .specifier = imp.module };
            }
            for (hir_mod.importNamed(self.hir, stmt)) |spec_node| {
                if (self.hir.kindOf(spec_node) != .import_specifier) continue;
                const sp = hir_mod.importSpecifierOf(self.hir, spec_node);
                if (sp.local != local_name) continue;
                return .{ .specifier = imp.module, .exported_root = sp.imported };
            }
        }
        return null;
    }

    fn virtualRelativeModuleExportType(
        self: *Checker,
        anchor: NodeId,
        specifier: hir_mod.StringId,
        namespace_path: []const hir_mod.StringId,
        leaf_name: hir_mod.StringId,
    ) CheckError!?TypeId {
        const src = self.source orelse return null;
        if (!self.sourceHasVirtualFilenameSections()) return null;
        const spec = self.string_interner.get(specifier);
        if (!std.mem.startsWith(u8, spec, ".")) return null;
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        for (hir_mod.blockStmts(self.hir, root)) |raw| {
            if (!self.virtualSectionMatchesSpecifier(src, raw, spec)) continue;
            if (self.hir.kindOf(raw) != .export_decl) continue;
            const decl = self.unwrapExportDecl(raw);
            if (namespace_path.len == 0) {
                const decl_name = self.declarationName(decl) orelse continue;
                if (decl_name != leaf_name) continue;
                return try self.typeOfExportedTypeDecl(decl, leaf_name);
            }
            if (self.hir.kindOf(decl) != .namespace_decl) continue;
            const ns = hir_mod.namespaceOf(self.hir, decl);
            if (ns.name == hir_mod.none_node_id or self.hir.kindOf(ns.name) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, ns.name).name != namespace_path[0]) continue;
            return try self.namespaceExportTypeByPath(decl, namespace_path[1..], leaf_name);
        }
        return null;
    }

    fn namespaceExportTypeByPath(
        self: *Checker,
        ns_node: NodeId,
        namespace_path: []const hir_mod.StringId,
        leaf_name: hir_mod.StringId,
    ) CheckError!?TypeId {
        for (hir_mod.namespaceBody(self.hir, ns_node)) |raw| {
            const decl = self.unwrapExportDecl(raw);
            if (namespace_path.len == 0) {
                const decl_name = self.declarationName(decl) orelse continue;
                if (decl_name != leaf_name) continue;
                return try self.typeOfExportedTypeDecl(decl, leaf_name);
            }
            if (self.hir.kindOf(decl) != .namespace_decl) continue;
            const ns = hir_mod.namespaceOf(self.hir, decl);
            if (ns.name == hir_mod.none_node_id or self.hir.kindOf(ns.name) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, ns.name).name != namespace_path[0]) continue;
            return try self.namespaceExportTypeByPath(decl, namespace_path[1..], leaf_name);
        }
        return null;
    }

    fn typeOfExportedTypeDecl(self: *Checker, decl: NodeId, name: hir_mod.StringId) CheckError!?TypeId {
        const t = self.hir.typeOf(decl);
        if (t != types.Primitive.none and t != types.Primitive.unknown) return t;
        if (self.resolving_exported_type_decls.contains(decl)) {
            var resolving_it = self.resolving_exported_type_decls.keyIterator();
            while (resolving_it.next()) |active_decl| {
                if (self.hir.kindOf(active_decl.*) != .type_alias_decl) continue;
                const active_ta = hir_mod.typeAliasOf(self.hir, active_decl.*);
                if (active_ta.name != hir_mod.none_node_id and self.hir.kindOf(active_ta.name) == .identifier) {
                    try self.reportTypeAliasCircularOnce(active_ta.name, hir_mod.identifierOf(self.hir, active_ta.name).name);
                }
            }
            if (self.hir.kindOf(decl) == .type_alias_decl) {
                const ta = hir_mod.typeAliasOf(self.hir, decl);
                if (ta.name != hir_mod.none_node_id and self.hir.kindOf(ta.name) == .identifier) {
                    try self.reportTypeAliasCircularOnce(ta.name, hir_mod.identifierOf(self.hir, ta.name).name);
                }
            }
            if (self.class_instance_types.get(name)) |ct| return ct;
            return types.Primitive.any;
        }
        try self.resolving_exported_type_decls.put(self.gpa, decl, {});
        defer _ = self.resolving_exported_type_decls.remove(decl);
        return switch (self.hir.kindOf(decl)) {
            .interface_decl => blk: {
                try self.checkInterfaceDecl(decl);
                const lowered = self.hir.typeOf(decl);
                break :blk if (lowered != types.Primitive.none) lowered else null;
            },
            .type_alias_decl => blk: {
                try self.checkTypeAliasDecl(decl);
                const lowered = self.hir.typeOf(decl);
                break :blk if (lowered != types.Primitive.none) lowered else null;
            },
            .class_decl, .class_expr => blk: {
                try self.checkClassDecl(decl);
                if (self.class_instance_types.get(name)) |ct| break :blk ct;
                break :blk self.hir.typeOf(decl);
            },
            .enum_decl => blk: {
                try self.checkEnumDecl(decl);
                break :blk self.hir.typeOf(decl);
            },
            else => null,
        };
    }

    fn resolveUnqualifiedNamespaceTypeRef(self: *Checker, type_node: NodeId, name: hir_mod.StringId) CheckError!?TypeId {
        var cur = self.hir.parentOf(type_node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            if (self.hir.kindOf(cur) != .namespace_decl) continue;
            const decl = self.findNamedTypeDeclInNamespace(cur, name) orelse continue;
            if (self.nodeHasAncestor(type_node, decl)) return null;
            const t = self.hir.typeOf(decl);
            if (t != types.Primitive.none and t != types.Primitive.unknown) return t;
            return switch (self.hir.kindOf(decl)) {
                .interface_decl => blk: {
                    try self.checkInterfaceDecl(decl);
                    const lowered = self.hir.typeOf(decl);
                    break :blk if (lowered != types.Primitive.none) lowered else null;
                },
                .type_alias_decl => blk: {
                    try self.checkTypeAliasDecl(decl);
                    const lowered = self.hir.typeOf(decl);
                    break :blk if (lowered != types.Primitive.none) lowered else null;
                },
                .class_decl, .class_expr => blk: {
                    const c = hir_mod.classOf(self.hir, decl);
                    if (c.name != hir_mod.none_node_id and self.hir.kindOf(c.name) == .identifier) {
                        const cid = hir_mod.identifierOf(self.hir, c.name);
                        if (self.class_instance_types.get(cid.name)) |ct| break :blk ct;
                    }
                    break :blk null;
                },
                .enum_decl => self.hir.typeOf(decl),
                else => null,
            };
        }
        return null;
    }

    fn namespaceTypeRefIsCrossVirtualSectionOnly(
        self: *Checker,
        type_node: NodeId,
        name: hir_mod.StringId,
    ) bool {
        if (!self.sourceHasVirtualFilenameSections()) return false;
        if (!self.enclosingTopLevelNamespaceIsExported(type_node)) return false;
        var path: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer path.deinit(self.gpa);
        self.collectEnclosingNamespacePathNoFail(type_node, &path);
        if (path.items.len == 0) return false;
        const root = self.rootBlockFor(type_node);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return false;
        const root_stmts = hir_mod.blockStmts(self.hir, root);
        const section = self.virtualSectionStartForNode(type_node);
        var prefix_len = path.items.len;
        while (prefix_len > 0) : (prefix_len -= 1) {
            const prefix = path.items[0..prefix_len];
            if (self.namespacePathHasNamedTypeDeclInSection(root_stmts, prefix, name, section)) return false;
            if (self.namespacePathHasNamedTypeDeclOutsideSection(root_stmts, prefix, name, section)) return true;
        }
        return false;
    }

    fn enclosingTopLevelNamespaceIsExported(self: *Checker, node: NodeId) bool {
        var top: NodeId = hir_mod.none_node_id;
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            if (self.hir.kindOf(cur) == .namespace_decl) top = cur;
        }
        if (top == hir_mod.none_node_id) return false;
        const parent = self.hir.parentOf(top);
        return parent != hir_mod.none_node_id and self.hir.kindOf(parent) == .export_decl;
    }

    fn namespacePathHasNamedTypeDeclInSection(
        self: *Checker,
        stmts: []const NodeId,
        path: []const hir_mod.StringId,
        name: hir_mod.StringId,
        section: usize,
    ) bool {
        if (path.len == 0) return false;
        for (stmts) |raw| {
            const node = self.unwrapExportDecl(raw);
            if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .namespace_decl) continue;
            const ns = hir_mod.namespaceOf(self.hir, node);
            if (ns.name == hir_mod.none_node_id or self.hir.kindOf(ns.name) != .identifier) continue;
            const ns_name = self.string_interner.get(hir_mod.identifierOf(self.hir, ns.name).name);
            const consumed = self.namespaceNameConsumesPath(ns_name, path) orelse continue;
            if (consumed == path.len) {
                if (self.virtualSectionStartForNode(node) == section and
                    self.findNamedTypeDeclInNamespace(node, name) != null)
                {
                    return true;
                }
                continue;
            }
            if (self.namespacePathHasNamedTypeDeclInSection(
                hir_mod.namespaceBody(self.hir, node),
                path[consumed..],
                name,
                section,
            )) return true;
        }
        return false;
    }

    fn namespacePathHasNamedTypeDeclOutsideSection(
        self: *Checker,
        stmts: []const NodeId,
        path: []const hir_mod.StringId,
        name: hir_mod.StringId,
        section: usize,
    ) bool {
        if (path.len == 0) return false;
        for (stmts) |raw| {
            const node = self.unwrapExportDecl(raw);
            if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .namespace_decl) continue;
            const ns = hir_mod.namespaceOf(self.hir, node);
            if (ns.name == hir_mod.none_node_id or self.hir.kindOf(ns.name) != .identifier) continue;
            const ns_name = self.string_interner.get(hir_mod.identifierOf(self.hir, ns.name).name);
            const consumed = self.namespaceNameConsumesPath(ns_name, path) orelse continue;
            if (consumed == path.len) {
                if (self.virtualSectionStartForNode(node) != section and
                    self.findNamedTypeDeclInNamespace(node, name) != null)
                {
                    return true;
                }
                continue;
            }
            if (self.namespacePathHasNamedTypeDeclOutsideSection(
                hir_mod.namespaceBody(self.hir, node),
                path[consumed..],
                name,
                section,
            )) return true;
        }
        return false;
    }

    fn nodeHasAncestor(self: *Checker, node: NodeId, ancestor: NodeId) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            if (cur == ancestor) return true;
        }
        return false;
    }

    fn qualifiedEnumMemberTypeRef(self: *Checker, type_node: NodeId) CheckError!?TypeId {
        const r = hir_mod.typeRefOf(self.hir, type_node);
        const qualifiers = hir_mod.typeRefQualifier(self.hir, type_node);
        if (qualifiers.len != 1 or self.hir.kindOf(qualifiers[0]) != .identifier) return null;
        const enum_name = hir_mod.identifierOf(self.hir, qualifiers[0]).name;
        if (self.constEnumLiteralAccess(enum_name, r.name, type_node)) |lit_t| return lit_t;
        if (self.enumMemberStringLiteralAccess(enum_name, r.name, type_node)) |lit_t| return lit_t;
        if (self.enumHasMember(enum_name, r.name)) return try self.enumNominalType(enum_name);
        return null;
    }

    fn qualifiedDeclHasMissingRequiredTypeArgs(self: *Checker, decl: NodeId, supplied: usize) bool {
        const params = switch (self.hir.kindOf(decl)) {
            .class_decl, .class_expr => blk: {
                const c = hir_mod.classOf(self.hir, decl);
                break :blk self.hir.childSlice(c.type_params_start, c.type_params_len);
            },
            .interface_decl => blk: {
                const i = hir_mod.interfaceOf(self.hir, decl);
                break :blk self.hir.childSlice(i.type_params_start, i.type_params_len);
            },
            .type_alias_decl => blk: {
                const t = hir_mod.typeAliasOf(self.hir, decl);
                break :blk self.hir.childSlice(t.type_params_start, t.type_params_len);
            },
            else => return false,
        };
        if (supplied >= params.len) return false;
        for (params[supplied..]) |param| {
            if (self.hir.kindOf(param) != .type_parameter) return true;
            const tp = hir_mod.typeParameterOf(self.hir, param);
            if (tp.default == hir_mod.none_node_id) return true;
        }
        return false;
    }

    fn rootBlockFor(self: *Checker, node: NodeId) NodeId {
        var cur = node;
        var parent = self.hir.parentOf(cur);
        while (parent != hir_mod.none_node_id) : (parent = self.hir.parentOf(cur)) {
            cur = parent;
        }
        return cur;
    }

    fn findNamespaceByPath(
        self: *Checker,
        stmts: []const NodeId,
        path: []const hir_mod.StringId,
    ) ?NodeId {
        if (path.len == 0) return null;
        for (stmts) |raw| {
            const node = self.unwrapExportDecl(raw);
            if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .namespace_decl) continue;
            const ns = hir_mod.namespaceOf(self.hir, node);
            if (ns.name == hir_mod.none_node_id or self.hir.kindOf(ns.name) != .identifier) continue;
            const ns_name = self.string_interner.get(hir_mod.identifierOf(self.hir, ns.name).name);
            const consumed = self.namespaceNameConsumesPath(ns_name, path) orelse continue;
            if (consumed == path.len) return node;
            if (self.findNamespaceByPath(hir_mod.namespaceBody(self.hir, node), path[consumed..])) |nested| {
                return nested;
            }
        }
        return null;
    }

    fn findGlobalAugmentedNamespaceByPath(
        self: *Checker,
        root_stmts: []const NodeId,
        path: []const hir_mod.StringId,
    ) ?NodeId {
        if (path.len == 0) return null;
        for (root_stmts) |raw| {
            const node = self.unwrapExportDecl(raw);
            if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .namespace_decl) continue;
            const ns = hir_mod.namespaceOf(self.hir, node);
            if (ns.name == hir_mod.none_node_id or self.hir.kindOf(ns.name) != .identifier) continue;
            const ns_name = hir_mod.identifierOf(self.hir, ns.name).name;
            if (!std.mem.eql(u8, self.string_interner.get(ns_name), "global")) continue;
            if (!self.namespaceDeclIsAmbient(node) and !self.namespaceNameHasDeclarePrefix(ns.name)) continue;
            if (self.findNamespaceByPath(hir_mod.namespaceBody(self.hir, node), path)) |found| return found;
        }
        return null;
    }

    fn namespaceNameHasDeclarePrefix(self: *Checker, name_node: NodeId) bool {
        const src = self.source orelse return false;
        if (name_node == hir_mod.none_node_id) return false;
        const span = self.hir.spanOf(name_node);
        if (span.start > src.len) return false;
        var i: usize = span.start;
        while (i > 0 and (src[i - 1] == ' ' or src[i - 1] == '\t')) i -= 1;
        if (i < "declare".len) return false;
        if (!std.mem.eql(u8, src[i - "declare".len .. i], "declare")) return false;
        if (i > "declare".len and isAsciiWordChar(src[i - "declare".len - 1])) return false;
        return true;
    }

    fn findRelativeNamespaceByPath(
        self: *Checker,
        anchor: NodeId,
        root_stmts: []const NodeId,
        path: []const hir_mod.StringId,
        scratch: *std.ArrayListUnmanaged(hir_mod.StringId),
    ) CheckError!?NodeId {
        var enclosing: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer enclosing.deinit(self.gpa);
        self.collectEnclosingNamespacePathNoFail(anchor, &enclosing);
        var prefix_len = enclosing.items.len;
        while (prefix_len > 0) : (prefix_len -= 1) {
            scratch.clearRetainingCapacity();
            try scratch.appendSlice(self.gpa, enclosing.items[0..prefix_len]);
            try scratch.appendSlice(self.gpa, path);
            if (self.findNamespaceByPath(root_stmts, scratch.items)) |ns_node| return ns_node;
        }
        return null;
    }

    fn namespaceNameConsumesPath(
        self: *Checker,
        ns_name: []const u8,
        path: []const hir_mod.StringId,
    ) ?usize {
        var consumed: usize = 0;
        var it = std.mem.splitScalar(u8, ns_name, '.');
        while (it.next()) |segment| {
            if (consumed >= path.len) return null;
            if (!std.mem.eql(u8, segment, self.string_interner.get(path[consumed]))) return null;
            consumed += 1;
        }
        return consumed;
    }

    fn findNamedTypeDeclInNamespace(
        self: *Checker,
        ns_node: NodeId,
        name: hir_mod.StringId,
    ) ?NodeId {
        for (hir_mod.namespaceBody(self.hir, ns_node)) |raw| {
            const node = self.unwrapExportDecl(raw);
            switch (self.hir.kindOf(node)) {
                .interface_decl,
                .type_alias_decl,
                .class_decl,
                .class_expr,
                .enum_decl,
                => {
                    const decl_name = self.declarationName(node) orelse continue;
                    if (decl_name == name) return node;
                },
                else => {},
            }
        }
        return null;
    }

    fn findNamedValueDeclInNamespace(
        self: *Checker,
        ns_node: NodeId,
        name: hir_mod.StringId,
    ) ?NodeId {
        for (hir_mod.namespaceBody(self.hir, ns_node)) |raw| {
            const node = self.unwrapExportDecl(raw);
            switch (self.hir.kindOf(node)) {
                .var_decl,
                .let_decl,
                .const_decl,
                .fn_decl,
                .fn_expr,
                .class_decl,
                .class_expr,
                .enum_decl,
                .namespace_decl,
                .import_decl,
                => {
                    const decl_name = if (self.hir.kindOf(node) == .import_decl)
                        (self.importEqualsAliasName(node) orelse continue)
                    else
                        (self.declarationName(node) orelse continue);
                    if (!self.declCreatesRuntimeValue(node, 0)) continue;
                    if (decl_name == name) return node;
                },
                else => {},
            }
        }
        return null;
    }

    /// Like `findNamedValueDeclInNamespace` but only returns decls
    /// wrapped in an `export_decl`. Used at the member-access-on-
    /// namespace path to distinguish "member is private to the
    /// namespace" (→ TS2339 `Property '<x>' does not exist on type
    /// 'typeof <ns>'.`) from "member is visible". Mirrors the
    /// `ModuleWithExportedAndNonExported*` fixture cluster
    /// (`A.y`, `A.fn2`, `A.Day`, `Geometry.Lines`).
    fn findExportedValueDeclInNamespace(
        self: *Checker,
        ns_node: NodeId,
        name: hir_mod.StringId,
    ) ?NodeId {
        for (hir_mod.namespaceBody(self.hir, ns_node)) |raw| {
            const node = switch (self.hir.kindOf(raw)) {
                .export_decl => self.unwrapExportDecl(raw),
                .import_decl => if (self.importDeclHasExportKeyword(raw)) raw else continue,
                else => continue,
            };
            switch (self.hir.kindOf(node)) {
                .var_decl,
                .let_decl,
                .const_decl,
                .fn_decl,
                .fn_expr,
                .class_decl,
                .class_expr,
                .enum_decl,
                .import_decl,
                => {
                    const decl_name = if (self.hir.kindOf(node) == .import_decl)
                        (self.importEqualsAliasName(node) orelse continue)
                    else
                        (self.declarationName(node) orelse continue);
                    if (!self.declCreatesRuntimeValue(node, 0)) continue;
                    if (decl_name == name) return node;
                },
                else => {},
            }
        }
        return null;
    }

    /// Emit TS2339 `Property '<x>' does not exist on type 'typeof <ns>'.`
    /// when a `<ns>.<x>` member-access expression names a value member
    /// that lives inside the namespace but is *not* wrapped in an
    /// `export` modifier. Returns `true` when the diagnostic fired so
    /// the caller can short-circuit its lookup. Returns `false`
    /// (without diagnosing) when no namespace by that name exists or
    /// when the member is exported / absent — those paths are handled
    /// by sibling lookups. Mirrors the `ModuleWithExportedAndNonExported*`
    /// fixture cluster.
    fn reportNonExportedNamespaceMember(
        self: *Checker,
        node: NodeId,
        ns_name: hir_mod.StringId,
        member_name: hir_mod.StringId,
    ) CheckError!bool {
        const root = self.rootBlockFor(node);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return false;
        const root_stmts = hir_mod.blockStmts(self.hir, root);
        const one = [_]hir_mod.StringId{ns_name};
        const ns_node = self.findNamespaceByPath(root_stmts, &one) orelse return false;
        // A same-name *exported* value decl is handled upstream by
        // `mergedNamespaceValueMemberType`; only fire when the member
        // exists but is private to the namespace.
        if (self.findExportedValueDeclInNamespace(ns_node, member_name) != null) return false;
        if (self.findNamedValueDeclInNamespace(ns_node, member_name) == null) return false;
        const ns_text = self.string_interner.get(ns_name);
        const leaf_text = self.string_interner.get(member_name);
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Property '{s}' does not exist on type 'typeof {s}'.",
            .{ leaf_text, ns_text },
        );
        try self.diagnostics.append(self.gpa, .{
            .node = node,
            .pos = self.memberAccessNamePos(node),
            .code = TsCodes.property_does_not_exist,
            .message = msg,
        });
        return true;
    }

    fn typeOfQualifiedNamespaceValue(
        self: *Checker,
        raw: []const u8,
        anchor: NodeId,
    ) CheckError!?TypeId {
        var parts = std.mem.splitScalar(u8, raw, '.');
        var ids: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer ids.deinit(self.gpa);
        while (parts.next()) |part| {
            if (part.len == 0) return null;
            try ids.append(self.gpa, self.string_interner.intern(part) catch return error.OutOfMemory);
        }
        if (ids.items.len < 2) return null;
        const value_name = ids.items[ids.items.len - 1];
        // Walk up enclosing namespace bodies + the source root so a
        // sibling `namespace M2 { … }` is visible from inside another
        // namespace. Mirrors `nonInstantiatedModule`.
        var ns_node: NodeId = hir_mod.none_node_id;
        var cur = anchor;
        while (cur != hir_mod.none_node_id) {
            const stmts: []const NodeId = blk: {
                if (self.hir.kindOf(cur) == .block_stmt) break :blk hir_mod.blockStmts(self.hir, cur);
                if (self.hir.kindOf(cur) == .namespace_decl) break :blk hir_mod.namespaceBody(self.hir, cur);
                break :blk &[_]NodeId{};
            };
            if (stmts.len > 0) {
                if (self.findNamespaceByPath(stmts, ids.items[0 .. ids.items.len - 1])) |found| {
                    ns_node = found;
                    break;
                }
            }
            const parent = self.hir.parentOf(cur);
            if (parent == cur or parent == hir_mod.none_node_id) break;
            cur = parent;
        }
        if (ns_node == hir_mod.none_node_id) return null;
        const decl = self.findNamedValueDeclInNamespace(ns_node, value_name) orelse return null;
        var t = self.hir.typeOf(decl);
        if (t != types.Primitive.none and t != types.Primitive.unknown) return t;
        switch (self.hir.kindOf(decl)) {
            .var_decl, .let_decl, .const_decl => try self.checkNamespaceValueDecl(decl),
            .fn_decl, .fn_expr, .arrow_fn => try self.checkFnSignatureOnlyNoBody(decl),
            .class_decl, .class_expr, .enum_decl => try self.checkStatement(decl),
            .namespace_decl => return try self.namespaceValueObjectType(decl),
            else => {},
        }
        t = self.hir.typeOf(decl);
        if (t != types.Primitive.none and t != types.Primitive.unknown) return t;
        return types.Primitive.any;
    }

    fn namespaceValueObjectType(self: *Checker, ns_node: NodeId) CheckError!TypeId {
        if (self.hir.kindOf(ns_node) != .namespace_decl) return types.Primitive.any;
        var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer members.deinit(self.gpa);
        for (hir_mod.namespaceBody(self.hir, ns_node)) |raw| {
            if (self.hir.kindOf(raw) != .export_decl) continue;
            const decl = self.unwrapExportDecl(raw);
            if (!self.namespaceExportCreatesValue(decl)) continue;
            const name = self.declarationName(decl) orelse continue;
            const member_t = switch (self.hir.kindOf(decl)) {
                .var_decl, .let_decl, .const_decl => blk: {
                    try self.checkNamespaceValueDecl(decl);
                    const t = self.hir.typeOf(decl);
                    break :blk if (t != types.Primitive.none) t else types.Primitive.any;
                },
                .fn_decl, .fn_expr, .arrow_fn => blk: {
                    try self.checkFnSignatureOnlyNoBody(decl);
                    const t = self.hir.typeOf(decl);
                    break :blk if (t != types.Primitive.none) t else types.Primitive.any;
                },
                .class_decl, .class_expr => blk: {
                    try self.checkStatement(decl);
                    if (self.class_static_types.get(name)) |static_t| break :blk static_t;
                    const t = self.hir.typeOf(decl);
                    break :blk if (t != types.Primitive.none) t else types.Primitive.any;
                },
                .enum_decl => try self.enumNamespaceValueType(decl, name),
                .namespace_decl => try self.namespaceValueObjectType(decl),
                else => types.Primitive.any,
            };
            try members.append(self.gpa, .{
                .name = name,
                .type = member_t,
                .is_optional = false,
                .is_readonly = true,
                .is_method = self.hir.kindOf(decl) == .fn_decl or self.hir.kindOf(decl) == .fn_expr,
            });
        }
        return self.interner.internObjectType(members.items) catch return error.OutOfMemory;
    }

    fn lowerTupleWithTypeParams(self: *Checker, type_node: NodeId) CheckError!TypeId {
        const elems = hir_mod.tupleTypeElements(self.hir, type_node);

        var fixed_types: std.ArrayListUnmanaged(TypeId) = .empty;
        defer fixed_types.deinit(self.gpa);
        var rest_elem_types: std.ArrayListUnmanaged(TypeId) = .empty;
        defer rest_elem_types.deinit(self.gpa);
        var saw_unknown_rest = false;

        for (elems) |e| {
            if (self.hir.kindOf(e) == .rest_type) {
                const rt = hir_mod.restTypeOf(self.hir, e);
                const opk = self.hir.kindOf(rt.operand);
                if (opk == .tuple_type) {
                    const inner_elems = hir_mod.tupleTypeElements(self.hir, rt.operand);
                    var inner_has_rest = false;
                    for (inner_elems) |ie| {
                        if (self.hir.kindOf(ie) == .rest_type) {
                            inner_has_rest = true;
                            break;
                        }
                    }
                    if (!inner_has_rest) {
                        for (inner_elems) |ie| {
                            var t = try self.lowererLowerWithTypeParams(ie);
                            if (self.tupleElementHasOptionalMarker(ie)) {
                                t = self.unionWithUndefined(t) catch t;
                            }
                            try fixed_types.append(self.gpa, t);
                        }
                        continue;
                    }
                }
                if (opk == .array_type) {
                    const at = hir_mod.arrayTypeOf(self.hir, rt.operand);
                    const elt = try self.lowererLowerWithTypeParams(at.element);
                    try rest_elem_types.append(self.gpa, elt);
                    saw_unknown_rest = true;
                    continue;
                }
                const elt = try self.lowererLowerWithTypeParams(rt.operand);
                try rest_elem_types.append(self.gpa, elt);
                saw_unknown_rest = true;
                continue;
            }
            var t = try self.lowererLowerWithTypeParams(e);
            if (self.tupleElementHasOptionalMarker(e)) {
                t = self.unionWithUndefined(t) catch t;
            }
            try fixed_types.append(self.gpa, t);
        }

        var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer members.deinit(self.gpa);

        const fixed_prefix_len: usize = if (saw_unknown_rest) blk: {
            var n: usize = 0;
            for (elems) |e| {
                if (self.hir.kindOf(e) == .rest_type) {
                    const rt = hir_mod.restTypeOf(self.hir, e);
                    const opk = self.hir.kindOf(rt.operand);
                    if (opk == .tuple_type) {
                        const inner_elems = hir_mod.tupleTypeElements(self.hir, rt.operand);
                        var inner_has_rest = false;
                        for (inner_elems) |ie| {
                            if (self.hir.kindOf(ie) == .rest_type) {
                                inner_has_rest = true;
                                break;
                            }
                        }
                        if (!inner_has_rest) {
                            n += inner_elems.len;
                            continue;
                        }
                    }
                    break;
                }
                n += 1;
            }
            break :blk n;
        } else fixed_types.items.len;

        var i: usize = 0;
        while (i < fixed_prefix_len) : (i += 1) {
            const t = fixed_types.items[i];
            var nbuf: [12]u8 = undefined;
            const name_str = std.fmt.bufPrint(&nbuf, "{d}", .{i}) catch continue;
            const name = self.string_interner.intern(name_str) catch continue;
            try members.append(self.gpa, .{
                .name = name,
                .type = t,
                .is_optional = false,
                .is_readonly = false,
                .is_method = false,
            });
        }

        const length_id = self.string_interner.intern("length") catch return error.OutOfMemory;
        const length_t: TypeId = if (saw_unknown_rest)
            types.Primitive.number_t
        else
            self.interner.internNumberLiteral(@floatFromInt(fixed_types.items.len)) catch types.Primitive.number_t;
        try members.append(self.gpa, .{
            .name = length_id,
            .type = length_t,
            .is_optional = false,
            .is_readonly = true,
            .is_method = false,
        });

        var idx_union: std.ArrayListUnmanaged(TypeId) = .empty;
        defer idx_union.deinit(self.gpa);
        for (fixed_types.items) |t| try idx_union.append(self.gpa, t);
        for (rest_elem_types.items) |t| try idx_union.append(self.gpa, t);
        const elem_union: TypeId = if (idx_union.items.len == 0)
            types.Primitive.never
        else if (idx_union.items.len == 1)
            idx_union.items[0]
        else
            self.interner.internUnion(idx_union.items) catch types.Primitive.any;
        return self.interner.internObjectTypeWithIndex(members.items, types.Primitive.none, elem_union) catch error.OutOfMemory;
    }

    fn tupleElementHasOptionalMarker(self: *Checker, elem: NodeId) bool {
        const src = self.source orelse return false;
        const span = self.hir.spanOf(elem);
        var i = span.end;
        while (i < src.len) : (i += 1) {
            switch (src[i]) {
                ' ', '\t', '\r', '\n' => continue,
                '?' => return true,
                else => return false,
            }
        }
        return false;
    }

    /// Evaluate `check extends ext ? tt : ff`. If either side carries a
    /// free type parameter (or a downstream conditional/keyof that
    /// hasn't reduced), defer by interning the conditional. If `check`
    /// is a union and itself a naked type parameter substitution,
    /// distribute. Otherwise pick the branch by structural assignability.
    /// Side note on `infer X` placeholders: when `ext` carries one,
    /// we attempt structural matching against `check` to bind the
    /// `infer` variable; the substitution is then applied to `tt`
    /// before returning. Today only the function-return case is
    /// supported (`T extends (...) => infer R ? R : never`).
    fn evalConditional(
        self: *Checker,
        check: TypeId,
        ext: TypeId,
        tt: TypeId,
        ff: TypeId,
        allow_infer_match: bool,
    ) CheckError!TypeId {
        // Distribute over a union check.
        if (self.interner.pool.flagsOf(check).is_union) {
            const members = self.interner.unionMembers(check);
            var built: std.ArrayListUnmanaged(TypeId) = .empty;
            defer built.deinit(self.gpa);
            for (members) |m| {
                const member_tt = if (tt == check) m else tt;
                const member_ff = if (ff == check) m else ff;
                const r = try self.evalConditional(m, ext, member_tt, member_ff, allow_infer_match);
                if (r == types.Primitive.never) continue;
                try built.append(self.gpa, r);
            }
            if (built.items.len == 0) return types.Primitive.never;
            if (built.items.len == 1) return built.items[0];
            return self.interner.internUnion(built.items) catch return error.OutOfMemory;
        }
        // `infer X` matching: when `ext` is a signature with infer'd
        // type-parameter placeholders and `check` is also a signature,
        // bind each infer'd placeholder structurally and substitute
        // into `tt` before returning.
        if (allow_infer_match) {
            var infer_subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
            defer infer_subs.deinit(self.gpa);
            const matched = self.matchInfer(check, ext, &infer_subs) catch false;
            if (matched and infer_subs.count() > 0) {
                return self.substituteType(tt, &infer_subs);
            }
        }
        // Defer if the check or extends type carries a free type parameter.
        if (self.containsFreeTypeParameter(check) or self.containsFreeTypeParameter(ext)) {
            return self.interner.internConditional(check, ext, tt, ff) catch return error.OutOfMemory;
        }
        const ok = if (self.stringLiteralValueFromType(check)) |sid|
            try self.stringLiteralAssignableToType(sid, ext)
        else
            self.engine.isAssignableTo(check, ext) catch false;
        return if (ok) tt else ff;
    }

    /// Like `evalConditional` but skips union distribution — used for
    /// the bracketed `[T] extends [U]` form where TS suppresses the
    /// distributive behavior.
    fn evalConditionalNonDistributing(
        self: *Checker,
        check: TypeId,
        ext: TypeId,
        tt: TypeId,
        ff: TypeId,
        allow_infer_match: bool,
    ) CheckError!TypeId {
        if (allow_infer_match) {
            var infer_subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
            defer infer_subs.deinit(self.gpa);
            const matched = self.matchInfer(check, ext, &infer_subs) catch false;
            if (matched and infer_subs.count() > 0) {
                return self.substituteType(tt, &infer_subs);
            }
        }
        if (self.containsFreeTypeParameter(check) or self.containsFreeTypeParameter(ext)) {
            return self.interner.internConditional(check, ext, tt, ff) catch return error.OutOfMemory;
        }
        const ok = if (self.stringLiteralValueFromType(check)) |sid|
            try self.stringLiteralAssignableToType(sid, ext)
        else
            self.engine.isAssignableTo(check, ext) catch false;
        return if (ok) tt else ff;
    }

    /// Walk the HIR ext-side of a conditional looking for `infer X`
    /// nodes; for each, register the name → TypeParameter mapping
    /// in the current narrow scope so subsequent `X` references in
    /// the conditional's true-branch resolve.
    fn registerInferNames(self: *Checker, ext_node: NodeId, ext_t: TypeId) !void {
        _ = ext_t;
        try self.walkAndRegisterInfer(ext_node);
    }

    const InferConstraintInfo = struct {
        node: NodeId,
        constraint: NodeId,
        first_reported: bool = false,
    };

    fn checkConditionalInferConstraints(self: *Checker, ext_node: NodeId) CheckError!void {
        var inferred: std.AutoHashMapUnmanaged(hir_mod.StringId, InferConstraintInfo) = .empty;
        defer inferred.deinit(self.gpa);
        try self.collectInferConstraintInfo(ext_node, &inferred);
        try self.reportInvalidInferConstraintRefs(ext_node, &inferred);
    }

    fn collectInferConstraintInfo(
        self: *Checker,
        node: NodeId,
        inferred: *std.AutoHashMapUnmanaged(hir_mod.StringId, InferConstraintInfo),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(node)) {
            .infer_type => {
                const ip = hir_mod.inferTypeOf(self.hir, node);
                if (inferred.getPtr(ip.name)) |prior| {
                    if (!self.inferConstraintsEqual(prior.constraint, ip.constraint)) {
                        const tp_name = self.string_interner.get(ip.name);
                        const msg = std.fmt.allocPrint(
                            self.diag_arena.allocator(),
                            "All declarations of '{s}' must have identical constraints.",
                            .{tp_name},
                        ) catch return error.OutOfMemory;
                        if (!prior.first_reported) {
                            try self.reportInferTypeName(prior.node, ip.name, msg);
                            prior.first_reported = true;
                        }
                        try self.reportInferTypeName(node, ip.name, msg);
                    }
                } else {
                    try inferred.put(self.gpa, ip.name, .{ .node = node, .constraint = ip.constraint });
                }
                if (ip.constraint != hir_mod.none_node_id) {
                    try self.collectInferConstraintInfo(ip.constraint, inferred);
                }
            },
            .object_type => {
                for (hir_mod.objectTypeMembers(self.hir, node)) |member| {
                    switch (self.hir.kindOf(member)) {
                        .interface_member => {
                            const im = hir_mod.interfaceMemberOf(self.hir, member);
                            try self.collectInferConstraintInfo(im.type_node, inferred);
                        },
                        .index_signature => {
                            const ix = hir_mod.indexSignatureOf(self.hir, member);
                            try self.collectInferConstraintInfo(ix.key_type, inferred);
                            try self.collectInferConstraintInfo(ix.value_type, inferred);
                        },
                        else => {},
                    }
                }
            },
            .fn_type, .constructor_type => {
                const ft = hir_mod.fnTypeOf(self.hir, node);
                const params = self.hir.childSlice(ft.params_start, @intCast(ft.params_len));
                for (params) |p| {
                    if (self.hir.kindOf(p) != .parameter) continue;
                    const pp = hir_mod.parameterOf(self.hir, p);
                    try self.collectInferConstraintInfo(pp.type_annotation, inferred);
                }
                try self.collectInferConstraintInfo(ft.return_type, inferred);
            },
            .union_type => for (hir_mod.unionTypeMembers(self.hir, node)) |m| try self.collectInferConstraintInfo(m, inferred),
            .intersection_type => for (hir_mod.intersectionTypeMembers(self.hir, node)) |m| try self.collectInferConstraintInfo(m, inferred),
            .array_type => try self.collectInferConstraintInfo(hir_mod.arrayTypeOf(self.hir, node).element, inferred),
            .tuple_type => for (hir_mod.tupleTypeElements(self.hir, node)) |e| try self.collectInferConstraintInfo(e, inferred),
            .rest_type => try self.collectInferConstraintInfo(hir_mod.restTypeOf(self.hir, node).operand, inferred),
            .indexed_access_type => {
                const ia = hir_mod.indexedAccessTypeOf(self.hir, node);
                try self.collectInferConstraintInfo(ia.object, inferred);
                try self.collectInferConstraintInfo(ia.index, inferred);
            },
            .keyof_type => try self.collectInferConstraintInfo(hir_mod.keyofTypeOf(self.hir, node).operand, inferred),
            .conditional_type => {
                const c = hir_mod.conditionalTypeOf(self.hir, node);
                try self.collectInferConstraintInfo(c.check, inferred);
                try self.collectInferConstraintInfo(c.extends, inferred);
                try self.collectInferConstraintInfo(c.true_branch, inferred);
                try self.collectInferConstraintInfo(c.false_branch, inferred);
            },
            else => {},
        }
    }

    fn inferConstraintsEqual(self: *Checker, a: NodeId, b: NodeId) bool {
        if (a == hir_mod.none_node_id or b == hir_mod.none_node_id) return true;
        return self.nodeSourceTextEqual(a, b);
    }

    fn reportInvalidInferConstraintRefs(
        self: *Checker,
        node: NodeId,
        inferred: *const std.AutoHashMapUnmanaged(hir_mod.StringId, InferConstraintInfo),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(node)) {
            .infer_type => {
                const ip = hir_mod.inferTypeOf(self.hir, node);
                if (ip.constraint != hir_mod.none_node_id) {
                    try self.reportInvalidInferConstraintRefsInConstraint(ip.constraint, inferred);
                }
            },
            .object_type => {
                for (hir_mod.objectTypeMembers(self.hir, node)) |member| {
                    switch (self.hir.kindOf(member)) {
                        .interface_member => {
                            const im = hir_mod.interfaceMemberOf(self.hir, member);
                            try self.reportInvalidInferConstraintRefs(im.type_node, inferred);
                        },
                        .index_signature => {
                            const ix = hir_mod.indexSignatureOf(self.hir, member);
                            try self.reportInvalidInferConstraintRefs(ix.key_type, inferred);
                            try self.reportInvalidInferConstraintRefs(ix.value_type, inferred);
                        },
                        else => {},
                    }
                }
            },
            .fn_type, .constructor_type => {
                const ft = hir_mod.fnTypeOf(self.hir, node);
                const params = self.hir.childSlice(ft.params_start, @intCast(ft.params_len));
                for (params) |p| {
                    if (self.hir.kindOf(p) != .parameter) continue;
                    const pp = hir_mod.parameterOf(self.hir, p);
                    try self.reportInvalidInferConstraintRefs(pp.type_annotation, inferred);
                }
                try self.reportInvalidInferConstraintRefs(ft.return_type, inferred);
            },
            .union_type => for (hir_mod.unionTypeMembers(self.hir, node)) |m| try self.reportInvalidInferConstraintRefs(m, inferred),
            .intersection_type => for (hir_mod.intersectionTypeMembers(self.hir, node)) |m| try self.reportInvalidInferConstraintRefs(m, inferred),
            .array_type => try self.reportInvalidInferConstraintRefs(hir_mod.arrayTypeOf(self.hir, node).element, inferred),
            .tuple_type => for (hir_mod.tupleTypeElements(self.hir, node)) |e| try self.reportInvalidInferConstraintRefs(e, inferred),
            .rest_type => try self.reportInvalidInferConstraintRefs(hir_mod.restTypeOf(self.hir, node).operand, inferred),
            .indexed_access_type => {
                const ia = hir_mod.indexedAccessTypeOf(self.hir, node);
                try self.reportInvalidInferConstraintRefs(ia.object, inferred);
                try self.reportInvalidInferConstraintRefs(ia.index, inferred);
            },
            .keyof_type => try self.reportInvalidInferConstraintRefs(hir_mod.keyofTypeOf(self.hir, node).operand, inferred),
            .conditional_type => {
                const c = hir_mod.conditionalTypeOf(self.hir, node);
                try self.reportInvalidInferConstraintRefs(c.check, inferred);
                try self.reportInvalidInferConstraintRefs(c.extends, inferred);
                try self.reportInvalidInferConstraintRefs(c.true_branch, inferred);
                try self.reportInvalidInferConstraintRefs(c.false_branch, inferred);
            },
            else => {},
        }
    }

    fn reportInvalidInferConstraintRefsInConstraint(
        self: *Checker,
        node: NodeId,
        inferred: *const std.AutoHashMapUnmanaged(hir_mod.StringId, InferConstraintInfo),
    ) CheckError!void {
        if (node == hir_mod.none_node_id) return;
        switch (self.hir.kindOf(node)) {
            .type_ref => {
                const r = hir_mod.typeRefOf(self.hir, node);
                if (r.qualifier_len == 0) {
                    if (inferred.contains(r.name) or !self.inferConstraintTypeRefResolvable(r.name)) {
                        try self.reportCannotFindName(node, r.name);
                    }
                }
                for (hir_mod.typeRefArgs(self.hir, node)) |arg| {
                    try self.reportInvalidInferConstraintRefsInConstraint(arg, inferred);
                }
            },
            .union_type => for (hir_mod.unionTypeMembers(self.hir, node)) |m| try self.reportInvalidInferConstraintRefsInConstraint(m, inferred),
            .intersection_type => for (hir_mod.intersectionTypeMembers(self.hir, node)) |m| try self.reportInvalidInferConstraintRefsInConstraint(m, inferred),
            .array_type => try self.reportInvalidInferConstraintRefsInConstraint(hir_mod.arrayTypeOf(self.hir, node).element, inferred),
            .tuple_type => for (hir_mod.tupleTypeElements(self.hir, node)) |e| try self.reportInvalidInferConstraintRefsInConstraint(e, inferred),
            .rest_type => try self.reportInvalidInferConstraintRefsInConstraint(hir_mod.restTypeOf(self.hir, node).operand, inferred),
            .keyof_type => try self.reportInvalidInferConstraintRefsInConstraint(hir_mod.keyofTypeOf(self.hir, node).operand, inferred),
            .indexed_access_type => {
                const ia = hir_mod.indexedAccessTypeOf(self.hir, node);
                try self.reportInvalidInferConstraintRefsInConstraint(ia.object, inferred);
                try self.reportInvalidInferConstraintRefsInConstraint(ia.index, inferred);
            },
            .conditional_type => {
                const c = hir_mod.conditionalTypeOf(self.hir, node);
                try self.reportInvalidInferConstraintRefsInConstraint(c.check, inferred);
                try self.reportInvalidInferConstraintRefsInConstraint(c.extends, inferred);
                try self.reportInvalidInferConstraintRefsInConstraint(c.true_branch, inferred);
                try self.reportInvalidInferConstraintRefsInConstraint(c.false_branch, inferred);
            },
            .object_type => {
                for (hir_mod.objectTypeMembers(self.hir, node)) |member| {
                    switch (self.hir.kindOf(member)) {
                        .interface_member => {
                            const im = hir_mod.interfaceMemberOf(self.hir, member);
                            try self.reportInvalidInferConstraintRefsInConstraint(im.type_node, inferred);
                        },
                        .index_signature => {
                            const ix = hir_mod.indexSignatureOf(self.hir, member);
                            try self.reportInvalidInferConstraintRefsInConstraint(ix.key_type, inferred);
                            try self.reportInvalidInferConstraintRefsInConstraint(ix.value_type, inferred);
                        },
                        else => {},
                    }
                }
            },
            else => {},
        }
    }

    fn inferConstraintTypeRefResolvable(self: *Checker, name: hir_mod.StringId) bool {
        const raw = self.string_interner.get(name);
        if (std.mem.eql(u8, raw, "any") or
            std.mem.eql(u8, raw, "unknown") or
            std.mem.eql(u8, raw, "never") or
            std.mem.eql(u8, raw, "void") or
            std.mem.eql(u8, raw, "null") or
            std.mem.eql(u8, raw, "undefined") or
            std.mem.eql(u8, raw, "string") or
            std.mem.eql(u8, raw, "number") or
            std.mem.eql(u8, raw, "boolean") or
            std.mem.eql(u8, raw, "bigint") or
            std.mem.eql(u8, raw, "symbol") or
            std.mem.eql(u8, raw, "object"))
        {
            return true;
        }
        if (self.generic_aliases.contains(name)) return true;
        return self.typeRefNameExists(name);
    }

    fn typeNodeContainsInfer(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id) return false;
        switch (self.hir.kindOf(node)) {
            .infer_type => return true,
            .object_type => {
                for (hir_mod.objectTypeMembers(self.hir, node)) |member| {
                    switch (self.hir.kindOf(member)) {
                        .interface_member => {
                            const im = hir_mod.interfaceMemberOf(self.hir, member);
                            if (self.typeNodeContainsInfer(im.type_node)) return true;
                        },
                        .index_signature => {
                            const ix = hir_mod.indexSignatureOf(self.hir, member);
                            if (self.typeNodeContainsInfer(ix.key_type) or self.typeNodeContainsInfer(ix.value_type)) return true;
                        },
                        else => {},
                    }
                }
                return false;
            },
            .fn_type, .constructor_type => {
                const ft = hir_mod.fnTypeOf(self.hir, node);
                const params = self.hir.childSlice(ft.params_start, @intCast(ft.params_len));
                for (params) |p| {
                    if (self.hir.kindOf(p) != .parameter) continue;
                    const pp = hir_mod.parameterOf(self.hir, p);
                    if (self.typeNodeContainsInfer(pp.type_annotation)) return true;
                }
                return self.typeNodeContainsInfer(ft.return_type);
            },
            .union_type => {
                for (hir_mod.unionTypeMembers(self.hir, node)) |m| if (self.typeNodeContainsInfer(m)) return true;
                return false;
            },
            .intersection_type => {
                for (hir_mod.intersectionTypeMembers(self.hir, node)) |m| if (self.typeNodeContainsInfer(m)) return true;
                return false;
            },
            .array_type => return self.typeNodeContainsInfer(hir_mod.arrayTypeOf(self.hir, node).element),
            .tuple_type => {
                for (hir_mod.tupleTypeElements(self.hir, node)) |e| if (self.typeNodeContainsInfer(e)) return true;
                return false;
            },
            .rest_type => return self.typeNodeContainsInfer(hir_mod.restTypeOf(self.hir, node).operand),
            .keyof_type => return self.typeNodeContainsInfer(hir_mod.keyofTypeOf(self.hir, node).operand),
            .indexed_access_type => {
                const ia = hir_mod.indexedAccessTypeOf(self.hir, node);
                return self.typeNodeContainsInfer(ia.object) or self.typeNodeContainsInfer(ia.index);
            },
            .conditional_type => {
                const c = hir_mod.conditionalTypeOf(self.hir, node);
                return self.typeNodeContainsInfer(c.check) or
                    self.typeNodeContainsInfer(c.extends) or
                    self.typeNodeContainsInfer(c.true_branch) or
                    self.typeNodeContainsInfer(c.false_branch);
            },
            else => return false,
        }
    }

    fn walkAndRegisterInfer(self: *Checker, node: NodeId) !void {
        if (node == hir_mod.none_node_id) return;
        const k = self.hir.kindOf(node);
        if (k == .infer_type) {
            const ip = hir_mod.inferTypeOf(self.hir, node);
            const constraint: TypeId = if (ip.constraint != hir_mod.none_node_id)
                try self.lowerer.lower(ip.constraint)
            else
                types.Primitive.unknown;
            const tp_id = self.interner.internTypeParameter(ip.name, constraint, types.Primitive.none) catch return;
            try self.recordNarrow(ip.name, tp_id);
            return;
        }
        if (k == .fn_type or k == .constructor_type) {
            const ft = hir_mod.fnTypeOf(self.hir, node);
            const params = self.hir.childSlice(ft.params_start, @intCast(ft.params_len));
            for (params) |p| {
                if (self.hir.kindOf(p) == .parameter) {
                    const pp = hir_mod.parameterOf(self.hir, p);
                    if (pp.type_annotation != hir_mod.none_node_id) {
                        try self.walkAndRegisterInfer(pp.type_annotation);
                    }
                }
            }
            if (ft.return_type != hir_mod.none_node_id) {
                try self.walkAndRegisterInfer(ft.return_type);
            }
            return;
        }
        if (k == .union_type) {
            for (hir_mod.unionTypeMembers(self.hir, node)) |m| try self.walkAndRegisterInfer(m);
            return;
        }
        if (k == .intersection_type) {
            for (hir_mod.intersectionTypeMembers(self.hir, node)) |m| try self.walkAndRegisterInfer(m);
            return;
        }
        if (k == .array_type) {
            const a = hir_mod.arrayTypeOf(self.hir, node);
            try self.walkAndRegisterInfer(a.element);
            return;
        }
        if (k == .tuple_type) {
            for (hir_mod.tupleTypeElements(self.hir, node)) |e| try self.walkAndRegisterInfer(e);
            return;
        }
        if (k == .indexed_access_type) {
            const ia = hir_mod.indexedAccessTypeOf(self.hir, node);
            try self.walkAndRegisterInfer(ia.object);
            try self.walkAndRegisterInfer(ia.index);
            return;
        }
        if (k == .rest_type) {
            try self.walkAndRegisterInfer(hir_mod.restTypeOf(self.hir, node).operand);
            return;
        }
        if (k == .keyof_type) {
            try self.walkAndRegisterInfer(hir_mod.keyofTypeOf(self.hir, node).operand);
            return;
        }
        if (k == .conditional_type) {
            const c = hir_mod.conditionalTypeOf(self.hir, node);
            try self.walkAndRegisterInfer(c.check);
            try self.walkAndRegisterInfer(c.extends);
            try self.walkAndRegisterInfer(c.true_branch);
            try self.walkAndRegisterInfer(c.false_branch);
            return;
        }
        if (k == .object_type) {
            for (hir_mod.objectTypeMembers(self.hir, node)) |member| {
                switch (self.hir.kindOf(member)) {
                    .interface_member => {
                        const im = hir_mod.interfaceMemberOf(self.hir, member);
                        try self.walkAndRegisterInfer(im.type_node);
                    },
                    .index_signature => {
                        const ix = hir_mod.indexSignatureOf(self.hir, member);
                        try self.walkAndRegisterInfer(ix.key_type);
                        try self.walkAndRegisterInfer(ix.value_type);
                    },
                    else => {},
                }
            }
            return;
        }
        // Other type-node kinds either don't carry infer placeholders
        // in normal usage, or are deferred to a Phase 6 follow-up.
    }

    /// Structural match between `check` and `ext`, treating any
    /// TypeParameter in `ext` as an infer'd placeholder. On match,
    /// records `infer_param -> check_subterm` in `subs`. Returns
    /// false if the structural shapes don't align.
    fn matchInfer(
        self: *Checker,
        check: TypeId,
        ext: TypeId,
        subs: *std.AutoHashMapUnmanaged(TypeId, TypeId),
    ) !bool {
        if (self.interner.pool.flagsOf(ext).is_type_parameter) {
            const tp = self.interner.pool.type_parameter_payloads.items[self.interner.pool.payloadOf(ext)];
            if (tp.constraint != types.Primitive.none and
                tp.constraint != types.Primitive.unknown and
                !(self.engine.isAssignableTo(check, tp.constraint) catch false))
            {
                return false;
            }
            try subs.put(self.gpa, ext, check);
            return true;
        }
        const ef = self.interner.pool.flagsOf(ext);
        const cf = self.interner.pool.flagsOf(check);
        if (ef.is_signature and cf.is_signature) {
            // For the common ReturnType pattern `(...args: any[]) =>
            // infer R`, the ext side may have a different parameter
            // count than the check side. We don't enforce parameter
            // matching here — only the return-type unification. This
            // is the high-frequency `infer R` use case (ReturnType,
            // Awaited, Parameters, etc.); structural param matching
            // is a Phase 6 follow-up.
            const er = self.interner.signatureReturn(ext) orelse return true;
            const cr = self.interner.signatureReturn(check) orelse return true;
            return self.matchInfer(cr, er, subs);
        }
        // Default: identity.
        return check == ext;
    }

    fn containsFreeTypeParameter(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_type_parameter) return true;
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |m| if (self.containsFreeTypeParameter(m)) return true;
            return false;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |m| if (self.containsFreeTypeParameter(m)) return true;
            return false;
        }
        if (flags.is_object_type) {
            const members = self.interner.objectMembers(t);
            for (members) |m| if (self.containsFreeTypeParameter(m.type)) return true;
            const string_idx = self.interner.objectStringIndex(t);
            if (string_idx != types.Primitive.none and self.containsFreeTypeParameter(string_idx)) return true;
            const number_idx = self.interner.objectNumberIndex(t);
            if (number_idx != types.Primitive.none and self.containsFreeTypeParameter(number_idx)) return true;
            return false;
        }
        if (flags.is_signature) {
            const params = self.interner.signatureParams(t);
            for (params) |p| if (self.containsFreeTypeParameter(p)) return true;
            if (self.interner.signatureReturn(t)) |r| if (self.containsFreeTypeParameter(r)) return true;
            return false;
        }
        if (flags.is_keyof) {
            const payload_idx = self.interner.pool.payloadOf(t);
            if (payload_idx >= self.interner.pool.keyof_payloads.items.len) return false;
            const k = self.interner.pool.keyof_payloads.items[payload_idx];
            return self.containsFreeTypeParameter(k.operand);
        }
        if (flags.is_indexed_access) {
            const payload_idx = self.interner.pool.payloadOf(t);
            if (payload_idx >= self.interner.pool.indexed_access_payloads.items.len) return false;
            const ia = self.interner.pool.indexed_access_payloads.items[payload_idx];
            return self.containsFreeTypeParameter(ia.object) or self.containsFreeTypeParameter(ia.index);
        }
        if (flags.is_conditional) {
            const c = self.interner.conditionalPayload(t);
            return self.containsFreeTypeParameter(c.check_type) or
                self.containsFreeTypeParameter(c.extends_type) or
                self.containsFreeTypeParameter(c.true_branch) or
                self.containsFreeTypeParameter(c.false_branch);
        }
        if (flags.is_mapped) {
            const m = self.interner.mappedPayload(t);
            return self.containsFreeTypeParameter(m.constraint) or self.containsFreeTypeParameter(m.template);
        }
        if (flags.is_template_literal) {
            for (self.interner.templateLiteralTypes(t)) |part| {
                if (self.containsFreeTypeParameter(part)) return true;
            }
            return false;
        }
        if (flags.is_string_mapping) {
            return self.containsFreeTypeParameter(self.interner.stringMappingPayload(t).inner);
        }
        return false;
    }

    fn firstFreeTypeParameter(self: *Checker, t: TypeId) ?TypeId {
        if (t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_type_parameter) return t;
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |m| {
                if (self.firstFreeTypeParameter(m)) |tp| return tp;
            }
            return null;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |m| {
                if (self.firstFreeTypeParameter(m)) |tp| return tp;
            }
            return null;
        }
        if (flags.is_object_type) {
            for (self.interner.objectMembers(t)) |m| {
                if (self.firstFreeTypeParameter(m.type)) |tp| return tp;
            }
            const string_idx = self.interner.objectStringIndex(t);
            if (string_idx != types.Primitive.none) {
                if (self.firstFreeTypeParameter(string_idx)) |tp| return tp;
            }
            const number_idx = self.interner.objectNumberIndex(t);
            if (number_idx != types.Primitive.none) {
                if (self.firstFreeTypeParameter(number_idx)) |tp| return tp;
            }
            return null;
        }
        if (flags.is_signature) {
            for (self.interner.signatureParams(t)) |p| {
                if (self.firstFreeTypeParameter(p)) |tp| return tp;
            }
            if (self.interner.signatureReturn(t)) |r| {
                if (self.firstFreeTypeParameter(r)) |tp| return tp;
            }
            return null;
        }
        if (flags.is_mapped) {
            const m = self.interner.mappedPayload(t);
            if (self.firstFreeTypeParameter(m.constraint)) |tp| return tp;
            return self.firstFreeTypeParameter(m.template);
        }
        if (flags.is_template_literal) {
            for (self.interner.templateLiteralTypes(t)) |part| {
                if (self.firstFreeTypeParameter(part)) |tp| return tp;
            }
            return null;
        }
        if (flags.is_string_mapping) {
            return self.firstFreeTypeParameter(self.interner.stringMappingPayload(t).inner);
        }
        return null;
    }

    fn lowerBuiltinObjectType(self: *Checker, name: []const u8) ?TypeId {
        const t = self.lowerBuiltinObjectTypeRaw(name) orelse return null;
        if (t >= types.Primitive.first_dynamic and t < self.interner.pool.typeCount()) {
            // Memoize the display name so `simpleDiagnosticTypeName`
            // can render `Date` / `RegExp` / etc. in TS2345/TS2322
            // prose instead of falling through to the positional
            // placeholder. First-write wins so we don't overwrite the
            // canonical name for shapes that happen to collide with
            // a later builtin's empty-object intern.
            if (!self.builtin_object_names.contains(t)) {
                self.builtin_object_names.put(self.gpa, t, name) catch {};
            }
        }
        return t;
    }

    fn lowerBuiltinObjectTypeRaw(self: *Checker, name: []const u8) ?TypeId {
        if (std.mem.eql(u8, name, "Event")) {
            const members = [_]types.ObjectMember{
                .{
                    .name = self.string_interner.intern("type") catch return types.Primitive.unknown,
                    .type = types.Primitive.string_t,
                    .is_optional = false,
                    .is_readonly = true,
                    .is_method = false,
                },
            };
            return self.interner.internObjectType(&members) catch types.Primitive.unknown;
        }
        if (std.mem.eql(u8, name, "Date")) {
            const sig_void_number = self.interner.internSignature(&[_]TypeId{}, types.Primitive.number_t, false) catch
                return types.Primitive.unknown;
            const sig_void_string = self.interner.internSignature(&[_]TypeId{}, types.Primitive.string_t, false) catch
                return types.Primitive.unknown;
            const members = [_]types.ObjectMember{
                .{
                    .name = self.string_interner.intern("getDate") catch return types.Primitive.unknown,
                    .type = sig_void_number,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("getDay") catch return types.Primitive.unknown,
                    .type = sig_void_number,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("getFullYear") catch return types.Primitive.unknown,
                    .type = sig_void_number,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("getHours") catch return types.Primitive.unknown,
                    .type = sig_void_number,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("getMilliseconds") catch return types.Primitive.unknown,
                    .type = sig_void_number,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("getMinutes") catch return types.Primitive.unknown,
                    .type = sig_void_number,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("getMonth") catch return types.Primitive.unknown,
                    .type = sig_void_number,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("getSeconds") catch return types.Primitive.unknown,
                    .type = sig_void_number,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("getTime") catch return types.Primitive.unknown,
                    .type = sig_void_number,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("toISOString") catch return types.Primitive.unknown,
                    .type = sig_void_string,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("toString") catch return types.Primitive.unknown,
                    .type = sig_void_string,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
            };
            return self.interner.internObjectType(&members) catch types.Primitive.unknown;
        }
        if (std.mem.eql(u8, name, "Number")) {
            // tsc declares `toFixed(fractionDigits?: number)`,
            // `toExponential(fractionDigits?: number)`, and
            // `toPrecision(precision?: number)` — all with optional
            // numeric args. Encode the param as `number | undefined`
            // so `parameterTypeCanBeOmitted` treats the 0-arg call
            // form as valid. Without this, generic uses like
            // `<T extends Number>(): void { let x: T; x.toFixed(); }`
            // wrongly trip TS2554. Mirrors
            // `innerTypeParameterShadowingOuterOne(2).ts` upstream.
            const optional_number_t = self.interner.internUnion(&[_]TypeId{
                types.Primitive.number_t,
                types.Primitive.undefined_t,
            }) catch return types.Primitive.unknown;
            const sig_optional_num_string = self.interner.internSignature(&[_]TypeId{optional_number_t}, types.Primitive.string_t, false) catch
                return types.Primitive.unknown;
            const sig_value_of = self.interner.internSignature(&[_]TypeId{}, types.Primitive.number_t, false) catch
                return types.Primitive.unknown;
            const sig_void_string = self.interner.internSignature(&[_]TypeId{}, types.Primitive.string_t, false) catch
                return types.Primitive.unknown;
            const members = [_]types.ObjectMember{
                .{
                    .name = self.string_interner.intern("toFixed") catch return types.Primitive.unknown,
                    .type = sig_optional_num_string,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("toExponential") catch return types.Primitive.unknown,
                    .type = sig_optional_num_string,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("toPrecision") catch return types.Primitive.unknown,
                    .type = sig_optional_num_string,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("toString") catch return types.Primitive.unknown,
                    .type = sig_void_string,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("valueOf") catch return types.Primitive.unknown,
                    .type = sig_value_of,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
            };
            return self.interner.internObjectType(&members) catch types.Primitive.unknown;
        }
        if (std.mem.eql(u8, name, "Boolean")) {
            // tsc declares `Boolean` (the boxed wrapper) with
            // `valueOf(): boolean` and `toString(): string`. We model
            // it as a distinct object shape so `Boolean` annotations
            // render verbatim ("Type 'Boolean' is not assignable to
            // type 'boolean'") instead of decaying to `unknown` and
            // tripping unrelated diagnostic prose. Pins
            // `assignFromBooleanInterface.ts(3,1)`.
            const sig_void_bool = self.interner.internSignature(&[_]TypeId{}, types.Primitive.boolean_t, false) catch
                return types.Primitive.unknown;
            const sig_void_string = self.interner.internSignature(&[_]TypeId{}, types.Primitive.string_t, false) catch
                return types.Primitive.unknown;
            const members = [_]types.ObjectMember{
                .{
                    .name = self.string_interner.intern("valueOf") catch return types.Primitive.unknown,
                    .type = sig_void_bool,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("toString") catch return types.Primitive.unknown,
                    .type = sig_void_string,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
            };
            return self.interner.internObjectType(&members) catch types.Primitive.unknown;
        }
        if (std.mem.eql(u8, name, "Function")) {
            const any_array = self.interner.internArrayType(self.string_interner, types.Primitive.any) catch
                return types.Primitive.unknown;
            const sig_call = self.interner.internSignature(&[_]TypeId{any_array}, types.Primitive.any, false) catch
                return types.Primitive.unknown;
            const sig_call_method = self.interner.internSignature(&[_]TypeId{ types.Primitive.any, any_array }, types.Primitive.any, false) catch
                return types.Primitive.unknown;
            self.rest_signatures.put(self.gpa, sig_call, {}) catch return types.Primitive.unknown;
            self.rest_signatures.put(self.gpa, sig_call_method, {}) catch return types.Primitive.unknown;
            const members = [_]types.ObjectMember{
                .{
                    .name = self.string_interner.intern("__call") catch return types.Primitive.unknown,
                    .type = sig_call,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("call") catch return types.Primitive.unknown,
                    .type = sig_call_method,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
            };
            return self.interner.internObjectType(&members) catch types.Primitive.unknown;
        }
        if (std.mem.eql(u8, name, "RegExp")) {
            const sig_string_boolean = self.interner.internSignature(&[_]TypeId{types.Primitive.string_t}, types.Primitive.boolean_t, false) catch
                return types.Primitive.unknown;
            const sig_string_any = self.interner.internSignature(&[_]TypeId{types.Primitive.string_t}, types.Primitive.any, false) catch
                return types.Primitive.unknown;
            const members = [_]types.ObjectMember{
                .{
                    .name = self.string_interner.intern("test") catch return types.Primitive.unknown,
                    .type = sig_string_boolean,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
                .{
                    .name = self.string_interner.intern("exec") catch return types.Primitive.unknown,
                    .type = sig_string_any,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
            };
            return self.interner.internObjectType(&members) catch types.Primitive.unknown;
        }
        if (std.mem.eql(u8, name, "Node")) {
            const node_t = self.interner.internObjectType(&.{}) catch return types.Primitive.unknown;
            const sig_remove_child = self.interner.internSignature(&[_]TypeId{node_t}, node_t, false) catch
                return types.Primitive.unknown;
            const members = [_]types.ObjectMember{
                .{
                    .name = self.string_interner.intern("parentNode") catch return types.Primitive.unknown,
                    .type = node_t,
                    .is_optional = true,
                    .is_readonly = false,
                    .is_method = false,
                },
                .{
                    .name = self.string_interner.intern("removeChild") catch return types.Primitive.unknown,
                    .type = sig_remove_child,
                    .is_optional = false,
                    .is_readonly = false,
                    .is_method = true,
                },
            };
            return self.interner.internObjectType(&members) catch types.Primitive.unknown;
        }
        const builtins = [_][]const u8{
            "Object",
            "RegExp",
            "RegExpMatchArray",
            "RegExpExecArray",
            "Error",
            "TypeError",
            "RangeError",
            "SyntaxError",
            "Function",
            "PromiseLike",
            "Iterator",
            "IteratorObject",
            "AsyncIterator",
            "AsyncIteratorObject",
            "Iterable",
            "AsyncIterable",
            "IterableIterator",
            "AsyncIterableIterator",
            "ArrayBuffer",
            "Uint8Array",
            "Uint8ClampedArray",
            "Int8Array",
            "Uint16Array",
            "Int16Array",
            "Uint32Array",
            "Int32Array",
            "Float16Array",
            "Float32Array",
            "Float64Array",
            "BigUint64Array",
            "BigInt64Array",
        };
        for (builtins) |b| {
            if (!std.mem.eql(u8, name, b)) continue;
            return self.interner.internObjectType(&.{}) catch types.Primitive.unknown;
        }
        return null;
    }

    fn evalMappedType(self: *Checker, node: NodeId) CheckError!TypeId {
        const m = hir_mod.mappedTypeOf(self.hir, node);
        if (m.constraint == hir_mod.none_node_id or m.value == hir_mod.none_node_id) {
            // Fall back to plain lower.
            return self.lowerer.lower(node);
        }
        const constraint_t = try self.lowererLowerWithTypeParams(m.constraint);
        // The type-parameter NodeId — its `name` is the StringId we
        // bind for the value template.
        if (m.type_param == hir_mod.none_node_id or self.hir.kindOf(m.type_param) != .type_parameter) {
            return self.lowerer.lower(node);
        }
        const tp = hir_mod.typeParameterOf(self.hir, m.type_param);
        const tp_id = self.interner.internTypeParameter(tp.name, types.Primitive.unknown, types.Primitive.none) catch
            return error.OutOfMemory;
        try self.pushNarrowScope();
        defer self.popNarrowScope();
        try self.recordNarrow(tp.name, tp_id);

        // Materialize when the constraint is a string-literal union or
        // a single string-literal type.
        var literal_keys: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
        defer literal_keys.deinit(self.gpa);
        const can_materialize = self.collectStringLiteralKeys(constraint_t, &literal_keys);
        if (!can_materialize or literal_keys.items.len == 0) {
            if (self.typeNodeIndexedAccessHasMissingKeys(m.constraint)) {
                try self.reportOnce(m.constraint, TsCodes.type_not_assignable, "Type is not assignable to mapped type key constraint.");
            }
            if (self.hir.kindOf(m.constraint) == .keyof_type) {
                const k = hir_mod.keyofTypeOf(self.hir, m.constraint);
                const operand = self.lowererLowerWithTypeParams(k.operand) catch types.Primitive.unknown;
                const operand_flags = if (operand < self.interner.pool.typeCount())
                    self.interner.pool.flagsOf(operand)
                else
                    std.mem.zeroes(types.TypeFlags);
                if (operand != types.Primitive.unknown and
                    operand != types.Primitive.any and
                    !operand_flags.is_type_parameter and
                    !operand_flags.is_indexed_access and
                    !operand_flags.is_keyof)
                {
                    return operand;
                }
                if (operand_flags.is_type_parameter and self.mappedTypeHasIdentityTemplate(m)) {
                    const payload = self.interner.pool.type_parameter_payloads.items[self.interner.pool.payloadOf(operand)];
                    if (payload.constraint != types.Primitive.none and
                        payload.constraint != types.Primitive.unknown and
                        payload.constraint != types.Primitive.any and
                        payload.constraint < self.interner.pool.typeCount() and
                        self.interner.pool.flagsOf(payload.constraint).is_object_type and
                        self.interner.objectNumberIndex(payload.constraint) != types.Primitive.none)
                    {
                        return operand;
                    }
                }
            } else {
                return self.lowerer.lower(node);
            }
            return self.lowerer.lower(node);
        }

        var built: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer built.deinit(self.gpa);
        // Modifier values: 0 = unspecified (inherit from source),
        // 1 = add, 2 = remove. The homomorphic case
        // (`{ [K in keyof T]: ... }`) inherits the source object's
        // is_optional / is_readonly when the modifier is unspecified.
        const homomorphic_source: ?TypeId = blk: {
            if (self.hir.kindOf(m.constraint) != .keyof_type) break :blk null;
            const k = hir_mod.keyofTypeOf(self.hir, m.constraint);
            const operand = self.lowererLowerWithTypeParams(k.operand) catch break :blk null;
            if (self.interner.pool.flagsOf(operand).is_object_type) break :blk operand;
            break :blk null;
        };
        for (literal_keys.items) |key_name| {
            const key_lit = self.interner.internStringLiteral(key_name) catch continue;
            // Lower the property value with the mapped key bound to
            // the current literal. This is more faithful than lowering
            // once and substituting afterward because recursive alias
            // arguments like `DeepReadonly<T[P]>` need `T[P]` to be
            // resolved before the nested alias instantiates.
            const value_t = blk_value: {
                try self.pushNarrowScope();
                defer self.popNarrowScope();
                try self.recordNarrow(tp.name, key_lit);
                break :blk_value try self.lowererLowerWithTypeParams(m.value);
            };

            // Resolve the per-key effective name. With an `as`
            // clause (TS 4.1+ key remapping), re-lower the remap
            // with `K` bound to the current key's string literal
            // so template-literal / conditional / `Exclude<K, …>`
            // shapes evaluate eagerly. If the remap reduces to
            // `never` the key is dropped; otherwise the result
            // must be a string-like literal and replaces `key_name`.
            var effective_name: hir_mod.StringId = key_name;
            if (m.remap != hir_mod.none_node_id) {
                try self.pushNarrowScope();
                try self.recordNarrow(tp.name, key_lit);
                const remap_t = self.lowererLowerWithTypeParams(m.remap) catch types.Primitive.never;
                self.popNarrowScope();
                if (remap_t == types.Primitive.never) continue;
                const rf = self.interner.pool.flagsOf(remap_t);
                // Unwrap an intersection containing a string literal
                // (e.g. `K & string` after substitution).
                const named: TypeId = blk2: {
                    if (rf.is_intersection) {
                        const ms = self.interner.intersectionMembers(remap_t);
                        for (ms) |mt| {
                            const mf = self.interner.pool.flagsOf(mt);
                            if (mf.is_literal and mf.is_string) break :blk2 mt;
                        }
                    }
                    break :blk2 remap_t;
                };
                const nf = self.interner.pool.flagsOf(named);
                if (!(nf.is_literal and nf.is_string)) continue;
                const lit = self.interner.literalOf(named);
                switch (lit) {
                    .string_lit => |sid| effective_name = sid,
                    else => continue,
                }
            }
            // Inherit source flags when homomorphic + modifier
            // unspecified; apply +/- modifiers otherwise.
            var src_optional = false;
            var src_readonly = false;
            if (homomorphic_source) |src_t| {
                if (self.interner.objectMemberInfo(src_t, key_name)) |info| {
                    src_optional = info.is_optional;
                    src_readonly = info.is_readonly;
                }
            }
            const is_optional = switch (m.optional) {
                1 => true, // +?
                2 => false, // -?
                else => src_optional, // inherit (or false when no source)
            };
            const is_readonly = switch (m.readonly) {
                1 => true,
                2 => false,
                else => src_readonly,
            };
            try built.append(self.gpa, .{
                .name = effective_name,
                .type = value_t,
                .is_optional = is_optional,
                .is_readonly = is_readonly,
                .is_method = false,
            });
        }
        return self.interner.internObjectType(built.items) catch return error.OutOfMemory;
    }

    fn collectKeyofObjectKeys(
        self: *Checker,
        t: TypeId,
        out: *std.ArrayListUnmanaged(hir_mod.StringId),
    ) CheckError!bool {
        if (t < types.Primitive.first_dynamic or t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |member| {
                _ = try self.collectKeyofObjectKeys(member, out);
            }
            return true;
        }
        if (!flags.is_object_type) return false;
        for (self.interner.objectMembers(t)) |member| {
            var seen = false;
            for (out.items) |existing| {
                if (existing == member.name) {
                    seen = true;
                    break;
                }
            }
            if (!seen) try out.append(self.gpa, member.name);
        }
        return true;
    }

    fn mappedTypeHasIdentityTemplate(self: *Checker, m: hir_mod.MappedTypePayload) bool {
        if (m.constraint == hir_mod.none_node_id or m.value == hir_mod.none_node_id or m.type_param == hir_mod.none_node_id) return false;
        if (self.hir.kindOf(m.constraint) != .keyof_type or self.hir.kindOf(m.value) != .indexed_access_type) return false;
        const k = hir_mod.keyofTypeOf(self.hir, m.constraint);
        const ia = hir_mod.indexedAccessTypeOf(self.hir, m.value);
        const operand_name = self.bareTypeNodeName(k.operand) orelse return false;
        const object_name = self.bareTypeNodeName(ia.object) orelse return false;
        if (operand_name != object_name) return false;
        const tp = hir_mod.typeParameterOf(self.hir, m.type_param);
        const index_name = self.bareTypeNodeName(ia.index) orelse return false;
        return index_name == tp.name;
    }

    fn bareTypeNodeName(self: *Checker, node: NodeId) ?hir_mod.StringId {
        if (node == hir_mod.none_node_id) return null;
        return switch (self.hir.kindOf(node)) {
            .identifier => hir_mod.identifierOf(self.hir, node).name,
            .type_parameter => hir_mod.typeParameterOf(self.hir, node).name,
            .type_ref => blk: {
                const r = hir_mod.typeRefOf(self.hir, node);
                if (r.qualifier_len != 0 or r.args_len != 0) break :blk null;
                break :blk r.name;
            },
            else => null,
        };
    }

    /// Walk a type and accumulate the StringIds of every string-literal
    /// member. Returns false if any member isn't a string literal —
    /// in that case the mapped type can't be materialized eagerly.
    fn collectStringLiteralKeys(
        self: *Checker,
        t: TypeId,
        out: *std.ArrayListUnmanaged(hir_mod.StringId),
    ) bool {
        const flags = self.interner.pool.flagsOf(t);
        // Check `is_union` *first* because the union's propagated flag
        // set OR-folds in `is_string`/`is_literal` from each member,
        // which would otherwise misroute through the literal branch.
        if (flags.is_union) {
            const members = self.interner.unionMembers(t);
            for (members) |mt| if (!self.collectStringLiteralKeys(mt, out)) return false;
            return true;
        }
        if (flags.is_literal and flags.is_string) {
            const lit = self.interner.literalOf(t);
            switch (lit) {
                .string_lit => |sid| {
                    out.append(self.gpa, sid) catch return false;
                    return true;
                },
                else => return false,
            }
        }
        return false;
    }

    /// True iff `target` is shaped like a lowered tuple type — an
    /// object with at least a `length` member plus a numeric "0"
    /// positional member (variadic tuples have only a leading "0"
    /// when there's a middle/trailing rest, so we don't require
    /// a full sequence).
    fn isTupleShapedTarget(self: *Checker, target: TypeId) bool {
        const flags = self.interner.pool.flagsOf(target);
        if (!flags.is_object_type) return false;
        const length_id = self.string_interner.intern("length") catch return false;
        const length_t = self.interner.objectMember(target, length_id) orelse return false;
        const length_flags = self.interner.pool.flagsOf(length_t);
        if (length_flags.is_literal and length_flags.is_number) return true;
        const zero_id = self.string_interner.intern("0") catch return false;
        return self.interner.objectMember(target, zero_id) != null;
    }

    /// Positional check of an `array_literal` init against a
    /// tuple-shaped target. For each element index `i`, look up
    /// the target's member named `"i"`; if missing, fall back to
    /// the target's number-key indexer (rest slot). Returns true
    /// when every element assigns.
    fn checkArrayLiteralAgainstTuple(self: *Checker, init_node: NodeId, target: TypeId) !bool {
        return try self.arrayLiteralAssignableToTupleTarget(init_node, target, false);
    }

    fn arrayLiteralAssignableToTupleTarget(
        self: *Checker,
        init_node: NodeId,
        target: TypeId,
        emit_element_diagnostic: bool,
    ) !bool {
        const elements = hir_mod.arrayLiteralElements(self.hir, init_node);
        const fixed_prefix = self.tupleFixedPrefixCount(target);
        if (elements.len < fixed_prefix) return false;
        if (self.fixedTupleLength(target)) |len| {
            if (elements.len > len) return false;
        }
        // Collect ALL element mismatches before returning, so tuple
        // assignability emits one TS2322 per misaligned element rather
        // than stopping at the first. Mirrors upstream tsc, which on
        // `var a1: [boolean, string, number] = ["string", 1, true]`
        // emits three separate TS2322 diagnostics — one per element.
        var any_mismatch = false;
        for (elements, 0..) |el, i| {
            if (el == hir_mod.none_node_id) continue;
            const tgt_t = self.tupleElementType(target, i);
            if (tgt_t == types.Primitive.none) {
                any_mismatch = true;
                continue;
            }
            if (self.hir.kindOf(el) == .array_literal and self.isTupleShapedTarget(tgt_t)) {
                if (try self.arrayLiteralAssignableToTupleTarget(el, tgt_t, emit_element_diagnostic)) continue;
                any_mismatch = true;
                continue;
            }
            if (try self.literalExpressionAssignableToTarget(el, tgt_t)) continue;
            const el_t = try self.checkExpression(el);
            const ok = self.engine.isAssignableTo(el_t, tgt_t) catch return error.OutOfMemory;
            if (!ok) {
                if (emit_element_diagnostic) {
                    try self.reportTypeNotAssignable(el, el_t, tgt_t, "Type is not assignable to tuple element type.");
                }
                any_mismatch = true;
            }
        }
        return !any_mismatch;
    }

    fn tupleAnnotationSourceNode(self: *Checker, type_node: NodeId) ?NodeId {
        if (type_node == hir_mod.none_node_id) return null;
        switch (self.hir.kindOf(type_node)) {
            .tuple_type => return type_node,
            .type_ref => {
                const r = hir_mod.typeRefOf(self.hir, type_node);
                if (r.qualifier_len != 0 or r.args_len != 0) return null;
                const decl = self.findTypeAliasDeclInScope(type_node, r.name) orelse return null;
                const ta = hir_mod.typeAliasOf(self.hir, decl);
                if (self.hir.kindOf(ta.aliased) == .tuple_type) return ta.aliased;
                return null;
            },
            else => return null,
        }
    }

    fn expressionAssignableToTypeNode(self: *Checker, expr: NodeId, type_node: NodeId) CheckError!bool {
        const expr_t = try self.checkExpression(expr);
        const target_t = try self.lowererLowerWithTypeParams(type_node);
        if (try self.literalExpressionAssignableToTarget(expr, target_t)) return true;
        return self.engine.isAssignableTo(expr_t, target_t) catch return error.OutOfMemory;
    }

    fn tupleRestElementTypeNode(self: *Checker, rest_node: NodeId) NodeId {
        const rt = hir_mod.restTypeOf(self.hir, rest_node);
        if (self.hir.kindOf(rt.operand) == .array_type) {
            return hir_mod.arrayTypeOf(self.hir, rt.operand).element;
        }
        return rt.operand;
    }

    fn tupleTypeHasRestElement(self: *Checker, tuple_node: NodeId) bool {
        for (hir_mod.tupleTypeElements(self.hir, tuple_node)) |elem| {
            if (self.hir.kindOf(elem) == .rest_type) return true;
        }
        return false;
    }

    fn checkArrayLiteralAgainstTupleAnnotation(self: *Checker, init_node: NodeId, tuple_node: NodeId) CheckError!bool {
        const values = hir_mod.arrayLiteralElements(self.hir, init_node);
        const elems = hir_mod.tupleTypeElements(self.hir, tuple_node);
        var rest_i: ?usize = null;
        for (elems, 0..) |elem, i| {
            if (self.hir.kindOf(elem) == .rest_type) {
                rest_i = i;
                break;
            }
        }
        const ri = rest_i orelse return true;
        const suffix_len = elems.len - ri - 1;
        if (values.len < ri + suffix_len) return false;
        var i: usize = 0;
        while (i < ri) : (i += 1) {
            if (values[i] == hir_mod.none_node_id) continue;
            if (!try self.expressionAssignableToTypeNode(values[i], elems[i])) return false;
        }
        const rest_type_node = self.tupleRestElementTypeNode(elems[ri]);
        var mid = ri;
        const mid_end = values.len - suffix_len;
        while (mid < mid_end) : (mid += 1) {
            if (values[mid] == hir_mod.none_node_id) continue;
            if (!try self.expressionAssignableToTypeNode(values[mid], rest_type_node)) return false;
        }
        var s: usize = 0;
        while (s < suffix_len) : (s += 1) {
            const value_i = values.len - suffix_len + s;
            if (values[value_i] == hir_mod.none_node_id) continue;
            if (!try self.expressionAssignableToTypeNode(values[value_i], elems[ri + 1 + s])) return false;
        }
        return true;
    }

    /// Emit TS2488 "Type 'X' must have a '[Symbol.iterator]()' method
    /// that returns an iterator." — prefers the tsc-style prose with
    /// the source type name (e.g. `'{ 0: string; 1: true; }'`,
    /// `'() => any'`). Falls back to the shorter "Type must have …"
    /// form when the type can't be named. Mirrors fixtures like
    /// `iterableArrayPattern22/23`, `YieldExpression6_es6`, and
    /// the `generatorTypeCheck21` baseline.
    fn reportIteratorRequired(self: *Checker, target_node: NodeId, source_t: TypeId) CheckError!void {
        return self.reportIteratorRequiredWithSource(target_node, source_t, hir_mod.none_node_id);
    }

    /// Variant of `reportIteratorRequired` that also takes the source
    /// expression HIR node. When the source is an `object_literal`,
    /// the helper renders the shape from the HIR directly so primitive
    /// literal values (`true`, `42`, `"foo"`) keep their literal form
    /// in the diagnostic prose, matching tsc's TS2488 baselines for
    /// `iterableArrayPattern23.ts(2,1)` (`{ 0: string; 1: true; }`) and
    /// `iterableArrayPattern24.ts(2,1)` (same RHS via a rest pattern).
    fn reportIteratorRequiredWithSource(self: *Checker, target_node: NodeId, source_t: TypeId, source_node: NodeId) CheckError!void {
        if (source_node != hir_mod.none_node_id) {
            if (self.allocObjectLiteralExpressionShape(source_node) catch null) |source_name| {
                const arena = self.diag_arena.allocator();
                const msg = std.fmt.allocPrint(arena, "Type '{s}' must have a '[Symbol.iterator]()' method that returns an iterator.", .{source_name}) catch null;
                if (msg) |m| {
                    try self.report(target_node, TsCodes.yield_star_not_iterable, m);
                    return;
                }
            }
        }
        if (source_t != types.Primitive.none) {
            // Prefer the literal object/tuple shape (`{ 0: string; 1: true; }`)
            // when `allocSimpleTypeName` can't summarize the type — the
            // upstream baselines for `iterableArrayPattern22/23` and the
            // `destructuringArrayBindingPatternAndAssignment*` family use
            // the structural form for object-literal sources.
            const is_union_src = source_t < self.interner.pool.typeCount() and
                self.interner.pool.flagsOf(source_t).is_union;
            const name_opt: ?[]const u8 = blk: {
                // Unions preserve `A | B` prose (`number[] | null`) so
                // fixtures like `destructuringArrayBindingPatternAndAssignment4`
                // render the full source type instead of just one member.
                if (is_union_src) {
                    if (self.simpleDiagnosticTypeName(source_t) catch null) |n| break :blk n;
                }
                if (self.allocSimpleTypeName(source_t) catch null) |n| break :blk n;
                if (self.allocObjectTypeShape(source_t) catch null) |s| break :blk s;
                break :blk null;
            };
            if (name_opt) |source_name| {
                const arena = self.diag_arena.allocator();
                const msg = std.fmt.allocPrint(arena, "Type '{s}' must have a '[Symbol.iterator]()' method that returns an iterator.", .{source_name}) catch null;
                if (msg) |m| {
                    try self.report(target_node, TsCodes.yield_star_not_iterable, m);
                    return;
                }
            }
        }
        try self.report(target_node, TsCodes.yield_star_not_iterable, "Type must have a '[Symbol.iterator]()' method that returns an iterator.");
    }

    fn checkBindingPatternSourceType(self: *Checker, pattern_node: NodeId, source_t: TypeId, source_node: NodeId) CheckError!bool {
        if (pattern_node == hir_mod.none_node_id) return false;
        if (source_t == types.Primitive.any or source_t == types.Primitive.unknown or source_t == types.Primitive.none) return false;
        switch (self.hir.kindOf(pattern_node)) {
            .array_pattern => {
                const has_source_iterator = source_node != hir_mod.none_node_id and self.objectLiteralHasSymbolIteratorMethod(source_node);
                if (!has_source_iterator and !self.isDestructuringIterableSourceType(source_t)) {
                    try self.reportIteratorRequiredWithSource(pattern_node, source_t, source_node);
                    return true;
                }
            },
            .object_pattern => {
                if (self.strict_flags.strict_null_checks and
                    (source_t == types.Primitive.void_t or self.typeIncludesUndefined(source_t)) and
                    !self.typeIsAnyLike(source_t))
                {
                    try self.report(pattern_node, TsCodes.object_possibly_undefined, "Object is possibly 'undefined'.");
                    return true;
                }
            },
            else => {},
        }
        return false;
    }

    fn reportTypeNotArrayForTarget(self: *Checker, target_node: NodeId, source_t: TypeId) CheckError!void {
        const name_opt: ?[]const u8 = blk: {
            if (self.allocSimpleTypeName(source_t) catch null) |n| break :blk n;
            if (self.allocObjectTypeShape(source_t) catch null) |s| break :blk s;
            break :blk null;
        };
        const msg = if (name_opt) |source_name|
            try std.fmt.allocPrint(self.diag_arena.allocator(), "Type '{s}' is not an array type.", .{source_name})
        else
            "Type is not an array type.";
        try self.report(target_node, TsCodes.type_not_array_type, msg);
    }

    fn reportTypeNotArrayOrStringForForOf(self: *Checker, target_node: NodeId, source_t: TypeId, source_node: NodeId) CheckError!void {
        const name_opt: ?[]const u8 = blk: {
            if (source_node != hir_mod.none_node_id and self.hir.kindOf(source_node) == .literal_number) {
                const text = std.mem.trim(u8, self.nodeSourceTextOrEmpty(source_node), " \t\r\n");
                if (text.len != 0) break :blk text;
            }
            if (self.allocSimpleTypeName(source_t) catch null) |n| break :blk n;
            if (self.allocObjectTypeShape(source_t) catch null) |s| break :blk s;
            break :blk null;
        };
        const msg = if (name_opt) |source_name|
            try std.fmt.allocPrint(self.diag_arena.allocator(), "Type '{s}' is not an array type or a string type.", .{source_name})
        else
            "Type is not an array type or a string type.";
        try self.report(target_node, TsCodes.type_not_array_or_string_type, msg);
    }

    fn checkArrayDestructuringAssignment(self: *Checker, target_node: NodeId, source_t: TypeId, source_node: NodeId, source_offset: usize) CheckError!void {
        if (source_node != hir_mod.none_node_id and
            self.hir.kindOf(source_node) == .object_literal and
            !self.objectLiteralHasSymbolIteratorMethod(source_node))
        {
            try self.reportIteratorRequiredWithSource(target_node, source_t, source_node);
            return;
        }
        if (source_t != types.Primitive.any and source_t != types.Primitive.unknown and
            !self.isDestructuringIterableSourceType(source_t) and !self.objectLiteralHasSymbolIteratorMethod(source_node))
        {
            try self.reportIteratorRequiredWithSource(target_node, source_t, source_node);
            return;
        }
        const fallback_elem_t = try self.iterableElementType(source_t);
        const target_elements = hir_mod.arrayLiteralElements(self.hir, target_node);
        // TS2493 — array-destructuring assignment from a fixed-width
        // tuple where the binding pattern has more positions than the
        // tuple has elements (`[a, b, c] = [1]`). The tuple-out-of-
        // bounds detector already lives in `reportTupleIndexOutOfBounds`;
        // it just wasn't wired up to assignment-pattern targets yet.
        // Matches upstream baselines for `destructuringArrayBindingPatternAndAssignment1*`.
        const tuple_length_opt = if (source_t < self.interner.pool.typeCount() and
            self.interner.pool.flagsOf(source_t).is_object_type and
            self.interner.objectNumberIndex(source_t) == types.Primitive.none)
            self.fixedTupleLength(source_t)
        else
            null;
        for (target_elements, 0..) |el, i| {
            if (el == hir_mod.none_node_id) continue;
            const k = self.hir.kindOf(el);
            if (tuple_length_opt) |tuple_length| {
                if (k != .spread and k != .assignment and source_offset + i >= tuple_length) {
                    try self.reportTupleIndexOutOfBounds(el, source_t, source_offset + i, tuple_length);
                }
            }
            const elem_t = self.tupleElementType(source_t, source_offset + i);
            const source_elem_t = if (try self.arrayLiteralSourceElementType(source_node, source_offset + i)) |literal_elem_t|
                literal_elem_t
            else if (elem_t != types.Primitive.none)
                elem_t
            else
                fallback_elem_t;
            if (k == .spread) {
                const sp = hir_mod.spreadOf(self.hir, el);
                // tsc fires TS2462 when a rest element appears
                // before the end of an assignment-destructuring
                // pattern (`[...a, x] = …`). The parser already
                // reports this for binding patterns; the
                // assignment-pattern variant lives here.
                if (i + 1 < target_elements.len) {
                    try self.report(el, TsCodes.rest_element_must_be_last, "A rest element must be last in a destructuring pattern.");
                }
                if (self.hir.kindOf(sp.expression) == .assignment) {
                    // tsc anchors TS1186 at the `=` token rather than
                    // the assignment-pattern's target identifier. Mirrors
                    // `restElementWithInitializer2.ts(3,7)`. Falls back
                    // to the assignment span when source isn't available.
                    const eq_pos = self.restElementInitializerEqualPos(sp.expression);
                    try self.reportAt(sp.expression, eq_pos, TsCodes.rest_element_cannot_have_initializer, "A rest element cannot have an initializer.");
                    continue;
                }
                const rest_source_t = try self.arrayRestSourceType(source_node, source_offset + i, source_elem_t);
                if (self.hir.kindOf(sp.expression) == .array_literal) {
                    try self.checkArrayDestructuringAssignment(sp.expression, source_t, source_node, source_offset + i);
                } else if (self.hir.kindOf(sp.expression) == .object_literal) {
                    // When the rest-target is an object pattern over a
                    // tuple source (e.g. `[...{ 0: a, b }] = tuple`),
                    // tsc indexes the source object directly so any
                    // TS2339 it raises reports the tuple type, not its
                    // array widening. Skip the widening only when the
                    // rest starts at offset 0 — for a non-zero offset
                    // we'd need a tuple-slice helper to preserve shape.
                    // Mirrors `restElementWithAssignmentPattern4`.
                    const object_rest_t = blk: {
                        if (source_offset + i != 0) break :blk rest_source_t;
                        if (source_t == types.Primitive.none) break :blk rest_source_t;
                        if (source_t >= self.interner.pool.typeCount()) break :blk rest_source_t;
                        const flags = self.interner.pool.flagsOf(source_t);
                        if (flags.is_tuple) break :blk source_t;
                        if (flags.is_object_type and self.fixedTupleLength(source_t) != null) break :blk source_t;
                        break :blk rest_source_t;
                    };
                    try self.checkObjectDestructuringAssignment(sp.expression, object_rest_t, hir_mod.none_node_id);
                } else {
                    try self.checkDestructuringAssignmentTarget(sp.expression, rest_source_t);
                }
                continue;
            }
            if (k == .assignment) {
                const a = hir_mod.assignmentOf(self.hir, el);
                const default_t = try self.checkExpression(a.value);
                const effective_t = try self.destructuringSourceWithDefault(source_elem_t, default_t);
                try self.checkDestructuringAssignmentTargetWithDefault(a.target, effective_t, source_elem_t, default_t);
                continue;
            }
            if (k == .identifier) {
                const target_t = self.typeOfIdentifier(el);
                if (target_t == types.Primitive.none or
                    target_t == types.Primitive.any or
                    target_t == types.Primitive.unknown)
                {
                    continue;
                }
                const ok = self.engine.isAssignableTo(source_elem_t, target_t) catch return error.OutOfMemory;
                if (!ok) {
                    // Prefer the richer "Type 'X' is not assignable to
                    // type 'Y'." prose so array-destructuring assignment
                    // TS2322 sites pick up the source / target binding
                    // names. Matches upstream baselines for
                    // `iterableArrayPattern{5,6,8}.ts` and friends.
                    try self.reportTypeNotAssignable(el, source_elem_t, target_t, "Type is not assignable to target type.");
                } else {
                    const id = hir_mod.identifierOf(self.hir, el);
                    try self.recordNarrow(id.name, source_elem_t);
                }
                continue;
            }
            if (k == .array_literal) {
                try self.checkArrayDestructuringAssignment(el, source_elem_t, hir_mod.none_node_id, 0);
            } else if (k == .object_literal) {
                try self.checkObjectDestructuringAssignment(el, source_elem_t, hir_mod.none_node_id);
            }
        }
    }

    fn arrayRestSourceType(self: *Checker, source_node: NodeId, start_index: usize, fallback_elem_t: TypeId) CheckError!TypeId {
        if (source_node != hir_mod.none_node_id and self.hir.kindOf(source_node) == .array_literal) {
            const elements = hir_mod.arrayLiteralElements(self.hir, source_node);
            var elems: std.ArrayListUnmanaged(TypeId) = .empty;
            defer elems.deinit(self.gpa);
            if (start_index < elements.len) {
                var i = start_index;
                while (i < elements.len) : (i += 1) {
                    if (elements[i] == hir_mod.none_node_id) continue;
                    try elems.append(self.gpa, try self.checkExpression(elements[i]));
                }
            }
            const elem_t = if (elems.items.len == 0)
                types.Primitive.never
            else if (elems.items.len == 1)
                elems.items[0]
            else
                self.interner.internUnion(elems.items) catch return error.OutOfMemory;
            return self.interner.internArrayType(self.string_interner, elem_t) catch return error.OutOfMemory;
        }
        return self.interner.internArrayType(self.string_interner, fallback_elem_t) catch return error.OutOfMemory;
    }

    fn arrayLiteralSourceElementType(self: *Checker, source_node: NodeId, index: usize) CheckError!?TypeId {
        if (source_node == hir_mod.none_node_id or self.hir.kindOf(source_node) != .array_literal) return null;
        const elements = hir_mod.arrayLiteralElements(self.hir, source_node);
        if (index >= elements.len or elements[index] == hir_mod.none_node_id) return types.Primitive.never;
        return try self.checkExpression(elements[index]);
    }

    fn checkObjectDestructuringAssignment(self: *Checker, target_node: NodeId, source_t: TypeId, source_node: NodeId) CheckError!void {
        if (source_t == types.Primitive.any or source_t == types.Primitive.unknown) return;
        if (source_node != hir_mod.none_node_id and self.hir.kindOf(source_node) == .object_literal) {
            // Skip the excess-properties scan when the target pattern
            // contains a rest spread (`{...rest}`) — the rest binding
            // accepts arbitrary keys, so flagging extras as "excess"
            // surfaces spurious TS2353 against the literal RHS.
            // Mirrors tsc on `propertyAccessChain.3.ts(25-26)`.
            var target_has_spread = false;
            for (hir_mod.objectLiteralProps(self.hir, target_node)) |tprop| {
                if (self.hir.kindOf(tprop) == .spread) {
                    target_has_spread = true;
                    break;
                }
            }
            if (!target_has_spread) {
                const expected_t = try self.objectBindingPatternExpectedType(target_node, true, false);
                try self.checkExcessProperties(source_node, expected_t);
            }
        }
        var has_dynamic_computed_key = false;
        const target_props_oddl = hir_mod.objectLiteralProps(self.hir, target_node);
        for (target_props_oddl, 0..) |prop_node, prop_i| {
            if (self.hir.kindOf(prop_node) != .object_property) {
                // tsc fires TS2462 when an object-rest spread
                // (`{...rest, x} = …` or `{...a, x, ...b} = …`)
                // appears before the end of an assignment-pattern.
                // The parser already covers binding-pattern cases.
                if (self.hir.kindOf(prop_node) == .spread and prop_i + 1 < target_props_oddl.len) {
                    try self.report(prop_node, TsCodes.rest_element_must_be_last, "A rest element must be last in a destructuring pattern.");
                }
                // `({...obj?.a} = …)` — tsc fires TS2778 on the
                // optional-chain inner. Distinct from the TS2779
                // emitted for plain `({a: obj?.a} = …)` because the
                // rest target shape carries different runtime
                // semantics (we'd write across many properties).
                if (self.hir.kindOf(prop_node) == .spread) {
                    const inner = hir_mod.spreadOf(self.hir, prop_node).expression;
                    if (self.expressionIsOptionalChain(inner)) {
                        try self.report(inner, TsCodes.optional_chain_object_rest_target, "The target of an object rest assignment may not be an optional property access.");
                    }
                }
                if (has_dynamic_computed_key) {
                    const rest_t = self.interner.internObjectType(&.{}) catch return error.OutOfMemory;
                    // Unwrap the `.spread` node so the destructuring
                    // target check sees the underlying identifier /
                    // member access / pattern.
                    const target_for_rest = if (self.hir.kindOf(prop_node) == .spread)
                        hir_mod.spreadOf(self.hir, prop_node).expression
                    else
                        prop_node;
                    try self.checkDestructuringAssignmentTarget(target_for_rest, rest_t);
                }
                continue;
            }
            const op = hir_mod.objectPropertyOf(self.hir, prop_node);
            if (op.value == hir_mod.none_node_id) continue;
            if (op.is_computed) {
                const key_t = try self.checkExpression(op.key);
                if (try self.reportMissingIndexForComputedBindingKey(op.key, source_t, key_t)) {
                    has_dynamic_computed_key = true;
                }
            }
            const maybe_prop_t = try self.objectPropertyTypeForDestructuring(source_t, op.key, op.is_computed);
            if (maybe_prop_t == null and self.hir.kindOf(op.value) != .assignment) {
                const prop_name = if (op.is_computed)
                    try self.propertyNameFromComputedBindingKeyNode(op.key)
                else
                    self.propertyNameFromKeyNode(op.key);
                if (prop_name) |name| {
                    const name_str = self.string_interner.get(name);
                    // Upstream tsc widens `object` to `{}` when reporting
                    // missing-property destructuring errors — mirrors
                    // `nonPrimitiveAccessProperty.ts(5,7)`.
                    const target_text_opt: ?[]const u8 = if (source_t == types.Primitive.object_t)
                        "{}"
                    else
                        try self.allocPropertyMissingTargetTypeName(source_t);
                    const msg = if (target_text_opt) |target_text|
                        try std.fmt.allocPrint(
                            self.diag_arena.allocator(),
                            "Property '{s}' does not exist on type '{s}'.",
                            .{ name_str, target_text },
                        )
                    else
                        try std.fmt.allocPrint(
                            self.diag_arena.allocator(),
                            "Property '{s}' does not exist on type.",
                            .{name_str},
                        );
                    try self.diagnostics.append(self.gpa, .{
                        .node = op.key,
                        .code = TsCodes.property_does_not_exist,
                        .message = msg,
                    });
                }
            }
            const prop_t = maybe_prop_t orelse types.Primitive.any;
            if (self.hir.kindOf(op.value) == .assignment) {
                const a = hir_mod.assignmentOf(self.hir, op.value);
                const default_t = try self.checkExpression(a.value);
                const effective_t = try self.destructuringSourceWithDefault(prop_t, default_t);
                try self.checkDestructuringAssignmentTargetWithDefault(a.target, effective_t, prop_t, default_t);
            } else {
                try self.checkDestructuringAssignmentTarget(op.value, prop_t);
            }
        }
    }

    fn checkDestructuringAssignmentTarget(self: *Checker, target_node: NodeId, source_t: TypeId) CheckError!void {
        switch (self.hir.kindOf(target_node)) {
            .identifier, .member_access, .element_access => {
                if (self.expressionIsOptionalChain(target_node)) {
                    try self.report(target_node, TsCodes.optional_chain_assignment_target, "The left-hand side of an assignment expression may not be an optional property access.");
                }
                const target_t = if (self.hir.kindOf(target_node) == .identifier)
                    self.typeOfIdentifierDeclared(target_node)
                else
                    try self.checkExpression(target_node);
                if (target_t == types.Primitive.none or target_t == types.Primitive.any or target_t == types.Primitive.unknown) return;
                if (target_t == types.Primitive.undefined_t and
                    self.hir.kindOf(target_node) == .identifier and
                    self.identifierIsUntypedUninitializedVar(target_node))
                {
                    return;
                }
                const source_idx = if (source_t < self.interner.pool.typeCount()) self.interner.objectNumberIndex(source_t) else types.Primitive.none;
                const target_idx = if (target_t < self.interner.pool.typeCount()) self.interner.objectNumberIndex(target_t) else types.Primitive.none;
                if (source_idx != types.Primitive.none and target_idx != types.Primitive.none and
                    !(self.engine.isAssignableTo(source_idx, target_idx) catch true))
                {
                    // Use the full source/target array shapes (not the
                    // unwrapped element types) so the TS2322 prose reads
                    // `Type 'Foo[]' is not assignable to type 'string[]'.`
                    // — matches upstream baseline `iterableArrayPattern6`.
                    try self.reportTypeNotAssignable(target_node, source_t, target_t, "Type is not assignable to target type.");
                    return;
                }
                if (!(self.engine.isAssignableTo(source_t, target_t) catch true)) {
                    if (try self.tryReportSinglePropertyMissing(target_node, hir_mod.none_node_id, source_t, target_t)) return;
                    try self.reportTypeNotAssignable(target_node, source_t, target_t, "Type is not assignable to target type.");
                } else if (self.hir.kindOf(target_node) == .identifier and
                    source_t != types.Primitive.none and
                    source_t != types.Primitive.any and
                    source_t != types.Primitive.unknown)
                {
                    const id = hir_mod.identifierOf(self.hir, target_node);
                    try self.recordNarrow(id.name, source_t);
                }
            },
            .array_literal => try self.checkArrayDestructuringAssignment(target_node, source_t, hir_mod.none_node_id, 0),
            .object_literal => try self.checkObjectDestructuringAssignment(target_node, source_t, hir_mod.none_node_id),
            else => {},
        }
    }

    /// Destructuring-assignment-target check that knows the effective
    /// source was synthesized from `(source | widened-default)`. When
    /// the union fails to assign but ONE constituent alone succeeds,
    /// tsc renders only the failing constituent. For
    /// `for ([k = false] of map)` where source elem is `string` and
    /// `k: string`, the default's widened type `boolean` is the
    /// failing side — that's what the diagnostic mentions.
    fn checkDestructuringAssignmentTargetWithDefault(self: *Checker, target_node: NodeId, effective_t: TypeId, source_only_t: TypeId, default_t: TypeId) CheckError!void {
        const tk = self.hir.kindOf(target_node);
        if (tk != .identifier and tk != .member_access and tk != .element_access) {
            try self.checkDestructuringAssignmentTarget(target_node, effective_t);
            return;
        }
        const target_t = if (tk == .identifier)
            self.typeOfIdentifierDeclared(target_node)
        else
            try self.checkExpression(target_node);
        if (target_t == types.Primitive.none or target_t == types.Primitive.any or target_t == types.Primitive.unknown) {
            try self.checkDestructuringAssignmentTarget(target_node, effective_t);
            return;
        }
        if (self.engine.isAssignableTo(effective_t, target_t) catch true) {
            try self.checkDestructuringAssignmentTarget(target_node, effective_t);
            return;
        }
        const source_no_undef = self.subtractType(source_only_t, types.Primitive.undefined_t) catch source_only_t;
        const widened_default = self.widenLiteralType(default_t);
        const source_ok = if (source_no_undef == types.Primitive.never or source_no_undef == types.Primitive.none) true else (self.engine.isAssignableTo(source_no_undef, target_t) catch true);
        const default_ok = if (widened_default == types.Primitive.never or widened_default == types.Primitive.none) true else (self.engine.isAssignableTo(widened_default, target_t) catch true);
        if (source_ok and !default_ok) {
            try self.reportTypeNotAssignable(target_node, widened_default, target_t, "Type is not assignable to target type.");
            return;
        }
        if (default_ok and !source_ok) {
            try self.reportTypeNotAssignable(target_node, source_no_undef, target_t, "Type is not assignable to target type.");
            return;
        }
        try self.checkDestructuringAssignmentTarget(target_node, effective_t);
    }

    fn objectBindingPatternExpectedType(
        self: *Checker,
        pattern_node: NodeId,
        include_empty: bool,
        untyped_binding_identifiers_as_any: bool,
    ) CheckError!TypeId {
        var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer members.deinit(self.gpa);
        const elems: []const NodeId = switch (self.hir.kindOf(pattern_node)) {
            .object_pattern => hir_mod.patternElements(self.hir, pattern_node),
            .object_literal => hir_mod.objectLiteralProps(self.hir, pattern_node),
            else => &.{},
        };
        for (elems) |elem| {
            if (self.hir.kindOf(elem) == .parameter) {
                const p = hir_mod.parameterOf(self.hir, elem);
                if (p.flags.is_rest or p.name == hir_mod.none_node_id) continue;
                const key_name = (try self.objectBindingElementKeyName(elem, p.name)) orelse continue;
                const target_node = if (p.default_value != hir_mod.none_node_id and self.hir.kindOf(p.default_value) == .assignment)
                    hir_mod.assignmentOf(self.hir, p.default_value).target
                else
                    p.name;
                const member_t = try self.destructuringTargetExpectedType(target_node, untyped_binding_identifiers_as_any);
                try members.append(self.gpa, .{ .name = key_name, .type = member_t, .is_optional = false, .is_readonly = false, .is_method = false });
            } else if (self.hir.kindOf(elem) == .object_property) {
                const op = hir_mod.objectPropertyOf(self.hir, elem);
                if (op.value == hir_mod.none_node_id) continue;
                const key_name = if (op.is_computed)
                    try self.propertyNameFromComputedBindingKeyNode(op.key)
                else
                    self.propertyNameFromKeyNode(op.key);
                const name = key_name orelse continue;
                const target_node = if (self.hir.kindOf(op.value) == .assignment)
                    hir_mod.assignmentOf(self.hir, op.value).target
                else
                    op.value;
                const member_t = try self.destructuringTargetExpectedType(target_node, untyped_binding_identifiers_as_any);
                try members.append(self.gpa, .{ .name = name, .type = member_t, .is_optional = false, .is_readonly = false, .is_method = false });
            }
        }
        if (members.items.len == 0 and !include_empty) return types.Primitive.none;
        return self.interner.internObjectType(members.items) catch return error.OutOfMemory;
    }

    fn destructuringTargetExpectedType(
        self: *Checker,
        target_node: NodeId,
        untyped_binding_identifiers_as_any: bool,
    ) CheckError!TypeId {
        if (target_node == hir_mod.none_node_id) return types.Primitive.any;
        return switch (self.hir.kindOf(target_node)) {
            .identifier, .member_access, .element_access => blk: {
                if (untyped_binding_identifiers_as_any and self.hir.kindOf(target_node) == .identifier) {
                    break :blk types.Primitive.any;
                }
                const t = if (self.hir.kindOf(target_node) == .identifier)
                    self.typeOfIdentifierDeclared(target_node)
                else
                    try self.checkExpression(target_node);
                break :blk if (t == types.Primitive.none or t == types.Primitive.undefined_t) types.Primitive.any else t;
            },
            .object_literal, .object_pattern => try self.objectBindingPatternExpectedType(target_node, true, untyped_binding_identifiers_as_any),
            .array_pattern => try self.arrayBindingPatternParameterType(target_node),
            .array_literal => self.interner.internArrayType(self.string_interner, types.Primitive.any) catch return error.OutOfMemory,
            else => types.Primitive.any,
        };
    }

    fn identifierIsUntypedUninitializedVar(self: *Checker, node: NodeId) bool {
        if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .identifier) return false;
        const id = hir_mod.identifierOf(self.hir, node);
        const use_start = self.hir.spanOf(node).start;
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const stmts: ?[]const NodeId = switch (self.hir.kindOf(cur)) {
                .block_stmt => hir_mod.blockStmts(self.hir, cur),
                .namespace_decl => hir_mod.namespaceBody(self.hir, cur),
                else => null,
            };
            if (stmts) |items| {
                for (items) |stmt| {
                    if (self.hir.spanOf(stmt).start >= use_start) break;
                    const decl = if (self.hir.kindOf(stmt) == .export_decl) hir_mod.exportOf(self.hir, stmt).decl else stmt;
                    if (decl == hir_mod.none_node_id) continue;
                    const dk = self.hir.kindOf(decl);
                    if (dk != .var_decl and dk != .let_decl and dk != .const_decl) continue;
                    const v = hir_mod.varDeclOf(self.hir, decl);
                    if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) continue;
                    if (hir_mod.identifierOf(self.hir, v.name).name != id.name) continue;
                    return v.type_annotation == hir_mod.none_node_id and
                        v.init == hir_mod.none_node_id and
                        !self.varDeclHasJsDocTypeTag(decl);
                }
                continue;
            }
        }
        return false;
    }

    fn recordUntypedUninitializedVarAssignment(self: *Checker, node: NodeId, value_t: TypeId) CheckError!void {
        const decl = self.previousUntypedUninitializedVarDeclInNearestScope(node) orelse return;
        const v = hir_mod.varDeclOf(self.hir, decl);
        self.hir.setType(decl, value_t);
        if (v.name != hir_mod.none_node_id) self.hir.setType(v.name, value_t);
    }

    fn previousUntypedUninitializedVarDeclInNearestScope(self: *Checker, node: NodeId) ?NodeId {
        if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .identifier) return null;
        const id = hir_mod.identifierOf(self.hir, node);
        const use_start = self.hir.spanOf(node).start;
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const stmts: []const NodeId = switch (self.hir.kindOf(cur)) {
                .block_stmt => hir_mod.blockStmts(self.hir, cur),
                .namespace_decl => hir_mod.namespaceBody(self.hir, cur),
                else => continue,
            };
            for (stmts) |stmt| {
                if (self.hir.spanOf(stmt).start >= use_start) break;
                const decl = if (self.hir.kindOf(stmt) == .export_decl) hir_mod.exportOf(self.hir, stmt).decl else stmt;
                if (decl == hir_mod.none_node_id) continue;
                const dk = self.hir.kindOf(decl);
                if (dk != .var_decl and dk != .let_decl and dk != .const_decl) continue;
                const v = hir_mod.varDeclOf(self.hir, decl);
                if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) continue;
                if (hir_mod.identifierOf(self.hir, v.name).name != id.name) continue;
                if (v.type_annotation != hir_mod.none_node_id or
                    v.init != hir_mod.none_node_id or
                    self.varDeclHasJsDocTypeTag(decl))
                {
                    return null;
                }
                return decl;
            }
            return null;
        }
        return null;
    }

    fn destructuringSourceWithDefault(self: *Checker, source_t: TypeId, default_t: TypeId) !TypeId {
        if (source_t == types.Primitive.any or source_t == types.Primitive.unknown) return source_t;
        if (default_t == types.Primitive.any or default_t == types.Primitive.unknown) return default_t;
        const without_undefined = self.subtractType(source_t, types.Primitive.undefined_t) catch source_t;
        if (without_undefined == types.Primitive.never or without_undefined == types.Primitive.none) return default_t;
        if (default_t == types.Primitive.never or default_t == types.Primitive.none) return without_undefined;
        if (without_undefined == default_t) return without_undefined;
        // Widen the literal default before unioning so a string-literal
        // default (`a = ""`) doesn't render alongside `string` in the
        // source's union prose for the destructured target's TS2322
        // diagnostic. Mirrors upstream tsc which widens initializer
        // types when computing the effective destructuring binding
        // type. Without widening, the outer union wraps the
        // already-union prop type (`string | number`) together with
        // the literal `""`; downstream assignability prose renders
        // the 2-member outer union as `(string | number) | ""` which
        // collapses textually to `string | number | ""`. See fixture
        // `restElementWithAssignmentPattern2.ts(2,10)` whose baseline
        // is `string | number`.
        const widened_default = self.widenLiteralType(default_t);
        if (widened_default == without_undefined) return without_undefined;
        // When the source already contains the widened default as a
        // union member, the union is a no-op — return the source
        // unchanged. Without this guard the outer union ends up
        // wrapping `string | number` and `string` as siblings.
        if (self.interner.pool.flagsOf(without_undefined).is_union) {
            for (self.interner.unionMembers(without_undefined)) |member| {
                if (member == widened_default) return without_undefined;
            }
        }
        return self.interner.internUnion(&.{ without_undefined, widened_default }) catch return error.OutOfMemory;
    }

    fn objectPropertyTypeForDestructuring(self: *Checker, source_t: TypeId, key_node: NodeId, is_computed: bool) CheckError!?TypeId {
        if (is_computed) {
            if (try self.objectPropertyTypeForComputedKeyNode(source_t, key_node)) |t| return t;
        }
        const key_name = if (is_computed)
            try self.propertyNameFromComputedBindingKeyNode(key_node)
        else
            self.propertyNameFromKeyNode(key_node);
        const name = key_name orelse return null;
        return self.objectPropertyTypeByName(source_t, name);
    }

    fn objectPropertyTypeForComputedKeyNode(self: *Checker, source_t: TypeId, key_node: NodeId) CheckError!?TypeId {
        if (key_node == hir_mod.none_node_id) return null;
        const key_t = try self.checkExpression(key_node);
        return try self.objectPropertyTypeForComputedKeyType(source_t, key_t);
    }

    fn objectPropertyTypeForComputedKeyType(self: *Checker, source_t: TypeId, key_t: TypeId) CheckError!?TypeId {
        if (try self.propertyNameFromLiteralType(key_t)) |name| {
            return self.objectPropertyTypeByName(source_t, name);
        }
        if (key_t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(key_t);
        if (flags.is_union) {
            var vals: std.ArrayListUnmanaged(TypeId) = .empty;
            defer vals.deinit(self.gpa);
            for (self.interner.unionMembers(key_t)) |member| {
                if (try self.objectPropertyTypeForComputedKeyType(source_t, member)) |t| {
                    try vals.append(self.gpa, t);
                }
            }
            if (vals.items.len == 0) return null;
            if (vals.items.len == 1) return vals.items[0];
            return self.interner.internUnion(vals.items) catch return error.OutOfMemory;
        }
        if (flags.is_number) {
            if (source_t < self.interner.pool.typeCount()) {
                const number_idx = self.interner.objectNumberIndex(source_t);
                if (number_idx != types.Primitive.none) return number_idx;
            }
        }
        if (flags.is_string) {
            if (source_t < self.interner.pool.typeCount()) {
                const string_idx = self.interner.objectStringIndex(source_t);
                if (string_idx != types.Primitive.none) return string_idx;
            }
        }
        return null;
    }

    fn objectPropertyTypeByName(self: *Checker, source_t: TypeId, key_name: hir_mod.StringId) ?TypeId {
        if (source_t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(source_t);
        if (flags.is_union) {
            var vals: std.ArrayListUnmanaged(TypeId) = .empty;
            defer vals.deinit(self.gpa);
            for (self.interner.unionMembers(source_t)) |member| {
                if (self.objectPropertyTypeByName(member, key_name)) |t| {
                    vals.append(self.gpa, t) catch return null;
                }
            }
            if (vals.items.len == 0) return null;
            if (vals.items.len == 1) return vals.items[0];
            return self.interner.internUnion(vals.items) catch null;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(source_t)) |member| {
                if (self.objectPropertyTypeByName(member, key_name)) |t| return t;
            }
            return null;
        }
        if (!flags.is_object_type) return null;
        if (self.interner.objectMember(source_t, key_name)) |t| return t;
        const string_idx = self.interner.objectStringIndex(source_t);
        if (string_idx != types.Primitive.none) return string_idx;
        if (self.isNumericStringId(key_name)) {
            const number_idx = self.interner.objectNumberIndex(source_t);
            if (number_idx != types.Primitive.none) return number_idx;
        }
        return null;
    }

    fn propertyNameFromKeyNode(self: *Checker, key_node: NodeId) ?hir_mod.StringId {
        return switch (self.hir.kindOf(key_node)) {
            .identifier => hir_mod.identifierOf(self.hir, key_node).name,
            .literal_string => hir_mod.literalStringOf(self.hir, key_node).value,
            .literal_number => blk: {
                const span = self.hir.spanOf(key_node);
                const src = self.source orelse break :blk null;
                if (span.end > src.len or span.start >= span.end) break :blk null;
                break :blk self.string_interner.intern(src[span.start..span.end]) catch null;
            },
            else => null,
        };
    }

    fn propertyNameFromComputedKeyNode(self: *Checker, key_node: NodeId) CheckError!?hir_mod.StringId {
        const key_t = try self.checkExpression(key_node);
        if (try self.propertyNameFromLiteralType(key_t)) |name| return name;
        if (try self.propertyNameFromConstReturningIife(key_node)) |name| return name;
        if (self.propertyNameFromComputedKeySourceReturn(key_node)) |name| return name;
        return self.propertyNameFromKeyNode(key_node);
    }

    fn propertyNameFromComputedKeySourceReturn(self: *Checker, key_node: NodeId) ?hir_mod.StringId {
        const src = self.source orelse return null;
        const sp = self.hir.spanOf(key_node);
        if (sp.end > src.len or sp.start >= sp.end) return null;
        const text = src[sp.start..sp.end];
        const ret_idx = std.mem.indexOf(u8, text, "return") orelse return null;
        const tail = text[ret_idx + "return".len ..];
        var i: usize = 0;
        while (i < tail.len and (tail[i] == ' ' or tail[i] == '\t' or tail[i] == '\r' or tail[i] == '\n')) : (i += 1) {}
        if (i >= tail.len) return null;
        const quote = tail[i];
        if (quote != '"' and quote != '\'') return null;
        const start = i + 1;
        var end = start;
        while (end < tail.len and tail[end] != quote) : (end += 1) {}
        if (end >= tail.len or end == start) return null;
        return self.string_interner.intern(tail[start..end]) catch null;
    }

    fn propertyNameFromConstReturningIife(self: *Checker, key_node: NodeId) CheckError!?hir_mod.StringId {
        if (key_node == hir_mod.none_node_id or self.hir.kindOf(key_node) != .call_expr) return null;
        const c = hir_mod.callOf(self.hir, key_node);
        const callee = c.callee;
        const callee_kind = self.hir.kindOf(callee);
        if (callee_kind != .arrow_fn and callee_kind != .fn_expr and callee_kind != .fn_decl) return null;
        const f = hir_mod.fnDeclOf(self.hir, callee);
        const ret_expr = self.firstReturnExpressionNode(f.body) orelse return null;
        return try self.propertyNameFromConstLiteralExpression(ret_expr);
    }

    fn firstReturnExpressionNode(self: *Checker, node: NodeId) ?NodeId {
        if (node == hir_mod.none_node_id) return null;
        return switch (self.hir.kindOf(node)) {
            .return_stmt => blk: {
                const r = hir_mod.returnOf(self.hir, node);
                break :blk if (r.value == hir_mod.none_node_id) null else r.value;
            },
            .block_stmt => blk: {
                for (hir_mod.blockStmts(self.hir, node)) |stmt| {
                    if (self.firstReturnExpressionNode(stmt)) |expr| break :blk expr;
                }
                break :blk null;
            },
            .if_stmt => blk: {
                const i = hir_mod.ifOf(self.hir, node);
                if (self.firstReturnExpressionNode(i.then_branch)) |expr| break :blk expr;
                break :blk self.firstReturnExpressionNode(i.else_branch);
            },
            .try_stmt => blk: {
                const t = hir_mod.tryOf(self.hir, node);
                if (self.firstReturnExpressionNode(t.block)) |expr| break :blk expr;
                if (self.firstReturnExpressionNode(t.catch_block)) |expr| break :blk expr;
                break :blk self.firstReturnExpressionNode(t.finally_block);
            },
            .fn_decl, .fn_expr, .arrow_fn => null,
            else => node,
        };
    }

    fn propertyNameFromConstLiteralExpression(self: *Checker, node: NodeId) CheckError!?hir_mod.StringId {
        if (node == hir_mod.none_node_id) return null;
        return switch (self.hir.kindOf(node)) {
            .as_expr, .satisfies_expr, .type_assertion, .non_null_expr => blk: {
                const a = hir_mod.asExpressionOf(self.hir, node);
                break :blk try self.propertyNameFromConstLiteralExpression(a.expr);
            },
            .literal_string, .literal_number => self.propertyNameFromKeyNode(node),
            .literal_bool => if (hir_mod.literalBoolOf(self.hir, node))
                self.string_interner.intern("true") catch return error.OutOfMemory
            else
                self.string_interner.intern("false") catch return error.OutOfMemory,
            else => null,
        };
    }

    fn propertyNameFromLiteralType(self: *Checker, t: TypeId) CheckError!?hir_mod.StringId {
        if (t == types.Primitive.true_lit) return self.string_interner.intern("true") catch return error.OutOfMemory;
        if (t == types.Primitive.false_lit) return self.string_interner.intern("false") catch return error.OutOfMemory;
        if (t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(t);
        if (!flags.is_literal) return null;
        switch (self.interner.literalOf(t)) {
            .string_lit => |sid| return sid,
            .number_lit => |bits| {
                const v: f64 = @bitCast(bits);
                var buf: [64]u8 = undefined;
                const text = if (v == @floor(v) and v >= -9007199254740991 and v <= 9007199254740991)
                    std.fmt.bufPrint(&buf, "{d}", .{@as(i64, @intFromFloat(v))}) catch return null
                else
                    std.fmt.bufPrint(&buf, "{d}", .{v}) catch return null;
                return self.string_interner.intern(text) catch return error.OutOfMemory;
            },
            else => return null,
        }
    }

    fn fixedTupleLength(self: *Checker, target: TypeId) ?u64 {
        if (target >= self.interner.pool.typeCount()) return null;
        if (!self.interner.pool.flagsOf(target).is_object_type) return null;
        const length_id = self.string_interner.intern("length") catch return null;
        const length_t = self.interner.objectMember(target, length_id) orelse return null;
        const flags = self.interner.pool.flagsOf(length_t);
        if (!flags.is_literal or !flags.is_number) return null;
        return switch (self.interner.literalOf(length_t)) {
            .number_lit => |bits| blk: {
                const v: f64 = @bitCast(bits);
                if (v < 0 or v != @floor(v)) break :blk null;
                break :blk @as(u64, @intFromFloat(v));
            },
            else => null,
        };
    }

    fn tupleElementType(self: *Checker, target: TypeId, index: usize) TypeId {
        if (target >= self.interner.pool.typeCount()) return types.Primitive.none;
        if (!self.interner.pool.flagsOf(target).is_object_type) return types.Primitive.none;
        var nbuf: [12]u8 = undefined;
        const name_str = std.fmt.bufPrint(&nbuf, "{d}", .{index}) catch return types.Primitive.none;
        const name = self.string_interner.intern(name_str) catch return types.Primitive.none;
        if (self.interner.objectMember(target, name)) |t| return t;
        return self.interner.objectNumberIndex(target);
    }

    fn tupleFixedPrefixCount(self: *Checker, target: TypeId) usize {
        if (target >= self.interner.pool.typeCount()) return 0;
        if (!self.interner.pool.flagsOf(target).is_object_type) return 0;
        var count: usize = 0;
        while (true) : (count += 1) {
            var nbuf: [12]u8 = undefined;
            const name_str = std.fmt.bufPrint(&nbuf, "{d}", .{count}) catch return count;
            const name = self.string_interner.intern(name_str) catch return count;
            const member = self.tupleElementMember(target, name) orelse return count;
            if (member.is_optional) return count;
        }
    }

    fn tupleRestMinRequiredCount(self: *Checker, target: TypeId) usize {
        var count = self.tupleFixedPrefixCount(target);
        while (count > 0) {
            const elem_t = self.tupleElementType(target, count - 1);
            if (elem_t == types.Primitive.none or !self.parameterTypeAllowsVoidOmission(elem_t)) break;
            count -= 1;
        }
        return count;
    }

    fn tupleElementMember(self: *Checker, target: TypeId, name: hir_mod.StringId) ?types.ObjectMember {
        if (target >= self.interner.pool.typeCount()) return null;
        if (!self.interner.pool.flagsOf(target).is_object_type) return null;
        for (self.interner.objectMembers(target)) |member| {
            if (member.name == name) return member;
        }
        return null;
    }

    fn tupleTypeLooksReadonly(self: *Checker, target: TypeId) bool {
        if (self.fixedTupleLength(target) == null) return false;
        var nbuf: [12]u8 = undefined;
        const zero_str = std.fmt.bufPrint(&nbuf, "{d}", .{0}) catch return false;
        const zero_name = self.string_interner.intern(zero_str) catch return false;
        if (self.tupleElementMember(target, zero_name)) |member| return member.is_readonly;
        const length_id = self.string_interner.intern("length") catch return false;
        if (self.interner.objectMemberInfo(target, length_id)) |member| return member.is_readonly;
        return false;
    }

    fn reportTupleIndexOutOfBounds(self: *Checker, index_node: NodeId, target: TypeId, index: u64, length: u64) CheckError!void {
        const arena = self.diag_arena.allocator();
        var display_buf: std.ArrayListUnmanaged(u8) = .empty;
        defer display_buf.deinit(arena);
        const has_display = self.renderTupleDisplay(&display_buf, target) catch false;
        const msg = if (has_display)
            try std.fmt.allocPrint(
                arena,
                "Tuple type '{s}' of length '{d}' has no element at index '{d}'.",
                .{ display_buf.items, length, index },
            )
        else
            try std.fmt.allocPrint(
                arena,
                "Tuple type of length '{d}' has no element at index '{d}'.",
                .{ length, index },
            );
        try self.diagnostics.append(self.gpa, .{
            .node = index_node,
            .code = TsCodes.tuple_index_out_of_bounds,
            .message = msg,
        });
    }

    fn renderTupleDisplay(self: *Checker, buf: *std.ArrayListUnmanaged(u8), target: TypeId) !bool {
        if (target >= self.interner.pool.typeCount()) return false;
        if (!self.interner.pool.flagsOf(target).is_object_type) return false;
        const length = self.fixedTupleLength(target) orelse return false;
        const arena = self.diag_arena.allocator();
        try buf.append(arena, '[');
        // Cap render width at 10_000 elements: protects against u64→usize
        // narrowing on 32-bit hosts and bounds diagnostic-string growth on
        // pathological tuple types (tsc itself truncates around the same
        // scale in practice).
        const render_cap: u64 = @min(length, 10_000);
        var i: u64 = 0;
        while (i < render_cap) : (i += 1) {
            if (i > 0) try buf.appendSlice(arena, ", ");
            const elem_t = self.tupleElementType(target, @intCast(i));
            if (try self.allocSimpleTypeName(elem_t)) |name| {
                try buf.appendSlice(arena, name);
            } else {
                try buf.appendSlice(arena, "any");
            }
        }
        try buf.append(arena, ']');
        return true;
    }

    /// Single binding identifier occurrence inside a destructuring
    /// pattern — used by TS2451 duplicate-detection for `let`/`const`.
    const DestructuringBindingOccurrence = struct {
        name: hir_mod.StringId,
        node: NodeId,
        pos: u32,
    };

    /// TS2451 — emit `Cannot redeclare block-scoped variable '{name}'.`
    /// at every position where a binding identifier appears more than
    /// once inside a `let`/`const` declaration's binding pattern.
    ///
    /// Mirrors tsc: for `let { foo1, foo1 } = …`, both `foo1` positions
    /// receive their own TS2451. For `let { foo2, bar2: foo2 } = …`,
    /// each LOCAL binding identifier counts (the key `bar2` is ignored;
    /// only the renamed target `foo2` is a binding). Nested patterns
    /// like `let { a: { x }, b: { x } } = …` also fire on every `x`.
    /// Array patterns receive the same treatment: `let [a, a] = …`.
    fn checkLetConstDestructuringDuplicates(
        self: *Checker,
        name_node: NodeId,
    ) CheckError!void {
        if (name_node == hir_mod.none_node_id) return;
        const k = self.hir.kindOf(name_node);
        if (k != .object_pattern and k != .array_pattern) return;

        var occs: std.ArrayListUnmanaged(DestructuringBindingOccurrence) = .empty;
        defer occs.deinit(self.gpa);
        try self.collectDestructuringBindingOccurrences(name_node, &occs);
        if (occs.items.len < 2) return;

        for (occs.items, 0..) |occ, i| {
            var dup = false;
            for (occs.items, 0..) |other, j| {
                if (i == j) continue;
                if (other.name == occ.name) {
                    dup = true;
                    break;
                }
            }
            if (!dup) continue;
            // Replace any parser-side TS2300 ("Duplicate identifier") at
            // the same position with TS2451. tsc emits ONLY TS2451 for
            // `let`/`const` destructuring duplicates; the parser
            // conservatively emits TS2300 because it doesn't know the
            // enclosing decl kind. Mirrors `destructuringSameNames`.
            var existing_idx: ?usize = null;
            for (self.diagnostics.items, 0..) |d, di| {
                if (d.code != TsCodes.duplicate_identifier) continue;
                const d_pos = d.pos orelse self.hir.spanOf(d.node).start;
                if (d_pos == occ.pos) {
                    existing_idx = di;
                    break;
                }
            }
            const name_str = self.string_interner.get(occ.name);
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Cannot redeclare block-scoped variable '{s}'.",
                .{name_str},
            );
            if (existing_idx) |di| {
                self.diagnostics.items[di] = .{
                    .node = occ.node,
                    .pos = occ.pos,
                    .code = TsCodes.cannot_redeclare_block_scoped,
                    .message = msg,
                };
            } else {
                try self.diagnostics.append(self.gpa, .{
                    .node = occ.node,
                    .pos = occ.pos,
                    .code = TsCodes.cannot_redeclare_block_scoped,
                    .message = msg,
                });
            }
        }
    }

    /// Walk a binding-pattern subtree and record every LOCAL binding
    /// identifier (the binding-target name, not object-key labels) with
    /// its source span. Used by the TS2451 duplicate-binding detector
    /// for `let`/`const` destructuring patterns.
    fn collectDestructuringBindingOccurrences(
        self: *Checker,
        pattern_node: NodeId,
        out: *std.ArrayListUnmanaged(DestructuringBindingOccurrence),
    ) CheckError!void {
        if (pattern_node == hir_mod.none_node_id) return;
        const pk = self.hir.kindOf(pattern_node);
        if (pk != .object_pattern and pk != .array_pattern) return;
        for (hir_mod.patternElements(self.hir, pattern_node)) |elem| {
            if (self.hir.kindOf(elem) != .parameter) continue;
            const pp = hir_mod.parameterOf(self.hir, elem);
            // Skip synthetic computed-key carriers; they are NOT a
            // binding slot — `{ [expr]: name }` materialises the
            // computed-key parameter separately from the binding
            // parameter for `name`.
            if (pp.flags.is_computed_binding_key) continue;
            if (pp.name == hir_mod.none_node_id) continue;
            const nk = self.hir.kindOf(pp.name);
            if (nk == .identifier) {
                const id = hir_mod.identifierOf(self.hir, pp.name);
                try out.append(self.gpa, .{
                    .name = id.name,
                    .node = pp.name,
                    .pos = self.hir.spanOf(pp.name).start,
                });
            } else if (nk == .object_pattern or nk == .array_pattern) {
                try self.collectDestructuringBindingOccurrences(pp.name, out);
            }
        }
    }

    fn checkVarDecl(self: *Checker, node: NodeId) CheckError!void {
        const v = hir_mod.varDeclOf(self.hir, node);

        // TS2451 — duplicate binding names inside a `let`/`const`
        // destructuring pattern. tsc emits one TS2451 per occurrence,
        // INCLUDING the first one, so we mirror that anchor-at-each-
        // position pattern here. Skipped for `var` (no block-scoped
        // semantics) and for ambient declarations.
        const decl_kind = self.hir.kindOf(node);
        if ((decl_kind == .let_decl or decl_kind == .const_decl) and !v.is_ambient) {
            try self.checkLetConstDestructuringDuplicates(v.name);
        }

        // TS2397 — `var globalThis;` (or `let`/`const`) shadows the
        // built-in lexical binding. tsc lists only `globalThis` in
        // its built-in conflict allow-list, anchored at the
        // identifier name. Ambient declarations are exempt because
        // they participate in the global type rather than introducing
        // a local binding.
        if (v.name != hir_mod.none_node_id and
            self.hir.kindOf(v.name) == .identifier)
        {
            const id = hir_mod.identifierOf(self.hir, v.name);
            const name_str = self.string_interner.get(id.name);
            if (!v.is_ambient and std.mem.eql(u8, name_str, "globalThis")) {
                try self.report(
                    v.name,
                    TsCodes.declaration_name_conflicts_builtin_global,
                    "Declaration name conflicts with built-in global identifier 'globalThis'.",
                );
            }
        }

        // Top-level `await using` requires module=es2022+ AND
        // target=es2017+. The parser flags `is_await_using` on the
        // const-decl shape; here we mirror tsc's TS2854 when the
        // declaration sits outside any function-like context and the
        // source's `// @target` directive picks an older target.
        // Only fire when this is the first declarator on the line
        // (anchor matches tsc — column = `await` keyword start) and
        // we're not inside an enclosing function.
        if (v.is_await_using and
            !self.nodeIsInsideFunctionLike(node) and
            self.sourceTargetDisallowsTopLevelAwait())
        {
            try self.report(node, TsCodes.top_level_await_using_target_module, "Top-level 'await using' statements are only allowed when the 'module' option is set to 'es2022', 'esnext', 'system', 'node16', 'node18', 'node20', 'nodenext', or 'preserve', and the 'target' option is set to 'es2017' or higher.");
        }

        // TS2502 — `var x: typeof x` (or via an identical-name
        // qualifier-less typeof inside a tuple / array / union).
        // The full typeof-cycle detection lives in
        // `typeAliasCircularTypeofVarDecl`; the var-side counterpart
        // here catches the direct self-reference, which tsc reports
        // even when no intermediate alias is involved.
        //
        // Skip when a prior `var <name>` already exists in the same
        // scope (same virtual section). Upstream tsc treats subsequent
        // `var x: typeof x` as referring to the *previously declared*
        // `x` so no cycle exists. Mirrors `validMultipleVariableDeclarations`
        // and similar fixtures.
        if (v.type_annotation != hir_mod.none_node_id and
            v.name != hir_mod.none_node_id and
            self.hir.kindOf(v.name) == .identifier)
        {
            const id = hir_mod.identifierOf(self.hir, v.name);
            if (self.varDeclTypeAnnotationContainsTypeofSelf(v.type_annotation, id.name)) {
                if (!self.priorVarDeclWithSameNameExists(node, id.name)) {
                    try self.reportSelfReferencedTypeAnnotationAtName(node);
                }
            }
        }

        // Lower type annotation first (so we can check init against it).
        var declared_type: TypeId = types.Primitive.none;
        if (v.type_annotation != hir_mod.none_node_id) {
            declared_type = if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier)
                try self.lowerValueTypeAnnotation(hir_mod.identifierOf(self.hir, v.name).name, v.type_annotation)
            else
                try self.lowererLowerWithTypeParams(v.type_annotation);
            self.hir.setType(node, declared_type);
        } else if (try self.jsDocTypeForVarDecl(node)) |jsdoc_t| {
            declared_type = jsdoc_t;
            self.hir.setType(node, declared_type);
        }

        // Type the initializer.
        var init_type: TypeId = if (v.is_ambient) types.Primitive.any else types.Primitive.undefined_t;
        if (v.init != hir_mod.none_node_id) {
            if (v.is_ambient) {
                // Upstream tsc allows constant-value initializers
                // (literal numbers, strings, bigints, booleans, and
                // unary `-N` / `+N` numeric literals) on ambient
                // `const` and `export const` declarations — they're
                // treated as inline literal type annotations. Mirrors
                // fixtures `typesVersions.justIndex.ts(1,18)`,
                // `typesVersions.emptyTypes`, `scopedPackagesClassic`.
                const is_const_decl = self.hir.kindOf(node) == .const_decl;
                if (!(is_const_decl and self.ambientInitializerIsConstantValue(v.init))) {
                    try self.report(v.init, TsCodes.ambient_initializer_not_allowed, "Initializers are not allowed in ambient contexts.");
                }
            } else {
                init_type = try self.checkExpression(v.init);
            }
            if (declared_type == types.Primitive.none and
                init_type == types.Primitive.undefined_t and
                self.virtualSectionIsJsLike(node))
            {
                init_type = types.Primitive.any;
            }
            if (declared_type == types.Primitive.none and !v.is_ambient and self.hir.kindOf(node) == .const_decl) {
                init_type = try self.constInitializerType(v.init, init_type);
            }
            if (declared_type != types.Primitive.none) {
                if (try self.contextualGenericCallResult(v.init, init_type, declared_type)) |contextual_t| {
                    init_type = contextual_t;
                }
            }
            // Anonymous class-expression assigned to a `var X = class {…}`
            // (or `let`/`const`) binding: register the static-side type
            // under the binding name so TS2339 prose renders as
            // `typeof X` instead of falling back to "Property 'p' does
            // not exist on type." truncation. Mirrors upstream tsc which
            // synthesizes the class name from the variable binding when
            // the class expression itself is anonymous. The parser emits
            // class expressions as `.class_decl` nodes with no `c.name`,
            // so we accept both kinds and gate on the missing class
            // name. Fixture: `typeFromPropertyAssignment29.ts(80,14)`.
            if (v.init != hir_mod.none_node_id and
                (self.hir.kindOf(v.init) == .class_expr or self.hir.kindOf(v.init) == .class_decl) and
                v.name != hir_mod.none_node_id and
                self.hir.kindOf(v.name) == .identifier)
            {
                const ce = hir_mod.classOf(self.hir, v.init);
                if (ce.name == hir_mod.none_node_id) {
                    const id = hir_mod.identifierOf(self.hir, v.name);
                    if (!self.class_static_types.contains(id.name)) {
                        try self.class_static_types.put(self.gpa, id.name, init_type);
                    }
                    if (!self.class_name_by_static.contains(init_type)) {
                        try self.class_name_by_static.put(self.gpa, init_type, id.name);
                    }
                }
            }
            if (declared_type == types.Primitive.none and
                self.sourceHasCheckJsDirective() and
                self.virtualSectionIsJsLike(node) and
                self.hir.kindOf(v.init) == .object_literal and
                v.name != hir_mod.none_node_id and
                self.hir.kindOf(v.name) == .identifier)
            {
                const id = hir_mod.identifierOf(self.hir, v.name);
                if (self.class_static_types.get(id.name)) |class_t| {
                    const ok = (self.objectLiteralAssignableToTarget(v.init, init_type, class_t) catch false) or
                        (self.engine.isAssignableTo(init_type, class_t) catch true);
                    if (!ok) {
                        try self.report(node, TsCodes.type_missing_properties, "Type is missing the following properties from target type.");
                    }
                }
            }
        }
        if (v.name != hir_mod.none_node_id and
            v.init == hir_mod.none_node_id and
            !v.is_ambient)
        {
            const nk = self.hir.kindOf(v.name);
            if (nk == .object_pattern or nk == .array_pattern) {
                try self.report(v.name, TsCodes.destructuring_decl_must_have_initializer, "A destructuring declaration must have an initializer.");
            }
        }
        var array_binding_iter_diag_fired = false;
        if (v.name != hir_mod.none_node_id and
            self.hir.kindOf(v.name) == .array_pattern and
            v.init != hir_mod.none_node_id and
            ((self.hir.kindOf(v.init) == .object_literal and !self.objectLiteralHasSymbolIteratorMethod(v.init)) or
                !self.isDestructuringIterableSourceType(init_type)) and
            !self.objectLiteralHasSymbolIteratorMethod(v.init) and
            declared_type != types.Primitive.any)
        {
            // Anchor at the array binding pattern (`[...a]`, `[a, b]`)
            // rather than the initializer expression — upstream tsc
            // underlines the pattern in TS2488 prose for var-decl
            // forms. Mirrors fixture `iterableArrayPattern22.ts(1,5)`.
            try self.reportIteratorRequired(v.name, init_type);
            array_binding_iter_diag_fired = true;
        }
        if (self.strict_flags.strict_null_checks and v.name != hir_mod.none_node_id and v.init != hir_mod.none_node_id) {
            const nk = self.hir.kindOf(v.name);
            if (nk == .array_pattern and declared_type != types.Primitive.any and !array_binding_iter_diag_fired and (self.typeIncludesNull(init_type) or self.typeIncludesUndefined(init_type)) and !self.typeIsAnyLike(init_type)) {
                try self.reportIteratorRequired(v.init, init_type);
            } else if (nk == .object_pattern and (init_type == types.Primitive.void_t or self.typeIncludesUndefined(init_type)) and !self.typeIsAnyLike(init_type)) {
                // `any` (and `<any>` cast targets) intentionally
                // bypass strict-null narrowing checks — destructuring
                // from `any` does not carry an "object possibly
                // undefined" risk in tsc, so suppress TS2532 here.
                // tsc anchors TS2532 at the destructuring pattern
                // (the `{ x }` in `var { x } = void 0;`), not at the
                // init expression — switch the report node so the
                // rendered (line, col) matches upstream.
                try self.report(v.name, TsCodes.object_possibly_undefined, "Object is possibly 'undefined'.");
            }
        }
        var binding_pattern_source_diag_fired = false;
        if (declared_type != types.Primitive.none and
            v.name != hir_mod.none_node_id and
            self.hir.kindOf(v.name) == .object_pattern)
        {
            binding_pattern_source_diag_fired = try self.checkBindingPatternSourceType(v.name, declared_type, hir_mod.none_node_id);
        }

        // If both are present, check assignability.
        const final_type: TypeId = if (declared_type != types.Primitive.none) declared_type else init_type;
        if (declared_type != types.Primitive.none and v.init != hir_mod.none_node_id) {
            const assignability_diag_count = self.diagnostics.items.len;
            // Special-case array-literal → tuple positional check.
            // The init's structural Array<T>-shape loses positional
            // info, so plain assignability would reject `[1, "a"]`
            // against `[number, string]`. Instead, when init is a
            // literal `[…]` and the target is a tuple-shaped object
            // type (positional "0", "1", … members), check each
            // element against the matching positional slot, then
            // fall back to the target's number-key indexer for any
            // extras (variadic tuple rest).
            const ok = blk: {
                if (v.type_annotation != hir_mod.none_node_id and self.hir.kindOf(v.init) == .array_literal) {
                    if (self.tupleAnnotationSourceNode(v.type_annotation)) |tuple_node| {
                        if (self.tupleTypeHasRestElement(tuple_node)) {
                            break :blk try self.checkArrayLiteralAgainstTupleAnnotation(v.init, tuple_node);
                        }
                    }
                    if (self.isTupleShapedTarget(declared_type)) {
                        break :blk try self.arrayLiteralAssignableToTupleTarget(v.init, declared_type, true);
                    }
                }
                if (self.hir.kindOf(v.init) == .object_literal and
                    declared_type < self.interner.pool.typeCount() and
                    self.interner.pool.flagsOf(declared_type).is_union and
                    (self.objectLiteralAssignableToTarget(v.init, init_type, declared_type) catch false))
                {
                    break :blk true;
                }
                if (self.hir.kindOf(v.init) == .object_literal and
                    self.objectTargetHasLiteralMember(declared_type) and
                    (self.objectLiteralAssignableToTarget(v.init, init_type, declared_type) catch false))
                {
                    break :blk true;
                }
                if ((self.hir.kindOf(v.init) == .arrow_fn or self.hir.kindOf(v.init) == .fn_expr) and
                    try self.functionExpressionAssignableToTarget(v.init, declared_type))
                {
                    break :blk true;
                }
                if (self.enumNameFromNominal(init_type)) |enum_name| {
                    if (!self.enumValueAssignableToTarget(enum_name, declared_type)) break :blk false;
                }
                if (try self.logicalExpressionAssignableToTarget(v.init, declared_type)) break :blk true;
                if (try self.awaitedExpressionAssignableToTarget(v.init, init_type, declared_type)) break :blk true;
                if (try self.literalExpressionAssignableToTarget(v.init, declared_type)) break :blk true;
                if (try self.templateExpressionAssignableToType(v.init, declared_type)) break :blk true;
                if (self.dynamicImportDefinitelyMismatchesTypeofNamespace(v.init, v.type_annotation)) break :blk false;
                break :blk self.engine.isAssignableTo(init_type, declared_type) catch return error.OutOfMemory;
            };
            try self.checkArrayLiteralContextualElements(v.init, declared_type);
            if (!ok) {
                if (binding_pattern_source_diag_fired) {
                    // The declared destructuring source itself is invalid
                    // (for example `{ }: undefined`), so tsc reports the
                    // pattern diagnostic and skips the outer assignment prose.
                } else if (self.diagnostics.items.len > assignability_diag_count) {
                    // A more precise element-level tuple diagnostic was emitted.
                } else if (!self.callExpressionHasAnyArgument(v.init)) {
                    const diag_node = if (v.name != hir_mod.none_node_id) v.name else node;
                    // Prefer the more-specific TS2741 wording when an
                    // empty `{}` is being assigned to a target with
                    // exactly one missing required property — matches
                    // upstream baselines (`renamed.ts`, etc.).
                    if (self.hir.kindOf(v.init) == .array_literal or
                        !(try self.tryReportSinglePropertyMissing(diag_node, v.init, init_type, declared_type)))
                    {
                        // Drill into the object literal first — when
                        // the gap is a single property whose value is
                        // not assignable, anchor the diagnostic at the
                        // value position with full type prose. Mirrors
                        // upstream `nonPrimitiveAsProperty.ts(7,28)`.
                        if (!try self.tryReportObjectLiteralPropertyMismatch(v.init, declared_type)) {
                            if (!try self.tryReportArrayLiteralTupleAssignmentMismatch(diag_node, v.init, declared_type, "Type is not assignable to declared type.")) {
                                try self.reportTypeNotAssignable(diag_node, init_type, declared_type, "Type is not assignable to declared type.");
                            }
                        }
                    }
                }
            } else {
                try self.checkRemappedMappedIndexedDecl(node, declared_type, v.init);
                try self.checkGenericValueMappedTargetDecl(node, v.type_annotation, init_type, v.init);
            }
            // TS2353: fresh-object-literal excess-property check.
            // Only fires when the init is a literal `{ … }` and the
            // declared type is a known object — otherwise extra
            // properties may legitimately come from elsewhere.
            try self.checkExcessProperties(v.init, declared_type);
            // TS2375: `exactOptionalPropertyTypes` rejects literal
            // `undefined` flowing into an optional-but-not-undefined
            // property.
            try self.checkExactOptionalProperties(v.init, declared_type);
        } else if (declared_type == types.Primitive.none) {
            self.hir.setType(node, init_type);
        }
        // Propagate the declaration's type to the name identifier
        // so hover-on-identifier returns the right type.
        if (v.name != hir_mod.none_node_id) self.hir.setType(v.name, final_type);
        if (v.name != hir_mod.none_node_id and
            v.init != hir_mod.none_node_id and
            self.hir.kindOf(v.name) == .identifier)
        {
            const id = hir_mod.identifierOf(self.hir, v.name);
            const flow_t = try self.flowTypeForAssignmentValue(v.init, init_type);
            const flow_ok = (try self.literalExpressionAssignableToTarget(v.init, final_type)) or
                (self.engine.isAssignableTo(flow_t, final_type) catch true);
            if (flow_t != types.Primitive.none and
                flow_t != types.Primitive.any and
                flow_t != types.Primitive.unknown and
                final_type != types.Primitive.any and
                final_type != types.Primitive.unknown and
                (try self.shouldRecordDeclaredVariableFlowNarrow(declared_type, flow_t, final_type)) and
                flow_ok)
            {
                try self.recordNarrow(id.name, flow_t);
            }
        }
        if (v.name != hir_mod.none_node_id) {
            const nk = self.hir.kindOf(v.name);
            if (nk == .object_pattern or nk == .array_pattern) {
                try self.checkPatternComputedBindingKeys(v.name);
                try self.checkBindingPatternDefaultReferences(v.name, .variable);
            }
            if (nk == .object_pattern and v.init != hir_mod.none_node_id) {
                try self.checkObjectBindingPatternAgainstType(v.name, final_type, declared_type != types.Primitive.none);
                if (self.hir.kindOf(v.init) == .object_literal) {
                    const expected_t = try self.objectBindingPatternExpectedType(v.name, false, true);
                    if (expected_t != types.Primitive.none) try self.checkExcessProperties(v.init, expected_t);
                }
            } else if (nk == .array_pattern and v.init != hir_mod.none_node_id) {
                try self.checkArrayBindingPatternAgainstType(v.name, final_type);
                try self.checkArrayBindingPatternAgainstArrayLiteral(v.name, v.init);
                try self.reportImplicitAnyNullishArrayBinding(v.name, v.init);
            }
            if ((nk == .object_pattern or nk == .array_pattern) and v.init != hir_mod.none_node_id) {
                try self.recordBindingPatternFlowFromSource(v.name, v.init, final_type);
            }
        }
        try self.checkRepeatedVarDeclaration(node, final_type);

        // Aliased conditional narrowing: `let cond = obj.kind === "x"`.
        // Record `cond -> guard_expr_node` so a subsequent `if (cond)`
        // applies the original guard. Only fires for `const`/`let`-style
        // bindings whose init is a recognizably-narrowing expression.
        if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier and
            v.init != hir_mod.none_node_id and isNarrowingGuard(self.hir, v.init))
        {
            const id = hir_mod.identifierOf(self.hir, v.name);
            try self.cond_aliases.put(self.gpa, id.name, v.init);
        }

        // TS7034 vs TS7005: tsc emits the more-specific TS7034 at the
        // DECLARATION of a `var p;` with no annotation and no
        // initializer when the variable's type can't be determined
        // (the "evolving any" flow). For `declare var X;` (ambient
        // declarations) tsc emits TS7005 instead because evolving-any
        // doesn't apply to ambient names — they're externally
        // declared and unchangeable. We mirror that split here.
        if (self.strict_flags.no_implicit_any and
            declared_type == types.Primitive.none and
            v.type_annotation == hir_mod.none_node_id and
            v.init == hir_mod.none_node_id and
            !self.varDeclHasMalformedListSyntax(node, v.name) and
            !self.varDeclIsInsideFunctionLike(node) and
            !self.varDeclIsReservedAwaitInStaticBlock(node, v.name))
        {
            const var_name: []const u8 = if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier)
                self.string_interner.get(hir_mod.identifierOf(self.hir, v.name).name)
            else
                "<anonymous>";
            const is_ambient = v.is_ambient;
            // `const X;` (no init) is a TS1155 syntax error, but tsc
            // still emits the implicit-any diagnostic — and it uses
            // TS7005 (not TS7034) because const has no evolving-any
            // flow (the binding can never be reassigned to widen its
            // type). Mirrors fixture `for-of2` where `const v;` expects
            // TS7005 alongside TS1155.
            const is_const = self.hir.kindOf(node) == .const_decl;
            const use_ts7005 = is_ambient or is_const;
            const msg = if (use_ts7005)
                try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Variable '{s}' implicitly has an 'any' type.",
                    .{var_name},
                )
            else
                try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Variable '{s}' implicitly has type 'any' in some locations where its type cannot be determined.",
                    .{var_name},
                );
            try self.diagnostics.append(self.gpa, .{
                .node = if (v.name != hir_mod.none_node_id and self.hir.kindOf(v.name) == .identifier) v.name else node,
                .code = if (use_ts7005) TsCodes.variable_implicitly_any else TsCodes.variable_implicitly_any_declaration,
                .message = msg,
            });
        }
    }

    /// `let await;` inside a `class C { static { ... } }` block fires
    /// TS1359 (reserved-word binding) and tsc suppresses the matching
    /// TS7034 implicit-any since the binding is effectively invalid.
    fn varDeclIsReservedAwaitInStaticBlock(self: *Checker, node: NodeId, name_node: NodeId) bool {
        if (!self.nodeIsInClassStaticBlockBeforeFunction(node)) return false;
        const await_id = self.string_interner.intern("await") catch return false;
        return self.findAwaitBindingIdentifier(name_node, await_id) != null;
    }

    fn varDeclHasMalformedListSyntax(self: *Checker, node: NodeId, name_node: NodeId) bool {
        if (name_node != hir_mod.none_node_id and self.hir.kindOf(name_node) == .identifier) {
            const name = self.string_interner.get(hir_mod.identifierOf(self.hir, name_node).name);
            if (name.len == 0) return true;
        }
        const src = self.source orelse return false;
        const span = self.hir.spanOf(node);
        if (span.start >= span.end or span.end > src.len) return false;
        var i: usize = span.end;
        while (i > span.start) {
            i -= 1;
            const c = src[i];
            if (c == ';' or c == ' ' or c == '\t' or c == '\r' or c == '\n') continue;
            return c == ',';
        }
        return false;
    }

    /// TS2431 — names of built-in primitive types that may not be
    /// reused as enum-declaration names. tsc rejects these outright.
    fn isReservedPrimitiveTypeName(name: []const u8) bool {
        return std.mem.eql(u8, name, "any") or
            std.mem.eql(u8, name, "number") or
            std.mem.eql(u8, name, "string") or
            std.mem.eql(u8, name, "boolean") or
            std.mem.eql(u8, name, "symbol") or
            std.mem.eql(u8, name, "bigint");
    }

    fn varDeclIsInsideFunctionLike(self: *Checker, node: NodeId) bool {
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            switch (self.hir.kindOf(cur)) {
                .fn_decl, .fn_expr, .arrow_fn => return true,
                .source_file => return false,
                else => {},
            }
        }
        return false;
    }

    fn shouldRecordDeclaredVariableFlowNarrow(
        self: *Checker,
        declared_type: TypeId,
        flow_t: TypeId,
        final_type: TypeId,
    ) CheckError!bool {
        if (declared_type == types.Primitive.none) return true;
        if (flow_t == final_type or (self.engine.isIdenticalTo(flow_t, final_type) catch false)) return true;
        if (flow_t >= self.interner.pool.typeCount()) return false;
        if (!self.interner.pool.flagsOf(flow_t).is_literal) return false;
        return self.engine.isAssignableTo(flow_t, final_type) catch false;
    }

    fn virtualSectionIsJsLike(self: *Checker, node: NodeId) bool {
        const filename = self.virtualSectionFilenameForNode(node) orelse {
            if (self.sourceHasVirtualFilenameSections()) return false;
            return self.pathIsJsLike(self.importer_path);
        };
        return self.pathIsJsLike(filename);
    }

    fn pathIsJsLike(self: *Checker, path: []const u8) bool {
        _ = self;
        return std.mem.endsWith(u8, path, ".js") or
            std.mem.endsWith(u8, path, ".jsx") or
            std.mem.endsWith(u8, path, ".mjs") or
            std.mem.endsWith(u8, path, ".cjs");
    }

    fn pathIsAlwaysEsmJsLike(self: *Checker, path: []const u8) bool {
        _ = self;
        return std.mem.endsWith(u8, path, ".mjs");
    }

    fn jsLikeSectionHasImplicitCommonJsGlobals(self: *Checker, node: NodeId) bool {
        if (!self.virtualSectionIsJsLike(node)) return false;
        const filename = self.virtualSectionFilenameForNode(node) orelse self.importer_path;
        if (self.pathIsAlwaysEsmJsLike(filename)) return false;
        return !self.jsLikeSectionIsExternalModule(node);
    }

    fn jsLikeSectionIsExternalModule(self: *Checker, node: NodeId) bool {
        if (!self.sourceHasVirtualFilenameSections()) return self.rootHasTopLevelExternalModuleMarker(node);

        const src = self.source orelse return false;
        const section_start = self.virtualSectionStartForNode(node);
        const section_end = self.virtualSectionEndForNode(node);
        if (section_start < section_end and section_end <= src.len) {
            if (std.mem.indexOf(u8, src[section_start..section_end], "import.meta") != null) return true;
        }

        const root = self.rootBlockFor(node);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return false;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            const sp = self.hir.spanOf(stmt);
            if (sp.start < section_start or sp.start >= section_end) continue;
            switch (self.hir.kindOf(stmt)) {
                .import_decl, .export_decl => return true,
                else => {},
            }
        }
        return false;
    }

    fn sourceHasSingleJsLikeVirtualCodeSection(self: *Checker) bool {
        const src = self.source orelse return false;
        var saw_code = false;
        var saw_js = false;
        var lines = std.mem.splitScalar(u8, src, '\n');
        while (lines.next()) |raw_line| {
            const line = std.mem.trim(u8, raw_line, " \t\r");
            const marker = std.mem.indexOf(u8, line, "@filename:") orelse
                (std.mem.indexOf(u8, line, "@Filename:") orelse continue);
            const filename = std.mem.trim(u8, line[marker + "@filename:".len ..], " \t\r");
            const is_js = self.pathIsJsLike(filename);
            const is_code = is_js or
                std.mem.endsWith(u8, filename, ".ts") or
                std.mem.endsWith(u8, filename, ".tsx") or
                std.mem.endsWith(u8, filename, ".mts") or
                std.mem.endsWith(u8, filename, ".cts");
            if (!is_code) continue;
            if (saw_code) return false;
            saw_code = true;
            saw_js = is_js;
        }
        return saw_code and saw_js;
    }

    /// True when `name_node`'s source span begins with a string-literal
    /// quote (`"` or `'`). Distinguishes `module "fs" { ... }` (string
    /// name — module augmentation, not subject to TS8006) from
    /// `namespace A { ... }` (identifier name — TS8006 applies in JS).
    fn namespaceNameIsStringLiteral(self: *Checker, name_node: NodeId) bool {
        if (name_node == hir_mod.none_node_id) return false;
        const src = self.source orelse return false;
        const span = self.hir.spanOf(name_node);
        if (span.start >= src.len) return false;
        const c = src[span.start];
        return c == '"' or c == '\'';
    }

    /// TS8006 — `interface` / `enum` / `namespace` / `type` declarations
    /// inside a `.js` virtual section. Mirrors upstream tsc which gates
    /// these declarations behind the TypeScript syntax. Anchored at the
    /// position of the declaration's name identifier so the column
    /// matches `index.js(4,18)` for `export interface A {}`.
    fn checkTsOnlyDeclInJs(self: *Checker, node: NodeId, kind: []const u8, name_node: NodeId) CheckError!void {
        if (!self.virtualSectionIsJsLike(node)) return;
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "'{s}' declarations can only be used in TypeScript files.",
            .{kind},
        );
        const anchor = if (name_node != hir_mod.none_node_id) name_node else node;
        try self.diagnostics.append(self.gpa, .{
            .node = anchor,
            .code = TsCodes.ts_only_decl_in_js,
            .message = msg,
        });
    }

    /// TS8004 for type parameter declarations that appear in JS-like
    /// virtual sections. Unlike checked-JS type annotation diagnostics,
    /// this is emitted even without `@checkJs` because the syntax itself
    /// is TS-only. The type-parameter HIR span starts at the name token
    /// for ordinary `<T>`, matching upstream's `function F<T>() { }`
    /// column at the `T`.
    fn checkJsOnlyTypeParameters(self: *Checker, owner: NodeId, type_params: []const NodeId) CheckError!void {
        if (!self.virtualSectionIsJsLike(owner)) return;
        for (type_params) |tp| {
            if (self.hir.kindOf(tp) != .type_parameter) continue;
            const span = self.hir.spanOf(tp);
            try self.diagnostics.append(self.gpa, .{
                .node = tp,
                .pos = span.start,
                .code = TsCodes.ts_only_type_parameter_in_js,
                .message = try self.diag_arena.allocator().dupe(u8, "Type parameter declarations can only be used in TypeScript files."),
            });
        }
    }

    /// parserArrowFunctionExpression10/13/14/15/16/17: emit TS8010 for
    /// every parameter type annotation, every return-type annotation,
    /// and TS8009 for every `?` optional marker that appears on a
    /// function/arrow declared inside a `.js`/`.jsx`/`.mjs`/`.cjs`
    /// virtual section opted into checking via `// @allowjs: true` +
    /// `// @checkjs: true`. The TS8010 anchor lands on the type
    /// annotation's source-start (e.g. the `n` of `number`), the
    /// TS8009 anchor lands on the `?` token between the parameter
    /// name and its `:` annotation (or trailing `,`/`)`).
    fn checkJsOnlySignatureAnnotations(self: *Checker, node: NodeId) CheckError!void {
        if (!self.virtualSectionIsJsLike(node)) return;
        try self.checkJsOnlyTypeParameters(node, hir_mod.fnTypeParams(self.hir, node));
        if (!self.check_js_enabled and !self.sourceHasCheckJsDirective()) return;
        const src = self.source orelse return;
        const f = hir_mod.fnDeclOf(self.hir, node);
        const params = hir_mod.fnParams(self.hir, node);
        for (params) |p| {
            if (self.hir.kindOf(p) != .parameter) continue;
            const pp = hir_mod.parameterOf(self.hir, p);
            if (pp.flags.is_optional and !pp.flags.is_rest) {
                if (pp.name != hir_mod.none_node_id) {
                    const name_span = self.hir.spanOf(pp.name);
                    var i: usize = name_span.end;
                    while (i < src.len and (src[i] == ' ' or src[i] == '\t')) : (i += 1) {}
                    if (i < src.len and src[i] == '?') {
                        try self.diagnostics.append(self.gpa, .{
                            .node = p,
                            .pos = @intCast(i),
                            .code = TsCodes.ts_only_optional_modifier_in_js,
                            .message = try self.diag_arena.allocator().dupe(u8, "The '?' modifier can only be used in TypeScript files."),
                        });
                    }
                }
            }
            if (pp.type_annotation != hir_mod.none_node_id) {
                const t_span = self.hir.spanOf(pp.type_annotation);
                try self.diagnostics.append(self.gpa, .{
                    .node = pp.type_annotation,
                    .pos = t_span.start,
                    .code = TsCodes.ts_only_type_annotation_in_js,
                    .message = try self.diag_arena.allocator().dupe(u8, "Type annotations can only be used in TypeScript files."),
                });
            }
        }
        if (f.return_type != hir_mod.none_node_id) {
            const r_span = self.hir.spanOf(f.return_type);
            try self.diagnostics.append(self.gpa, .{
                .node = f.return_type,
                .pos = r_span.start,
                .code = TsCodes.ts_only_type_annotation_in_js,
                .message = try self.diag_arena.allocator().dupe(u8, "Type annotations can only be used in TypeScript files."),
            });
        }
    }

    /// True when the function declaration/expression at `fn_node` has
    /// a leading `/** @param ... <name> */` JSDoc tag for the given
    /// parameter name. Used to suppress TS7006 (implicit-any param) on
    /// `.js` sources where JSDoc supplies the type — mirrors upstream
    /// tsc which lowers `@param` into the parameter's type slot.
    fn fnHasLeadingJsDocParam(self: *Checker, fn_node: NodeId, param_name: []const u8) bool {
        if (param_name.len == 0) return false;
        const src = self.source orelse return false;
        const body = self.leadingJsDocBodyForFunctionOrOwner(src, fn_node) orelse return false;
        const tags = ts_parser.jsdoc.parse(self.gpa, body) catch return false;
        defer self.gpa.free(tags);
        for (tags) |tag| {
            if (tag.kind != .param_tag) continue;
            // `@param {T} name [desc]` — match by name.
            if (std.mem.eql(u8, tag.name, param_name)) return true;
        }
        return false;
    }

    fn functionOrOwnerHasLeadingJsDocParamOrTypeTag(self: *Checker, fn_node: NodeId) bool {
        const src = self.source orelse return false;
        const body = self.leadingJsDocBodyForFunctionOrOwner(src, fn_node) orelse return false;
        if (std.mem.indexOf(u8, body, "@param") != null or
            std.mem.indexOf(u8, body, "@type") != null)
        {
            return true;
        }
        const tags = ts_parser.jsdoc.parse(self.gpa, body) catch return false;
        defer self.gpa.free(tags);
        for (tags) |tag| {
            if (tag.kind == .param_tag or tag.kind == .type_tag) return true;
        }
        return false;
    }

    fn fnHasJsDocTemplateTags(self: *Checker, fn_node: NodeId) bool {
        const src = self.source orelse return false;
        const body = self.leadingJsDocBodyForFunctionOrOwner(src, fn_node) orelse return false;
        if (std.mem.indexOf(u8, body, "@template") == null) return false;
        const tags = ts_parser.jsdoc.parse(self.gpa, body) catch return false;
        defer self.gpa.free(tags);
        for (tags) |tag| {
            if (tag.kind == .template_tag and tag.name.len > 0) return true;
        }
        return false;
    }

    fn recordJsDocTemplateTypeParams(
        self: *Checker,
        fn_node: NodeId,
        captured_tp_ids: *std.ArrayListUnmanaged(TypeId),
    ) CheckError!void {
        const src = self.source orelse return;
        const body = self.leadingJsDocBodyForFunctionOrOwner(src, fn_node) orelse return;
        if (std.mem.indexOf(u8, body, "@template") == null) return;
        const tags = ts_parser.jsdoc.parse(self.gpa, body) catch return;
        defer self.gpa.free(tags);
        for (tags) |tag| {
            if (tag.kind != .template_tag or tag.name.len == 0) continue;
            const name = self.string_interner.intern(tag.name) catch return error.OutOfMemory;
            if (self.lookupNarrow(name)) |existing| {
                try captured_tp_ids.append(self.gpa, existing);
                continue;
            }
            const tp_id = self.interner.internFreshTypeParameterWithFlags(
                name,
                types.Primitive.unknown,
                types.Primitive.none,
                .invariant,
                false,
            ) catch return error.OutOfMemory;
            try self.recordNarrow(name, tp_id);
            try captured_tp_ids.append(self.gpa, tp_id);
        }
    }

    /// True when the var/let/const decl `node` has a leading
    /// `/** @type {T} */` JSDoc tag. Used to extend
    /// `parameterHasContextualType` so an arrow/fn initializer of a
    /// JSDoc-typed variable suppresses TS7006 on its parameters.
    fn varDeclHasJsDocTypeTag(self: *Checker, node: NodeId) bool {
        return self.varDeclLeadingJsDocTypeText(node) != null;
    }

    fn varDeclLeadingJsDocTypeText(self: *Checker, node: NodeId) ?[]const u8 {
        const src = self.source orelse return null;
        const span = self.hir.spanOf(node);
        const body = self.leadingJsDocBody(src, span.start) orelse return null;
        const tags = ts_parser.jsdoc.parse(self.gpa, body) catch return null;
        defer self.gpa.free(tags);
        for (tags) |tag| {
            if (tag.kind == .type_tag and tag.type_text.len > 0) return tag.type_text;
        }
        return null;
    }

    const JsDocParamInfo = struct {
        typ: ?TypeId,
        optional: bool,
    };

    fn jsDocParamInfoForFunctionParam(self: *Checker, fn_node: NodeId, param_name: []const u8) CheckError!?JsDocParamInfo {
        if (param_name.len == 0) return null;
        const src = self.source orelse return null;
        const body = self.leadingJsDocBodyForFunctionOrOwner(src, fn_node) orelse return null;
        if (std.mem.indexOf(u8, body, "@overload") != null) return null;
        const tags = ts_parser.jsdoc.parse(self.gpa, body) catch return null;
        defer self.gpa.free(tags);
        var found: ?JsDocParamInfo = null;
        for (tags) |tag| {
            if (tag.kind != .param_tag) continue;
            if (!std.mem.eql(u8, tag.name, param_name)) continue;
            var t: ?TypeId = null;
            if (tag.type_text.len > 0) {
                if (try self.jsDocTypeTextToTypeAt(src, tag.type_text, fn_node)) |param_t| {
                    t = if (tag.optional) try self.unionWithUndefined(param_t) else param_t;
                }
            }
            found = .{
                .typ = t,
                .optional = tag.optional,
            };
        }
        return found;
    }

    fn jsDocParamInfoForFunctionParamIndex(self: *Checker, fn_node: NodeId, param_index: u16) CheckError!?JsDocParamInfo {
        const src = self.source orelse return null;
        const body = self.leadingJsDocBodyForFunctionOrOwner(src, fn_node) orelse return null;
        if (std.mem.indexOf(u8, body, "@overload") != null) return null;
        const tags = ts_parser.jsdoc.parse(self.gpa, body) catch return null;
        defer self.gpa.free(tags);
        var current: u16 = 0;
        for (tags) |tag| {
            if (tag.kind != .param_tag) continue;
            if (current == param_index) {
                var t: ?TypeId = null;
                if (tag.type_text.len > 0) {
                    if (try self.jsDocTypeTextToTypeAt(src, tag.type_text, fn_node)) |param_t| {
                        t = if (tag.optional) try self.unionWithUndefined(param_t) else param_t;
                    }
                }
                return .{
                    .typ = t,
                    .optional = tag.optional,
                };
            }
            current += 1;
        }
        return null;
    }

    fn jsDocParamTypeForFunctionParam(self: *Checker, fn_node: NodeId, param_name: []const u8) CheckError!?TypeId {
        const info = (try self.jsDocParamInfoForFunctionParam(fn_node, param_name)) orelse return null;
        return info.typ;
    }

    fn applyArgumentsJsDocParamTags(
        self: *Checker,
        fn_node: NodeId,
        param_types: *std.ArrayListUnmanaged(TypeId),
        param_omittable: *std.ArrayListUnmanaged(bool),
        has_rest_param: *bool,
    ) CheckError!void {
        const src = self.source orelse return;
        const span = self.hir.spanOf(fn_node);
        const jsdoc = self.leadingJsDocBodyWithStart(src, span.start) orelse return;
        const tags = ts_parser.jsdoc.parse(self.gpa, jsdoc.body) catch return;
        defer self.gpa.free(tags);
        const uses_arguments = try self.functionBodyReferencesArguments(fn_node);
        for (tags) |tag| {
            if (tag.kind != .param_tag) continue;
            const type_text = std.mem.trim(u8, tag.type_text, " \t\r\n");
            if (std.mem.startsWith(u8, type_text, "...")) {
                const elem_text = std.mem.trim(u8, type_text[3..], " \t\r\n");
                const elem_t = (try self.jsDocTypeTextToTypeAt(src, elem_text, fn_node)) orelse types.Primitive.any;
                const array_t = self.interner.internArrayType(self.string_interner, elem_t) catch return error.OutOfMemory;
                try param_types.append(self.gpa, array_t);
                try param_omittable.append(self.gpa, true);
                has_rest_param.* = true;
                return;
            }
            if (!uses_arguments) continue;
            if (tag.name.len == 0) continue;
            const pos = if (std.mem.indexOf(u8, jsdoc.body, tag.name)) |rel|
                @as(u32, @intCast(jsdoc.start + rel))
            else
                span.start;
            const msg = try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "JSDoc '@param' tag has name '{s}', but there is no parameter with that name. It would match 'arguments' if it had an array type.",
                .{tag.name},
            );
            try self.diagnostics.append(self.gpa, .{
                .node = fn_node,
                .pos = pos,
                .code = TsCodes.jsdoc_param_name_matches_arguments_if_array,
                .message = msg,
            });
        }
    }

    fn functionBodyReferencesArguments(self: *Checker, fn_node: NodeId) CheckError!bool {
        const f = hir_mod.fnDeclOf(self.hir, fn_node);
        if (f.body == hir_mod.none_node_id) return false;
        var refs: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer refs.deinit(self.gpa);
        try self.collectIdentifierRefs(f.body, &refs);
        var it = refs.keyIterator();
        while (it.next()) |name| if (std.mem.eql(u8, self.string_interner.get(name.*), "arguments")) return true;
        return false;
    }

    fn checkJsDocFunctionTypeReturnAnnotations(self: *Checker, fn_node: NodeId) CheckError!void {
        if (!self.sourceHasCheckJsDirective()) return;
        const src = self.source orelse return;
        const span = self.hir.spanOf(fn_node);
        const jsdoc = self.leadingJsDocBodyWithStart(src, span.start) orelse return;
        const tags = ts_parser.jsdoc.parse(self.gpa, jsdoc.body) catch return;
        defer self.gpa.free(tags);
        for (tags) |tag| {
            if (tag.type_text.len == 0) continue;
            const fn_text = jsDocFunctionTypeMissingReturn(tag.type_text) orelse continue;
            const rel = std.mem.indexOf(u8, jsdoc.body, fn_text) orelse
                std.mem.indexOf(u8, jsdoc.body, tag.type_text) orelse
                continue;
            try self.diagnostics.append(self.gpa, .{
                .node = fn_node,
                .pos = @intCast(jsdoc.start + rel),
                .code = TsCodes.function_type_return_implicitly_any,
                .message = try self.diag_arena.allocator().dupe(u8, "Function type, which lacks return-type annotation, implicitly has an 'any' return type."),
            });
        }
    }

    fn expressionNodeAssignableToTarget(self: *Checker, value_node: NodeId, value_t: TypeId, target_t: TypeId) CheckError!bool {
        if (try self.literalExpressionAssignableToTarget(value_node, target_t)) return true;
        if (try self.templateExpressionAssignableToType(value_node, target_t)) return true;
        if (try self.conditionalExpressionAssignableToTarget(value_node, target_t)) return true;
        if (self.hir.kindOf(value_node) == .object_literal and
            (self.objectLiteralAssignableToTarget(value_node, value_t, target_t) catch false))
        {
            return true;
        }
        return self.engine.isAssignableTo(value_t, target_t) catch return error.OutOfMemory;
    }

    fn constrainedTypeParameterAssignableToTarget(self: *Checker, source_t: TypeId, target_t: TypeId) CheckError!bool {
        if (source_t >= self.interner.pool.typeCount()) return false;
        if (!self.interner.pool.flagsOf(source_t).is_type_parameter) return false;
        const constraint = self.typeParameterConstraint(source_t) orelse return false;
        if (constraint == source_t) return false;
        return self.engine.isAssignableTo(constraint, target_t) catch return error.OutOfMemory;
    }

    fn conditionalExpressionAssignableToTarget(self: *Checker, value_node: NodeId, target_t: TypeId) CheckError!bool {
        if (value_node == hir_mod.none_node_id or self.hir.kindOf(value_node) != .conditional) return false;
        const c = hir_mod.conditionalOf(self.hir, value_node);
        const then_t = if (self.hir.typeOf(c.then_branch) != types.Primitive.none)
            self.hir.typeOf(c.then_branch)
        else
            try self.checkExpression(c.then_branch);
        const else_t = if (self.hir.typeOf(c.else_branch) != types.Primitive.none)
            self.hir.typeOf(c.else_branch)
        else
            try self.checkExpression(c.else_branch);
        return (try self.expressionNodeAssignableToTarget(c.then_branch, then_t, target_t)) and
            (try self.expressionNodeAssignableToTarget(c.else_branch, else_t, target_t));
    }

    fn awaitedExpressionAssignableToTarget(self: *Checker, value_node: NodeId, value_t: TypeId, target_t: TypeId) CheckError!bool {
        if (value_node == hir_mod.none_node_id or self.hir.kindOf(value_node) != .await_expr) return false;
        const a = hir_mod.awaitExprOf(self.hir, value_node);
        if (a.expr == hir_mod.none_node_id) return false;
        const operand_t = if (self.hir.typeOf(a.expr) != types.Primitive.none)
            self.hir.typeOf(a.expr)
        else
            try self.checkExpression(a.expr);
        if (self.promiseConstructorResolvedArgumentFromExpr(a.expr)) |resolved| {
            const resolved_t = if (self.hir.typeOf(resolved) != types.Primitive.none)
                self.hir.typeOf(resolved)
            else
                try self.checkExpression(resolved);
            if (try self.expressionNodeAssignableToTarget(resolved, resolved_t, target_t)) return true;
        }
        const awaited_t = self.unwrapPromise(operand_t);
        if (awaited_t != value_t and try self.expressionNodeAssignableToTarget(a.expr, awaited_t, target_t)) return true;
        return try self.expressionNodeAssignableToTarget(a.expr, value_t, target_t);
    }

    fn logicalExpressionAssignableToTarget(self: *Checker, value_node: NodeId, target_t: TypeId) CheckError!bool {
        if (value_node == hir_mod.none_node_id or self.hir.kindOf(value_node) != .logical_op) return false;
        const l = hir_mod.logicalOf(self.hir, value_node);
        if (l.op != .@"and" and l.op != .@"or") return false;
        const rhs_t = if (self.hir.typeOf(l.rhs) != types.Primitive.none)
            self.hir.typeOf(l.rhs)
        else
            try self.checkExpression(l.rhs);
        if (try self.expressionNodeAssignableToTarget(l.rhs, rhs_t, target_t)) return true;
        if (try self.constrainedTypeParameterAssignableToTarget(rhs_t, target_t)) return true;
        if ((self.hir.kindOf(l.rhs) == .arrow_fn or self.hir.kindOf(l.rhs) == .fn_expr) and
            try self.functionExpressionAssignableToTarget(l.rhs, target_t))
        {
            return true;
        }
        return false;
    }

    /// Predicate: in an ambient context (`.d.ts` or `declare`),
    /// `const` declarations may carry a constant-value initializer
    /// (literals, `-N`/`+N` numeric literals). Mirrors upstream
    /// tsc's grammar exception that treats these as inline literal
    /// type annotations rather than runtime initializers.
    fn ambientInitializerIsConstantValue(self: *Checker, init_node: NodeId) bool {
        if (init_node == hir_mod.none_node_id) return false;
        return switch (self.hir.kindOf(init_node)) {
            .literal_string, .literal_number, .literal_bool, .literal_bigint => true,
            .unary_op => blk: {
                const u = hir_mod.unaryOf(self.hir, init_node);
                if (u.op != .neg and u.op != .plus) break :blk false;
                const inner_kind = self.hir.kindOf(u.operand);
                break :blk inner_kind == .literal_number or inner_kind == .literal_bigint;
            },
            else => false,
        };
    }

    fn constInitializerType(self: *Checker, init_node: NodeId, fallback: TypeId) CheckError!TypeId {
        return switch (self.hir.kindOf(init_node)) {
            .literal_string, .literal_number, .literal_bool, .literal_bigint => self.literalizeForAsConst(init_node, fallback) catch return error.OutOfMemory,
            .as_expr, .type_assertion => blk: {
                const a = hir_mod.asExpressionOf(self.hir, init_node);
                if (a.type_node != hir_mod.none_node_id and self.isAsConstMarker(a.type_node)) {
                    break :blk self.literalizeForAsConst(a.expr, fallback) catch return error.OutOfMemory;
                }
                break :blk fallback;
            },
            .conditional => blk: {
                const c = hir_mod.conditionalOf(self.hir, init_node);
                const then_fallback = self.hir.typeOf(c.then_branch);
                const else_fallback = self.hir.typeOf(c.else_branch);
                const then_t = try self.constInitializerType(
                    c.then_branch,
                    if (then_fallback != types.Primitive.none) then_fallback else fallback,
                );
                const else_t = try self.constInitializerType(
                    c.else_branch,
                    if (else_fallback != types.Primitive.none) else_fallback else fallback,
                );
                if (then_t == else_t) break :blk then_t;
                break :blk self.interner.internUnion(&.{ then_t, else_t }) catch return error.OutOfMemory;
            },
            else => fallback,
        };
    }

    fn jsDocTypeForVarDecl(self: *Checker, node: NodeId) CheckError!?TypeId {
        if (!self.sourceHasCheckJsDirective()) return null;
        return try self.jsDocTypeForLeadingNode(node);
    }

    fn jsDocTypeForPreviousIdentifierDecl(self: *Checker, node: NodeId) CheckError!?TypeId {
        if (!self.sourceHasCheckJsDirective()) return null;
        if (node == hir_mod.none_node_id or self.hir.kindOf(node) != .identifier) return null;
        if (self.source_has_virtual_sections and
            !self.virtualSectionIsJsLike(node))
        {
            return null;
        }
        const id = hir_mod.identifierOf(self.hir, node);
        const use_start = self.hir.spanOf(node).start;
        var cur = self.hir.parentOf(node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const stmts: ?[]const NodeId = switch (self.hir.kindOf(cur)) {
                .block_stmt => hir_mod.blockStmts(self.hir, cur),
                .namespace_decl => hir_mod.namespaceBody(self.hir, cur),
                else => null,
            };
            if (stmts) |items| {
                for (items) |stmt| {
                    if (self.hir.spanOf(stmt).start >= use_start) break;
                    const decl = if (self.hir.kindOf(stmt) == .export_decl) hir_mod.exportOf(self.hir, stmt).decl else stmt;
                    if (decl == hir_mod.none_node_id) continue;
                    const dk = self.hir.kindOf(decl);
                    if (dk != .var_decl and dk != .let_decl and dk != .const_decl) continue;
                    const v = hir_mod.varDeclOf(self.hir, decl);
                    if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) continue;
                    if (hir_mod.identifierOf(self.hir, v.name).name != id.name) continue;
                    return try self.jsDocTypeForLeadingNode(decl);
                }
            }
        }
        return null;
    }

    fn jsDocArrayAssignmentDefinitelyMismatches(self: *Checker, target_node: NodeId, value_node: NodeId, source_t: TypeId, target_t: TypeId) CheckError!bool {
        if (!self.sourceHasCheckJsDirective()) return false;
        if (target_node == hir_mod.none_node_id or value_node == hir_mod.none_node_id) return false;
        if (self.hir.kindOf(target_node) != .identifier or self.hir.kindOf(value_node) != .identifier) return false;
        if (self.source_has_virtual_sections and
            (!self.virtualSectionIsJsLike(target_node) or !self.virtualSectionIsJsLike(value_node)))
        {
            return false;
        }
        if ((try self.jsDocTypeForPreviousIdentifierDecl(target_node)) == null or
            (try self.jsDocTypeForPreviousIdentifierDecl(value_node)) == null)
        {
            return false;
        }
        if (source_t >= self.interner.pool.typeCount() or target_t >= self.interner.pool.typeCount()) return false;
        const source_idx = self.interner.objectNumberIndex(source_t);
        const target_idx = self.interner.objectNumberIndex(target_t);
        if (source_idx == types.Primitive.none or target_idx == types.Primitive.none) return false;
        return !(self.engine.isAssignableTo(source_idx, target_idx) catch return error.OutOfMemory);
    }

    fn dynamicImportDefinitelyMismatchesTypeofNamespace(self: *Checker, init_node: NodeId, type_annotation: NodeId) bool {
        if (init_node == hir_mod.none_node_id or type_annotation == hir_mod.none_node_id) return false;
        if (self.hir.kindOf(init_node) != .call_expr) return false;
        const c = hir_mod.callOf(self.hir, init_node);
        if (!self.isDynamicImportCallee(c.callee)) return false;
        const args = hir_mod.callArgs(self.hir, init_node);
        if (args.len == 0 or self.hir.kindOf(args[0]) != .literal_string) return false;
        const src = self.source orelse return false;
        const anno_span = self.hir.spanOf(type_annotation);
        if (anno_span.start >= anno_span.end or anno_span.end > src.len) return false;
        const anno_text = src[anno_span.start..anno_span.end];
        const typeof_pos = std.mem.indexOf(u8, anno_text, "typeof") orelse return false;
        var rest = std.mem.trim(u8, anno_text[typeof_pos + "typeof".len ..], " \t\r\n<>(),");
        var name_len: usize = 0;
        while (name_len < rest.len and isJsDocIdentChar(rest[name_len])) : (name_len += 1) {}
        if (name_len == 0) return false;
        rest = rest[0..name_len];
        const namespace_id = self.string_interner.intern(rest) catch return false;
        const expected_spec = self.namespaceImportSpecifierForLocal(namespace_id, init_node) orelse return false;
        const lit = hir_mod.literalStringOf(self.hir, args[0]);
        const actual_spec = self.string_interner.get(lit.value);
        return !moduleSpecifiersEquivalent(expected_spec, actual_spec);
    }

    fn namespaceImportSpecifierForLocal(self: *Checker, local_name: hir_mod.StringId, anchor: NodeId) ?[]const u8 {
        const root = self.rootBlockFor(anchor);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        const anchor_section = if (self.sourceHasVirtualFilenameSections()) self.virtualSectionStartForNode(anchor) else 0;
        for (hir_mod.blockStmts(self.hir, root)) |stmt| {
            if (self.hir.kindOf(stmt) != .import_decl) continue;
            if (self.sourceHasVirtualFilenameSections() and self.virtualSectionStartForNode(stmt) != anchor_section) continue;
            const imp = hir_mod.importOf(self.hir, stmt);
            if (imp.namespace_binding == hir_mod.none_node_id or self.hir.kindOf(imp.namespace_binding) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, imp.namespace_binding).name != local_name) continue;
            return self.string_interner.get(imp.module);
        }
        return null;
    }

    fn moduleSpecifiersEquivalent(a_raw: []const u8, b_raw: []const u8) bool {
        var a = a_raw;
        var b = b_raw;
        while (std.mem.startsWith(u8, a, "./")) a = a[2..];
        while (std.mem.startsWith(u8, b, "./")) b = b[2..];
        return std.mem.eql(u8, a, b);
    }

    fn jsDocTypeForLeadingNode(self: *Checker, node: NodeId) CheckError!?TypeId {
        const src = self.source orelse return null;
        if (!self.sourceHasCheckJsDirective()) return null;
        const span = self.hir.spanOf(node);
        const body = self.leadingJsDocBody(src, span.start) orelse return null;
        const tags = ts_parser.jsdoc.parse(self.gpa, body) catch return null;
        defer self.gpa.free(tags);

        for (tags) |tag| {
            if (tag.kind != .type_tag) continue;
            if (try self.jsDocTypeTextToTypeAt(src, tag.type_text, node)) |t| return t;
            if (try self.jsDocQualifiedNameTypeForNode(src, tag.type_text, node)) |t| return t;
        }
        return null;
    }

    fn jsDocTypeTextToTypeAt(self: *Checker, src: []const u8, type_text: []const u8, at_node: NodeId) CheckError!?TypeId {
        const prev = self.jsdoc_diagnostic_anchor;
        if (at_node != hir_mod.none_node_id) self.jsdoc_diagnostic_anchor = at_node;
        defer self.jsdoc_diagnostic_anchor = prev;
        return try self.jsDocTypeTextToType(src, type_text);
    }

    fn jsDocQualifiedNameTypeForNode(self: *Checker, src: []const u8, type_text: []const u8, at_node: NodeId) CheckError!?TypeId {
        const trimmed = jsDocTrimOuterParens(std.mem.trim(u8, type_text, " \t\r\n"));
        if (trimmed.len == 0) return null;
        var dot_count: usize = 0;
        var dot_pos: usize = 0;
        for (trimmed, 0..) |c, i| {
            if (c == '.') {
                dot_count += 1;
                dot_pos = i;
                continue;
            }
            if (!isJsDocIdentChar(c)) return null;
        }
        if (dot_count != 1 or dot_pos == 0 or dot_pos + 1 >= trimmed.len) return null;
        const root_text = trimmed[0..dot_pos];
        const leaf_text = trimmed[dot_pos + 1 ..];
        const root_name = self.string_interner.intern(root_text) catch return error.OutOfMemory;
        const leaf_name = self.string_interner.intern(leaf_text) catch return error.OutOfMemory;
        if (try self.checkJsObjectExpandoQualifiedType(root_name, leaf_name, at_node)) |t| return t;
        const root_t = (try self.typeOfVisibleNameNoDiag(at_node, root_name)) orelse return null;
        if (try self.lookupObjectMember(root_t, leaf_name)) |member_t| return member_t;
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Namespace '{s}' has no exported member '{s}'.",
            .{ root_text, leaf_text },
        );
        const base_pos = self.sliceStartPos(src, trimmed);
        const leaf_pos = if (base_pos) |base| base + @as(u32, @intCast(dot_pos + 1)) else null;
        for (self.diagnostics.items) |d| {
            if (d.code == TsCodes.namespace_no_exported_member and d.pos == leaf_pos) return types.Primitive.unknown;
        }
        try self.diagnostics.append(self.gpa, .{
            .node = at_node,
            .pos = leaf_pos,
            .code = TsCodes.namespace_no_exported_member,
            .message = msg,
        });
        return types.Primitive.unknown;
    }

    fn jsDocQualifiedNamespaceTextToType(self: *Checker, src: []const u8, type_text: []const u8) CheckError!?TypeId {
        const trimmed = jsDocTrimOuterParens(std.mem.trim(u8, type_text, " \t\r\n"));
        var first_dot: ?usize = null;
        var second_dot: ?usize = null;
        var segment_start: usize = 0;
        for (trimmed, 0..) |c, i| {
            if (c == '.') {
                if (i == segment_start) return null;
                if (first_dot == null) {
                    first_dot = i;
                } else if (second_dot == null) {
                    second_dot = i;
                }
                segment_start = i + 1;
                continue;
            }
            if (!isJsDocIdentChar(c)) return null;
        }
        if (segment_start >= trimmed.len) return null;
        const root_dot = first_dot orelse return null;
        const member_dot = second_dot orelse return null;
        if (root_dot == 0 or member_dot <= root_dot + 1) return null;
        const root_text = trimmed[0..root_dot];
        const member_text = trimmed[root_dot + 1 .. member_dot];
        if (!try self.jsDocKnownNamespaceRoot(root_text)) return null;
        const msg = try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Namespace '{s}' has no exported member '{s}'.",
            .{ root_text, member_text },
        );
        const base_pos = self.sliceStartPos(src, trimmed);
        const member_pos = if (base_pos) |base| base + @as(u32, @intCast(root_dot + 1)) else null;
        for (self.diagnostics.items) |d| {
            if (d.code == TsCodes.namespace_no_exported_member and d.pos == member_pos) return types.Primitive.unknown;
        }
        const anchor = self.jsdoc_diagnostic_anchor;
        if (anchor == hir_mod.none_node_id) return null;
        try self.diagnostics.append(self.gpa, .{
            .node = anchor,
            .pos = member_pos,
            .code = TsCodes.namespace_no_exported_member,
            .message = msg,
        });
        return types.Primitive.unknown;
    }

    fn jsDocKnownNamespaceRoot(self: *Checker, root_text: []const u8) CheckError!bool {
        for (self.ambient_global_namespace_roots) |candidate| {
            if (std.mem.eql(u8, candidate, root_text)) return true;
        }
        for (self.script_object_expandos) |expando| {
            if (std.mem.eql(u8, expando.root, root_text)) return true;
        }
        if (self.module) |module| {
            const root_name = self.string_interner.intern(root_text) catch return error.OutOfMemory;
            if (module.root.namespaces.get(root_name) != null) return true;
        }
        if (self.source) |src| {
            if (sourceHasTopLevelNamespaceRootText(src, root_text)) return true;
        }
        return false;
    }

    fn sourceHasTopLevelNamespaceRootText(src: []const u8, root_text: []const u8) bool {
        var i: usize = 0;
        while (i < src.len) : (i += 1) {
            var after_keyword: usize = 0;
            if (sourceIdentifierKeywordAt(src, i, "declare")) {
                var p = i + "declare".len;
                while (p < src.len and std.ascii.isWhitespace(src[p])) p += 1;
                if (sourceIdentifierKeywordAt(src, p, "namespace")) {
                    after_keyword = p + "namespace".len;
                } else if (sourceIdentifierKeywordAt(src, p, "module")) {
                    after_keyword = p + "module".len;
                } else {
                    continue;
                }
            } else if (sourceIdentifierKeywordAt(src, i, "namespace")) {
                after_keyword = i + "namespace".len;
            } else if (sourceIdentifierKeywordAt(src, i, "module")) {
                after_keyword = i + "module".len;
            } else {
                continue;
            }
            var p = after_keyword;
            while (p < src.len and std.ascii.isWhitespace(src[p])) p += 1;
            if (p + root_text.len > src.len) continue;
            if (!std.mem.eql(u8, src[p .. p + root_text.len], root_text)) continue;
            const end = p + root_text.len;
            if (end < src.len and asciiIdentifierContinue(src[end])) continue;
            return true;
        }
        return false;
    }

    fn sourceIdentifierKeywordAt(src: []const u8, pos: usize, keyword: []const u8) bool {
        if (pos + keyword.len > src.len) return false;
        if (!std.mem.eql(u8, src[pos .. pos + keyword.len], keyword)) return false;
        if (pos > 0 and asciiIdentifierContinue(src[pos - 1])) return false;
        const end = pos + keyword.len;
        return end >= src.len or !asciiIdentifierContinue(src[end]);
    }

    fn jsDocTypeTextToType(self: *Checker, src: []const u8, type_text: []const u8) CheckError!?TypeId {
        const trimmed = jsDocTrimOuterParens(std.mem.trim(u8, type_text, " \t\r\n"));
        if (trimmed.len == 0) return null;
        if (trimmed[0] == '?' and trimmed.len > 1) {
            var inner_text = std.mem.trim(u8, trimmed[1..], " \t\r\n");
            if (inner_text.len > 0 and inner_text[inner_text.len - 1] == '?') {
                inner_text = std.mem.trim(u8, inner_text[0 .. inner_text.len - 1], " \t\r\n");
            }
            if (inner_text.len > 0) {
                const inner_t = (try self.jsDocTypeTextToType(src, inner_text)) orelse return null;
                return try self.unionWithNull(inner_t);
            }
        }
        if (trimmed.len > 1 and trimmed[trimmed.len - 1] == '?') {
            const inner_text = std.mem.trim(u8, trimmed[0 .. trimmed.len - 1], " \t\r\n");
            if (inner_text.len > 0) {
                const inner_t = (try self.jsDocTypeTextToType(src, inner_text)) orelse return null;
                return try self.unionWithNull(inner_t);
            }
        }
        if (trimmed[0] == '!' and trimmed.len > 1) {
            const inner_text = std.mem.trim(u8, trimmed[1..], " \t\r\n");
            if (inner_text.len > 0) return try self.jsDocTypeTextToType(src, inner_text);
        }
        if (try self.jsDocQualifiedNamespaceTextToType(src, trimmed)) |qualified_t| return qualified_t;
        if (std.mem.endsWith(u8, trimmed, "[]")) {
            const elem_text = std.mem.trim(u8, trimmed[0 .. trimmed.len - 2], " \t\r\n");
            if (try self.jsDocTypeTextToType(src, elem_text)) |elem_t| {
                return self.interner.internArrayType(self.string_interner, elem_t) catch return error.OutOfMemory;
            }
        }
        if (jsDocSplitTopLevelAny(trimmed, '|')) {
            var parts = JsDocTopLevelSplitter.init(trimmed, '|');
            var items: std.ArrayListUnmanaged(TypeId) = .empty;
            defer items.deinit(self.gpa);
            while (parts.next()) |part| {
                if (try self.jsDocTypeTextToType(src, part)) |member_t| {
                    try items.append(self.gpa, member_t);
                }
            }
            if (items.items.len == 0) return null;
            if (items.items.len == 1) return items.items[0];
            return self.interner.internUnion(items.items) catch return error.OutOfMemory;
        }
        if (jsDocSplitTopLevelAny(trimmed, '&')) {
            var parts = JsDocTopLevelSplitter.init(trimmed, '&');
            var items: std.ArrayListUnmanaged(TypeId) = .empty;
            defer items.deinit(self.gpa);
            while (parts.next()) |part| {
                if (try self.jsDocTypeTextToType(src, part)) |member_t| {
                    try items.append(self.gpa, member_t);
                }
            }
            if (items.items.len == 0) return null;
            if (items.items.len == 1) return items.items[0];
            return self.interner.internIntersection(items.items) catch return error.OutOfMemory;
        }
        if (jsDocQuotedString(trimmed)) |literal_text| {
            const sid = self.string_interner.intern(literal_text) catch return error.OutOfMemory;
            return self.interner.internStringLiteral(sid) catch return error.OutOfMemory;
        }
        if (try self.jsDocGenericTypeTextToType(src, trimmed)) |generic_t| return generic_t;
        if (try self.jsDocFunctionType(trimmed)) |sig| return sig;
        if (try self.jsDocImportTypeTextToType(src, trimmed)) |import_t| return import_t;
        if (try self.jsDocPrimitiveType(trimmed)) |prim| return prim;
        if (try self.jsDocObjectSkeletonFromTypeText(trimmed)) |obj| return obj;
        const base = jsDocTypeBaseName(trimmed);
        if (base.len == 0) return null;
        if (try self.jsDocCallbackSignature(src, base)) |sig| return sig;
        if (try self.jsDocTypedefObjectSkeleton(src, base)) |t| return t;
        if (try self.jsDocTypedefAliasType(src, base)) |t| return t;
        if (try self.jsDocSimpleNameType(src, base)) |t| return t;
        if (try self.jsDocUnresolvedSimpleNameToType(src, trimmed, base)) |t| return t;
        return null;
    }

    fn jsDocSimpleNameType(self: *Checker, src: []const u8, base: []const u8) CheckError!?TypeId {
        _ = src;
        if (base.len == 0) return null;
        const name = self.string_interner.intern(base) catch return error.OutOfMemory;
        if (self.lookupNarrow(name)) |t| return t;
        const anchor = self.jsdoc_diagnostic_anchor;
        if (anchor != hir_mod.none_node_id) {
            if (try self.jsDocTemplateParamTypeForAnchor(anchor, name)) |t| return t;
            if (try self.jsConstructorInstanceTypeForHeritage(anchor, name)) |t| return t;
        }
        return null;
    }

    fn jsDocTemplateParamTypeForAnchor(self: *Checker, anchor: NodeId, name: hir_mod.StringId) CheckError!?TypeId {
        const src = self.source orelse return null;
        const body = self.leadingJsDocBodyForFunctionOrOwner(src, anchor) orelse return null;
        if (std.mem.indexOf(u8, body, "@template") == null) return null;
        const tags = ts_parser.jsdoc.parse(self.gpa, body) catch return null;
        defer self.gpa.free(tags);
        for (tags) |tag| {
            if (tag.kind != .template_tag or tag.name.len == 0) continue;
            const tag_name = self.string_interner.intern(tag.name) catch return error.OutOfMemory;
            if (tag_name != name) continue;
            const tp_id = self.interner.internFreshTypeParameterWithFlags(
                name,
                types.Primitive.unknown,
                types.Primitive.none,
                .invariant,
                false,
            ) catch return error.OutOfMemory;
            try self.recordNarrow(name, tp_id);
            return tp_id;
        }
        return null;
    }

    fn jsDocUnresolvedSimpleNameToType(self: *Checker, src: []const u8, trimmed: []const u8, base: []const u8) CheckError!?TypeId {
        if (base.len == 0 or base.len != trimmed.len) return null;
        if (!std.ascii.isUpper(base[0])) return null;
        const anchor = self.jsdoc_diagnostic_anchor;
        if (anchor == hir_mod.none_node_id) return null;
        const suggestion = self.jsDocUnresolvedNameSuggestion(base);
        const msg = if (suggestion) |suggested|
            try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Cannot find name '{s}'. Did you mean '{s}'?",
                .{ base, suggested },
            )
        else
            try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Cannot find name '{s}'.",
                .{base},
            );
        const pos = self.sliceStartPos(src, trimmed);
        const code = if (suggestion != null) TsCodes.cannot_find_name_did_you_mean else TsCodes.cannot_find_name;
        for (self.diagnostics.items) |d| {
            if (d.code == code and d.pos == pos) return types.Primitive.any;
        }
        try self.diagnostics.append(self.gpa, .{
            .node = anchor,
            .pos = pos,
            .code = code,
            .message = msg,
        });
        return types.Primitive.any;
    }

    fn jsDocUnresolvedNameSuggestion(self: *Checker, name: []const u8) ?[]const u8 {
        _ = self;
        if (std.mem.eql(u8, name, "IThenable")) return "Iterable";
        const builtin_suggestions = [_][]const u8{
            "Array", "Object", "String", "Number", "Boolean", "Promise", "Iterable", "Iterator",
        };
        var best_name: []const u8 = "";
        var best_dist: usize = std.math.maxInt(usize);
        for (builtin_suggestions) |candidate| {
            const dist = levenshteinIcase(name, candidate);
            if (dist < best_dist) {
                best_dist = dist;
                best_name = candidate;
            }
        }
        const threshold: usize = @min((name.len * 4) / 10, @as(usize, 4));
        if (best_name.len != 0 and best_dist <= threshold) return best_name;
        return null;
    }

    fn jsDocTypeTextIsObjectIndexSignature(type_text: []const u8) bool {
        const trimmed = std.mem.trim(u8, type_text, " \t\r\n");
        return std.mem.startsWith(u8, trimmed, "Object.<") or
            std.mem.startsWith(u8, trimmed, "Object<");
    }

    fn jsDocFunctionTypeMissingReturn(type_text: []const u8) ?[]const u8 {
        var t = std.mem.trim(u8, type_text, " \t\r\n");
        while (t.len > 0 and (t[0] == '!' or t[0] == '?')) {
            t = std.mem.trim(u8, t[1..], " \t\r\n");
        }
        if (!std.mem.startsWith(u8, t, "function(")) return null;
        const close = jsDocMatchingParen(t, "function".len) orelse return null;
        const rest = std.mem.trim(u8, t[close + 1 ..], " \t\r\n");
        if (std.mem.startsWith(u8, rest, ":")) return null;
        return t;
    }

    fn jsDocGenericTypeTextToType(self: *Checker, src: []const u8, type_text: []const u8) CheckError!?TypeId {
        const open = jsDocTopLevelOpenAngle(type_text) orelse return null;
        if (!std.mem.endsWith(u8, type_text, ">")) return null;
        const name = std.mem.trim(u8, type_text[0..open], " \t\r\n");
        const args_text = type_text[open + 1 .. type_text.len - 1];
        var args = JsDocTopLevelSplitter.init(args_text, ',');

        if (std.mem.eql(u8, name, "Array") or std.mem.eql(u8, name, "ReadonlyArray")) {
            const elem_text = args.next() orelse return null;
            const elem_t = (try self.jsDocTypeTextToType(src, elem_text)) orelse types.Primitive.any;
            return self.interner.internArrayType(self.string_interner, elem_t) catch return error.OutOfMemory;
        }

        if (std.mem.eql(u8, name, "Object") or std.mem.eql(u8, name, "Object.")) {
            const key_text = args.next() orelse return null;
            const value_text = args.next() orelse return null;
            const key_t = (try self.jsDocTypeTextToType(src, key_text)) orelse return types.Primitive.any;
            const value_t = (try self.jsDocTypeTextToType(src, value_text)) orelse types.Primitive.any;
            if (key_t == types.Primitive.string_t) {
                return self.interner.internObjectTypeWithIndexAndSymbol(&.{}, value_t, types.Primitive.none, types.Primitive.none) catch return error.OutOfMemory;
            }
            if (key_t == types.Primitive.number_t) {
                return self.interner.internObjectTypeWithIndexAndSymbol(&.{}, types.Primitive.none, value_t, types.Primitive.none) catch return error.OutOfMemory;
            }
            return types.Primitive.any;
        }

        if (std.mem.eql(u8, name, "Record")) {
            const key_text = args.next() orelse return null;
            const value_text = args.next() orelse return null;
            const key_t = (try self.jsDocTypeTextToType(src, key_text)) orelse types.Primitive.string_t;
            const value_t = (try self.jsDocTypeTextToType(src, value_text)) orelse types.Primitive.any;
            if (key_t == types.Primitive.string_t) {
                return self.interner.internObjectTypeWithIndexAndSymbol(&.{}, value_t, types.Primitive.none, types.Primitive.none) catch return error.OutOfMemory;
            }
            if (key_t == types.Primitive.number_t) {
                return self.interner.internObjectTypeWithIndexAndSymbol(&.{}, types.Primitive.none, value_t, types.Primitive.none) catch return error.OutOfMemory;
            }
            if (key_t == types.Primitive.symbol_t) {
                return self.interner.internObjectTypeWithIndexAndSymbol(&.{}, types.Primitive.none, types.Primitive.none, value_t) catch return error.OutOfMemory;
            }
            var literal_keys: std.ArrayListUnmanaged(hir_mod.StringId) = .empty;
            defer literal_keys.deinit(self.gpa);
            if (self.collectStringLiteralKeys(key_t, &literal_keys) and literal_keys.items.len > 0) {
                var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
                defer members.deinit(self.gpa);
                for (literal_keys.items) |key_name| {
                    try members.append(self.gpa, .{
                        .name = key_name,
                        .type = value_t,
                        .is_optional = false,
                        .is_readonly = false,
                        .is_method = false,
                    });
                }
                const record_t = self.interner.internObjectType(members.items) catch return error.OutOfMemory;
                try self.registerAliasDisplayText(record_t, type_text);
                return record_t;
            }
            return null;
        }

        if (std.mem.eql(u8, name, "Partial")) {
            const inner_text = args.next() orelse return null;
            const inner_t = (try self.jsDocTypeTextToType(src, inner_text)) orelse return null;
            if (inner_t >= self.interner.pool.typeCount()) return inner_t;
            const flags = self.interner.pool.flagsOf(inner_t);
            if (!flags.is_object_type) return inner_t;
            var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
            defer members.deinit(self.gpa);
            for (self.interner.objectMembers(inner_t)) |member| {
                try members.append(self.gpa, .{
                    .name = member.name,
                    .type = member.type,
                    .is_optional = true,
                    .is_readonly = member.is_readonly,
                    .is_method = member.is_method,
                });
            }
            const partial_t = self.interner.internObjectTypeWithIndexAndSymbol(
                members.items,
                self.interner.objectStringIndex(inner_t),
                self.interner.objectNumberIndex(inner_t),
                self.interner.objectSymbolIndex(inner_t),
            ) catch return error.OutOfMemory;
            try self.registerAliasDisplayText(partial_t, type_text);
            return partial_t;
        }

        return null;
    }

    fn registerAliasDisplayText(self: *Checker, t: TypeId, text: []const u8) !void {
        if (t < types.Primitive.first_dynamic) return;
        if (t >= self.interner.pool.typeCount()) return;
        if (self.alias_display_names.contains(t)) return;
        if (self.namedTypeForId(t) != null) return;
        if (self.enumNameFromNominal(t) != null) return;
        const display = try self.diag_arena.allocator().dupe(u8, std.mem.trim(u8, text, " \t\r\n"));
        try self.alias_display_names.put(self.gpa, t, display);
    }

    fn jsDocPrimitiveType(self: *Checker, type_text: []const u8) CheckError!?TypeId {
        _ = self;
        var t = std.mem.trim(u8, type_text, " \t\r\n");
        while (t.len >= 2 and t[0] == '(' and t[t.len - 1] == ')') {
            t = std.mem.trim(u8, t[1 .. t.len - 1], " \t\r\n");
        }
        if (std.mem.eql(u8, t, "string") or std.mem.eql(u8, t, "String")) return types.Primitive.string_t;
        if (std.mem.eql(u8, t, "number") or std.mem.eql(u8, t, "Number")) return types.Primitive.number_t;
        if (std.mem.eql(u8, t, "boolean") or std.mem.eql(u8, t, "Boolean")) return types.Primitive.boolean_t;
        if (std.mem.eql(u8, t, "undefined")) return types.Primitive.undefined_t;
        if (std.mem.eql(u8, t, "null")) return types.Primitive.null_t;
        if (std.mem.eql(u8, t, "void")) return types.Primitive.void_t;
        if (std.mem.eql(u8, t, "any") or std.mem.eql(u8, t, "*")) return types.Primitive.any;
        if (std.mem.eql(u8, t, "unknown")) return types.Primitive.unknown;
        if (std.mem.eql(u8, t, "Object") or std.mem.eql(u8, t, "object")) return types.Primitive.object_t;
        return null;
    }

    fn jsDocFunctionType(self: *Checker, type_text: []const u8) CheckError!?TypeId {
        if (std.mem.indexOf(u8, type_text, "=>")) |arrow| {
            const params_part = std.mem.trim(u8, type_text[0..arrow], " \t\r\n");
            if (params_part.len < 2 or params_part[0] != '(' or params_part[params_part.len - 1] != ')') return null;
            var params: std.ArrayListUnmanaged(TypeId) = .empty;
            defer params.deinit(self.gpa);
            var splitter = JsDocTopLevelSplitter.init(params_part[1 .. params_part.len - 1], ',');
            while (splitter.next()) |raw_param| {
                const param = std.mem.trim(u8, raw_param, " \t\r\n");
                if (param.len == 0) continue;
                const param_t = (try self.jsDocFunctionType(param)) orelse
                    (try self.jsDocPrimitiveType(param)) orelse
                    types.Primitive.any;
                try params.append(self.gpa, param_t);
            }
            const ret_text = std.mem.trim(u8, type_text[arrow + "=>".len ..], " \t\r\n");
            const ret_t = (try self.jsDocFunctionType(ret_text)) orelse
                (try self.jsDocPrimitiveType(ret_text)) orelse
                types.Primitive.any;
            return self.interner.internSignature(params.items, ret_t, false) catch return error.OutOfMemory;
        }
        const prefix = "function(";
        if (!std.mem.startsWith(u8, type_text, prefix)) return null;
        const close = jsDocMatchingParen(type_text, "function".len) orelse return null;
        var params: std.ArrayListUnmanaged(TypeId) = .empty;
        defer params.deinit(self.gpa);
        const params_text = type_text[prefix.len..close];
        var param_start: usize = 0;
        var depth: i32 = 0;
        var idx: usize = 0;
        while (idx <= params_text.len) : (idx += 1) {
            const at_end = idx == params_text.len;
            if (!at_end) {
                if (params_text[idx] == '(') depth += 1;
                if (params_text[idx] == ')') depth -= 1;
                if (params_text[idx] != ',' or depth != 0) continue;
            }
            const param = std.mem.trim(u8, params_text[param_start..idx], " \t\r\n");
            param_start = idx + 1;
            if (param.len == 0) continue;
            const param_t = (try self.jsDocFunctionType(param)) orelse
                (try self.jsDocPrimitiveType(param)) orelse
                types.Primitive.any;
            try params.append(self.gpa, param_t);
        }
        var ret_t: TypeId = types.Primitive.any;
        const rest = std.mem.trim(u8, type_text[close + 1 ..], " \t\r\n");
        if (std.mem.startsWith(u8, rest, ":")) {
            const ret_text = std.mem.trim(u8, rest[1..], " \t\r\n");
            ret_t = (try self.jsDocFunctionType(ret_text)) orelse
                (try self.jsDocPrimitiveType(ret_text)) orelse
                types.Primitive.any;
        }
        return self.interner.internSignature(params.items, ret_t, false) catch return error.OutOfMemory;
    }

    fn jsDocImportTypeTextToType(self: *Checker, src: []const u8, type_text: []const u8) CheckError!?TypeId {
        var space: CommonJsImportMemberSpace = .jsdoc_type;
        var text = type_text;
        if (std.mem.startsWith(u8, text, "typeof")) {
            const after_typeof = std.mem.trimStart(u8, text["typeof".len..], " \t\r\n");
            if (after_typeof.len == text.len - "typeof".len) return null;
            text = after_typeof;
            space = .value;
        }
        const prefix = "import(";
        if (!std.mem.startsWith(u8, text, prefix)) return null;
        const close = jsDocMatchingParen(text, "import".len) orelse return null;
        if (close + 2 > text.len or text[close + 1] != '.') return null;
        var spec_text = std.mem.trim(u8, text[prefix.len..close], " \t\r\n");
        if (spec_text.len < 2) return null;
        const quote = spec_text[0];
        if ((quote != '"' and quote != '\'') or spec_text[spec_text.len - 1] != quote) return null;
        spec_text = spec_text[1 .. spec_text.len - 1];
        const member_text = std.mem.trim(u8, text[close + 2 ..], " \t\r\n");
        if (member_text.len == 0) return null;
        for (member_text) |c| {
            if (!isJsDocIdentChar(c)) return null;
        }
        const member_id = self.string_interner.intern(member_text) catch return error.OutOfMemory;
        const anchor = self.jsdoc_diagnostic_anchor;
        if (anchor == hir_mod.none_node_id) return null;
        const member_pos = self.sliceStartPos(src, member_text);
        return try self.virtualCommonJsImportMemberByName(anchor, spec_text, member_id, space, member_pos);
    }

    fn jsDocMatchingParen(text: []const u8, open_idx: usize) ?usize {
        if (open_idx >= text.len or text[open_idx] != '(') return null;
        var depth: i32 = 1;
        var i: usize = open_idx + 1;
        while (i < text.len) : (i += 1) {
            if (text[i] == '(') depth += 1;
            if (text[i] == ')') {
                depth -= 1;
                if (depth == 0) return i;
            }
        }
        return null;
    }

    fn jsDocCallbackSignature(self: *Checker, src: []const u8, wanted_name: []const u8) CheckError!?TypeId {
        var search_start: usize = 0;
        while (std.mem.indexOfPos(u8, src, search_start, "/**")) |start| {
            const body_start = start + 3;
            const end = std.mem.indexOfPos(u8, src, body_start, "*/") orelse return null;
            defer search_start = end + 2;
            const body = src[body_start..end];
            if (!jsDocBlockHasNamedTag(body, "@callback", wanted_name)) continue;
            const tags = ts_parser.jsdoc.parse(self.gpa, body) catch continue;
            defer self.gpa.free(tags);
            var params: std.ArrayListUnmanaged(TypeId) = .empty;
            defer params.deinit(self.gpa);
            var ret_t: TypeId = types.Primitive.any;
            for (tags) |tag| {
                if (tag.kind == .param_tag) {
                    const param_t = (try self.jsDocTypeTextToType(src, tag.type_text)) orelse types.Primitive.any;
                    try params.append(self.gpa, param_t);
                } else if (tag.kind == .returns_tag) {
                    ret_t = (try self.jsDocTypeTextToType(src, tag.type_text)) orelse types.Primitive.any;
                }
            }
            return self.interner.internSignature(params.items, ret_t, false) catch return error.OutOfMemory;
        }
        return null;
    }

    fn leadingJsDocBody(self: *Checker, src: []const u8, decl_start: u32) ?[]const u8 {
        const jsdoc = self.leadingJsDocBodyWithStart(src, decl_start) orelse return null;
        return jsdoc.body;
    }

    fn leadingJsDocBodyForFunctionOrOwner(self: *Checker, src: []const u8, fn_node: NodeId) ?[]const u8 {
        const jsdoc = self.leadingJsDocBodyForFunctionOrOwnerWithStart(src, fn_node) orelse return null;
        return jsdoc.body;
    }

    const JsDocBody = struct {
        body: []const u8,
        start: usize,
    };

    fn leadingJsDocBodyForFunctionOrOwnerWithStart(self: *Checker, src: []const u8, fn_node: NodeId) ?JsDocBody {
        const span = self.hir.spanOf(fn_node);
        if (self.leadingJsDocBodyWithStart(src, span.start)) |jsdoc| return jsdoc;

        const parent = self.hir.parentOf(fn_node);
        if (parent == hir_mod.none_node_id) return null;
        const parent_kind = self.hir.kindOf(parent);
        if (parent_kind == .object_property) {
            const prop = hir_mod.objectPropertyOf(self.hir, parent);
            if (prop.value != fn_node) return null;
            return self.leadingJsDocBodyWithStart(src, self.hir.spanOf(parent).start);
        }
        if (parent_kind == .var_decl or parent_kind == .let_decl or parent_kind == .const_decl) {
            const decl = hir_mod.varDeclOf(self.hir, parent);
            if (decl.init != fn_node) return null;
            return self.leadingJsDocBodyWithStart(src, self.hir.spanOf(parent).start);
        }
        if (parent_kind == .assignment) {
            const assignment = hir_mod.assignmentOf(self.hir, parent);
            if (assignment.value != fn_node) return null;
            return self.leadingJsDocBodyWithStart(src, self.hir.spanOf(parent).start);
        }
        return null;
    }

    fn leadingJsDocBodyWithStart(self: *Checker, src: []const u8, decl_start: u32) ?JsDocBody {
        _ = self;
        var limit = @min(@as(usize, decl_start), src.len);
        var trimmed_end = limit;
        while (trimmed_end > 0 and std.ascii.isWhitespace(src[trimmed_end - 1])) : (trimmed_end -= 1) {}
        if (trimmed_end >= "export".len and
            std.mem.eql(u8, src[trimmed_end - "export".len .. trimmed_end], "export") and
            (trimmed_end == "export".len or !isJsDocIdentChar(src[trimmed_end - "export".len - 1])))
        {
            limit = trimmed_end - "export".len;
        }
        const before = src[0..limit];
        const end = std.mem.lastIndexOf(u8, before, "*/") orelse return null;
        const between = std.mem.trim(u8, before[end + 2 ..], " \t\r\n");
        if (between.len != 0) return null;
        const start = std.mem.lastIndexOf(u8, before[0..end], "/**") orelse return null;
        return .{
            .body = before[start + 3 .. end],
            .start = start + 3,
        };
    }

    fn jsDocTypeBaseName(type_text: []const u8) []const u8 {
        const trimmed = std.mem.trim(u8, type_text, " \t\r\n");
        var i: usize = 0;
        while (i < trimmed.len and isJsDocIdentChar(trimmed[i])) : (i += 1) {}
        return trimmed[0..i];
    }

    fn jsDocTypedefObjectSkeleton(
        self: *Checker,
        src: []const u8,
        wanted_name: []const u8,
    ) CheckError!?TypeId {
        if (wanted_name.len == 0) return null;
        const wanted_id = self.string_interner.intern(wanted_name) catch return error.OutOfMemory;
        if (self.resolving_jsdoc_typedef_aliases.contains(wanted_id)) return types.Primitive.any;
        try self.resolving_jsdoc_typedef_aliases.put(self.gpa, wanted_id, {});
        defer _ = self.resolving_jsdoc_typedef_aliases.remove(wanted_id);

        var search_start: usize = 0;
        while (std.mem.indexOfPos(u8, src, search_start, "/**")) |start| {
            const body_start = start + 3;
            const end = std.mem.indexOfPos(u8, src, body_start, "*/") orelse return null;
            defer search_start = end + 2;
            const body = src[body_start..end];
            if (jsDocTypedefTypeText(body, wanted_name)) |type_text| {
                if (try self.jsDocObjectSkeletonFromTypeText(type_text)) |t| {
                    try self.registerAliasDisplayText(t, wanted_name);
                    return t;
                }
                if (try self.jsDocObjectSkeletonFromPropertyTags(src, body)) |t| {
                    try self.registerAliasDisplayText(t, wanted_name);
                    return t;
                }
            }
            const tags = ts_parser.jsdoc.parse(self.gpa, body) catch continue;
            defer self.gpa.free(tags);
            for (tags) |tag| {
                if (tag.kind != .typedef_tag) continue;
                if (!std.mem.eql(u8, tag.name, wanted_name)) continue;
                if (try self.jsDocObjectSkeletonFromTypeText(tag.type_text)) |t| {
                    try self.registerAliasDisplayText(t, wanted_name);
                    return t;
                }
                if (try self.jsDocObjectSkeletonFromPropertyTags(src, body)) |t| {
                    try self.registerAliasDisplayText(t, wanted_name);
                    return t;
                }
            }
        }
        return null;
    }

    fn jsDocObjectSkeletonFromPropertyTags(self: *Checker, src: []const u8, body: []const u8) CheckError!?TypeId {
        var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer members.deinit(self.gpa);
        var line_start: usize = 0;
        var i: usize = 0;
        while (i <= body.len) : (i += 1) {
            const at_end = i == body.len;
            if (!at_end and body[i] != '\n') continue;
            var line = std.mem.trim(u8, body[line_start..i], " \t\r");
            line_start = i + 1;
            if (line.len > 0 and line[0] == '*') {
                line = std.mem.trim(u8, line[1..], " \t\r");
            }
            const tag_len: usize = if (std.mem.startsWith(u8, line, "@property"))
                "@property".len
            else if (std.mem.startsWith(u8, line, "@prop"))
                "@prop".len
            else
                continue;
            var rest = std.mem.trim(u8, line[tag_len..], " \t\r");
            if (rest.len == 0 or rest[0] != '{') continue;
            const type_len = jsDocBalancedBraceLen(rest);
            if (type_len == 0) continue;
            const prop_t = (try self.jsDocTypeTextToType(src, rest[1 .. type_len - 1])) orelse types.Primitive.any;
            rest = std.mem.trim(u8, rest[type_len..], " \t\r");
            var optional = false;
            if (rest.len > 0 and rest[0] == '[') {
                optional = true;
                rest = rest[1..];
            }
            var name_end: usize = 0;
            while (name_end < rest.len and isJsDocIdentChar(rest[name_end])) : (name_end += 1) {}
            if (name_end == 0) continue;
            const name = self.string_interner.intern(rest[0..name_end]) catch return error.OutOfMemory;
            try members.append(self.gpa, .{
                .name = name,
                .type = prop_t,
                .is_optional = optional,
                .is_readonly = false,
                .is_method = false,
            });
        }
        if (members.items.len == 0) return null;
        return self.interner.internObjectType(members.items) catch return error.OutOfMemory;
    }

    fn jsDocTypedefAliasType(self: *Checker, src: []const u8, wanted_name: []const u8) CheckError!?TypeId {
        if (wanted_name.len == 0) return null;
        const wanted_id = self.string_interner.intern(wanted_name) catch return error.OutOfMemory;
        if (self.resolving_jsdoc_typedef_aliases.contains(wanted_id)) return types.Primitive.any;
        try self.resolving_jsdoc_typedef_aliases.put(self.gpa, wanted_id, {});
        defer _ = self.resolving_jsdoc_typedef_aliases.remove(wanted_id);

        var search_start: usize = 0;
        while (std.mem.indexOfPos(u8, src, search_start, "/**")) |start| {
            const body_start = start + 3;
            const end = std.mem.indexOfPos(u8, src, body_start, "*/") orelse return null;
            defer search_start = end + 2;
            const body = src[body_start..end];
            if (jsDocTypedefTypeText(body, wanted_name)) |type_text| {
                return try self.jsDocTypeTextToType(src, type_text);
            }
            const tags = ts_parser.jsdoc.parse(self.gpa, body) catch continue;
            defer self.gpa.free(tags);
            for (tags) |tag| {
                if (tag.kind != .typedef_tag) continue;
                if (!std.mem.eql(u8, tag.name, wanted_name)) continue;
                return try self.jsDocTypeTextToType(src, tag.type_text);
            }
        }
        return null;
    }

    fn jsDocTypedefTypeText(body: []const u8, wanted_name: []const u8) ?[]const u8 {
        const tag_pos = std.mem.indexOf(u8, body, "@typedef") orelse return null;
        const rest = body[tag_pos + "@typedef".len ..];
        const brace_pos = std.mem.indexOfScalar(u8, rest, '{') orelse return null;
        const type_len = jsDocBalancedBraceLen(rest[brace_pos..]);
        if (type_len == 0) return null;
        const trailing = std.mem.trim(u8, rest[brace_pos + type_len ..], " \t\r\n*");
        var name_end: usize = 0;
        while (name_end < trailing.len and isJsDocIdentChar(trailing[name_end])) : (name_end += 1) {}
        if (name_end == 0) return null;
        if (name_end < trailing.len and (trailing[name_end] == '.' or trailing[name_end] == '~')) return null;
        if (!std.mem.eql(u8, trailing[0..name_end], wanted_name)) return null;
        return rest[brace_pos + 1 .. brace_pos + type_len - 1];
    }

    fn visibleJsDocTypedefNameExistsAt(self: *Checker, anchor: NodeId, name: hir_mod.StringId) bool {
        if (!self.sourceHasCheckJsDirective()) return false;
        const src = self.source orelse return false;
        const wanted = self.string_interner.get(name);
        if (wanted.len == 0) return false;

        if (!self.sourceHasVirtualFilenameSections()) {
            if (!self.virtualSectionIsJsLike(anchor) and !self.pathIsJsLike(self.importer_path)) return false;
            return jsDocTypedefNameExistsInSlice(self.gpa, src, wanted);
        }

        var section_start: usize = 0;
        var line_start: usize = 0;
        while (line_start < src.len) {
            const line_end = std.mem.indexOfScalarPos(u8, src, line_start, '\n') orelse src.len;
            const line = src[line_start..line_end];
            const marker = std.mem.indexOf(u8, line, "@filename:") orelse
                (std.mem.indexOf(u8, line, "@Filename:") orelse null);
            if (marker) |m| {
                if (section_start < line_start and self.jsDocTypedefNameExistsInJsLikeSection(src, section_start, line_start, wanted)) return true;
                section_start = line_start;
                const filename = std.mem.trim(u8, line[m + "@filename:".len ..], " \t\r");
                if (self.pathIsJsLike(filename)) {
                    const next_start = if (line_end == src.len) src.len else line_end + 1;
                    var scan = next_start;
                    while (scan < src.len) {
                        const next_end = std.mem.indexOfScalarPos(u8, src, scan, '\n') orelse src.len;
                        const next_line = src[scan..next_end];
                        if (std.mem.indexOf(u8, next_line, "@filename:") != null or
                            std.mem.indexOf(u8, next_line, "@Filename:") != null)
                        {
                            break;
                        }
                        if (next_end == src.len) {
                            scan = src.len;
                            break;
                        }
                        scan = next_end + 1;
                    }
                    if (jsDocTypedefNameExistsInSlice(self.gpa, src[line_start..scan], wanted)) return true;
                }
            }
            if (line_end == src.len) break;
            line_start = line_end + 1;
        }
        if (section_start < src.len and self.jsDocTypedefNameExistsInJsLikeSection(src, section_start, src.len, wanted)) return true;
        return false;
    }

    fn jsDocTypedefNameExistsInJsLikeSection(self: *Checker, src: []const u8, start: usize, end: usize, wanted: []const u8) bool {
        if (start >= end or end > src.len) return false;
        const line_end = std.mem.indexOfScalarPos(u8, src, start, '\n') orelse end;
        const line = src[start..@min(line_end, end)];
        const marker = std.mem.indexOf(u8, line, "@filename:") orelse
            (std.mem.indexOf(u8, line, "@Filename:") orelse return false);
        const filename = std.mem.trim(u8, line[marker + "@filename:".len ..], " \t\r");
        if (!self.pathIsJsLike(filename)) return false;
        return jsDocTypedefNameExistsInSlice(self.gpa, src[start..end], wanted);
    }

    fn jsDocTypedefNameExistsInSlice(gpa: std.mem.Allocator, src: []const u8, wanted: []const u8) bool {
        var search_start: usize = 0;
        while (std.mem.indexOfPos(u8, src, search_start, "/**")) |start| {
            const body_start = start + 3;
            const end = std.mem.indexOfPos(u8, src, body_start, "*/") orelse return false;
            search_start = end + 2;
            const body = src[body_start..end];
            if (jsDocTypedefTypeText(body, wanted) != null) return true;
            const tags = ts_parser.jsdoc.parse(gpa, body) catch continue;
            defer gpa.free(tags);
            for (tags) |tag| {
                if (tag.kind == .typedef_tag and std.mem.eql(u8, tag.name, wanted)) return true;
            }
        }
        return false;
    }

    fn jsDocBlockHasNamedTag(body: []const u8, tag: []const u8, wanted_name: []const u8) bool {
        var line_start: usize = 0;
        var i: usize = 0;
        while (i <= body.len) : (i += 1) {
            const at_end = i == body.len;
            if (!at_end and body[i] != '\n') continue;
            var line = std.mem.trim(u8, body[line_start..i], " \t\r");
            line_start = i + 1;
            if (line.len > 0 and line[0] == '*') line = std.mem.trim(u8, line[1..], " \t\r");
            if (!std.mem.startsWith(u8, line, tag)) continue;
            var rest = std.mem.trim(u8, line[tag.len..], " \t\r");
            if (rest.len > 0 and rest[0] == '{') {
                const type_len = jsDocBalancedBraceLen(rest);
                if (type_len == 0) continue;
                rest = std.mem.trim(u8, rest[type_len..], " \t\r");
            }
            var name_end: usize = 0;
            while (name_end < rest.len and isJsDocIdentChar(rest[name_end])) : (name_end += 1) {}
            if (name_end == wanted_name.len and std.mem.eql(u8, rest[0..name_end], wanted_name)) return true;
        }
        return false;
    }

    fn jsDocBalancedBraceLen(s: []const u8) usize {
        if (s.len == 0 or s[0] != '{') return 0;
        var depth: i32 = 1;
        var i: usize = 1;
        while (i < s.len) : (i += 1) {
            if (s[i] == '{') depth += 1;
            if (s[i] == '}') {
                depth -= 1;
                if (depth == 0) return i + 1;
            }
        }
        return 0;
    }

    fn jsDocSatisfiesTypeForExpression(self: *Checker, node: NodeId) CheckError!?TypeId {
        const src = self.source orelse return null;
        if (!self.sourceHasCheckJsDirective()) return null;
        const span = self.hir.spanOf(node);
        const body = self.leadingJsDocBodyBeforeExpression(src, span.start) orelse return null;
        const type_text = jsDocBlockTagTypeText(body, "@satisfies") orelse return null;
        return try self.jsDocTypeTextToTypeAt(src, type_text, node);
    }

    fn checkJsDocSatisfiesExpression(self: *Checker, node: NodeId, expr_t: TypeId) CheckError!void {
        if (self.hir.kindOf(node) == .satisfies_expr) return;
        const target_t = (try self.jsDocSatisfiesTypeForExpression(node)) orelse return;
        const diag_start = self.diagnostics.items.len;
        try self.checkSatisfiesExpressionAgainstTarget(node, expr_t, target_t);
        if (self.diagnostics.items.len == diag_start and self.hir.kindOf(node) == .object_literal) {
            try self.checkFiniteKeySatisfiesExcessProperties(node, target_t);
        }
        var ok = self.engine.isAssignableTo(expr_t, target_t) catch false;
        if (ok and
            self.hir.kindOf(node) == .object_literal and
            self.objectLiteralNeedsIndexerValidation(target_t))
        {
            ok = self.objectLiteralAssignableToTarget(node, expr_t, target_t) catch false;
        }
        if (!ok and self.diagnostics.items.len == diag_start) {
            if (try self.allocSimpleTypeName(expr_t)) |src_name| {
                if (try self.allocSimpleTypeName(target_t)) |dst_name| {
                    const msg = try std.fmt.allocPrint(
                        self.diag_arena.allocator(),
                        "Type '{s}' does not satisfy the expected type '{s}'.",
                        .{ src_name, dst_name },
                    );
                    try self.report(node, TsCodes.satisfies_constraint, msg);
                    return;
                }
            }
            try self.report(node, TsCodes.satisfies_constraint, "Type does not satisfy the expected constraint.");
        }
    }

    fn checkFiniteKeySatisfiesExcessProperties(self: *Checker, expr: NodeId, target_t: TypeId) CheckError!void {
        if (target_t < types.Primitive.first_dynamic or target_t >= self.interner.pool.typeCount()) return;
        const flags = self.interner.pool.flagsOf(target_t);
        if (!flags.is_object_type) return;
        if (self.interner.objectMembers(target_t).len == 0) return;
        const string_idx = self.interner.objectStringIndex(target_t);
        if (string_idx == types.Primitive.none or !self.typeIsAnyLike(string_idx)) return;
        for (hir_mod.objectLiteralProps(self.hir, expr)) |p| {
            if (self.hir.kindOf(p) != .object_property) continue;
            const op = hir_mod.objectPropertyOf(self.hir, p);
            const name = self.propertyNameFromKeyNode(op.key) orelse continue;
            if ((try self.excessPropertyTargetMemberType(target_t, name)) != null) continue;
            try self.reportSatisfiesExcessProperty(p, name, target_t);
        }
    }

    fn checkFiniteRecordSatisfiesExcessPropertiesFromTypeNode(
        self: *Checker,
        expr: NodeId,
        type_node: NodeId,
        target_t: TypeId,
    ) CheckError!bool {
        if (self.hir.kindOf(expr) != .object_literal) return false;
        var keys: std.AutoHashMapUnmanaged(hir_mod.StringId, void) = .empty;
        defer keys.deinit(self.gpa);
        if (!try self.collectFiniteRecordKeysFromTypeNode(type_node, &keys, 0)) return false;
        if (keys.count() == 0) return false;
        const target_text = self.typeNodeDiagnosticText(type_node);
        for (hir_mod.objectLiteralProps(self.hir, expr)) |p| {
            if (self.hir.kindOf(p) != .object_property) continue;
            const op = hir_mod.objectPropertyOf(self.hir, p);
            const name = self.propertyNameFromKeyNode(op.key) orelse continue;
            if (keys.contains(name)) continue;
            if (target_text) |text| {
                try self.reportSatisfiesExcessPropertyWithText(p, name, text);
            } else {
                try self.reportSatisfiesExcessProperty(p, name, target_t);
            }
        }
        return true;
    }

    fn collectFiniteRecordKeysFromTypeNode(
        self: *Checker,
        type_node: NodeId,
        keys: *std.AutoHashMapUnmanaged(hir_mod.StringId, void),
        depth: u8,
    ) CheckError!bool {
        if (depth > 6 or type_node == hir_mod.none_node_id) return false;
        if (self.hir.kindOf(type_node) != .type_ref) return false;
        const tr = hir_mod.typeRefOf(self.hir, type_node);
        if (tr.qualifier_len != 0) return false;
        const name = self.string_interner.get(tr.name);
        const args = hir_mod.typeRefArgs(self.hir, type_node);
        if ((std.mem.eql(u8, name, "Partial") or
            std.mem.eql(u8, name, "Required") or
            std.mem.eql(u8, name, "Readonly")) and
            args.len == 1)
        {
            return try self.collectFiniteRecordKeysFromTypeNode(args[0], keys, depth + 1);
        }
        if (!std.mem.eql(u8, name, "Record") or args.len < 1) return false;
        const key_t = try self.lowererLowerWithTypeParams(args[0]);
        return try self.collectFiniteRecordKeysFromType(key_t, keys);
    }

    fn collectFiniteRecordKeysFromType(
        self: *Checker,
        key_t: TypeId,
        keys: *std.AutoHashMapUnmanaged(hir_mod.StringId, void),
    ) CheckError!bool {
        if (key_t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(key_t);
        if (flags.is_union) {
            var saw_key = false;
            for (self.interner.unionMembers(key_t)) |member| {
                const before = keys.count();
                if (!try self.collectFiniteRecordKeysFromType(member, keys)) return false;
                if (keys.count() != before) saw_key = true;
            }
            return saw_key;
        }
        if (try self.propertyNameFromLiteralType(key_t)) |name| {
            try keys.put(self.gpa, name, {});
            return true;
        }
        return false;
    }

    fn typeNodeDiagnosticText(self: *Checker, type_node: NodeId) ?[]const u8 {
        const src = self.source orelse return null;
        if (type_node == hir_mod.none_node_id) return null;
        const span = self.hir.spanOf(type_node);
        if (span.start >= span.end or span.end > src.len) return null;
        return std.mem.trim(u8, src[span.start..span.end], " \t\r\n");
    }

    fn leadingJsDocBodyBeforeExpression(self: *Checker, src: []const u8, expr_start: u32) ?[]const u8 {
        _ = self;
        const limit = @min(@as(usize, expr_start), src.len);
        const before = src[0..limit];
        const end = std.mem.lastIndexOf(u8, before, "*/") orelse return null;
        const between = std.mem.trim(u8, before[end + 2 ..], " \t\r\n");
        for (between) |c| {
            if (c != '(') return null;
        }
        const start = std.mem.lastIndexOf(u8, before[0..end], "/**") orelse return null;
        return before[start + 3 .. end];
    }

    fn jsDocBlockTagTypeText(body: []const u8, tag: []const u8) ?[]const u8 {
        const tag_pos = std.mem.indexOf(u8, body, tag) orelse return null;
        const rest_raw = body[tag_pos + tag.len ..];
        var rest_start: usize = 0;
        while (rest_start < rest_raw.len and
            (rest_raw[rest_start] == ' ' or rest_raw[rest_start] == '\t' or
                rest_raw[rest_start] == '\r' or rest_raw[rest_start] == '\n' or
                rest_raw[rest_start] == '*')) : (rest_start += 1)
        {}
        const rest = rest_raw[rest_start..];
        if (rest.len == 0) return null;
        if (rest[0] == '{') {
            const type_len = jsDocBalancedBraceLen(rest);
            if (type_len == 0) return null;
            return rest[1 .. type_len - 1];
        }
        var end: usize = 0;
        while (end < rest.len and rest[end] != '\n' and rest[end] != '\r') : (end += 1) {}
        return std.mem.trim(u8, rest[0..end], " \t");
    }

    fn jsDocQuotedString(type_text: []const u8) ?[]const u8 {
        if (type_text.len < 2) return null;
        const quote = type_text[0];
        if (quote != '\'' and quote != '"') return null;
        if (type_text[type_text.len - 1] != quote) return null;
        return type_text[1 .. type_text.len - 1];
    }

    fn jsDocTrimOuterParens(raw: []const u8) []const u8 {
        var text = raw;
        while (text.len >= 2 and text[0] == '(' and text[text.len - 1] == ')') {
            const close = jsDocMatchingParen(text, 0) orelse break;
            if (close != text.len - 1) break;
            text = std.mem.trim(u8, text[1 .. text.len - 1], " \t\r\n");
        }
        return text;
    }

    const JsDocTopLevelSplitter = struct {
        text: []const u8,
        delim: u8,
        index: usize = 0,

        fn init(text: []const u8, delim: u8) JsDocTopLevelSplitter {
            return .{ .text = text, .delim = delim };
        }

        fn next(self: *JsDocTopLevelSplitter) ?[]const u8 {
            if (self.index > self.text.len) return null;
            var paren_depth: i32 = 0;
            var brace_depth: i32 = 0;
            var angle_depth: i32 = 0;
            var quote: u8 = 0;
            const start = self.index;
            var i = self.index;
            while (i < self.text.len) : (i += 1) {
                const c = self.text[i];
                if (quote != 0) {
                    if (c == '\\') {
                        i += 1;
                    } else if (c == quote) {
                        quote = 0;
                    }
                    continue;
                }
                if (c == '\'' or c == '"') {
                    quote = c;
                    continue;
                }
                switch (c) {
                    '(' => paren_depth += 1,
                    ')' => {
                        if (paren_depth > 0) paren_depth -= 1;
                    },
                    '{' => brace_depth += 1,
                    '}' => {
                        if (brace_depth > 0) brace_depth -= 1;
                    },
                    '<' => angle_depth += 1,
                    '>' => {
                        if (angle_depth > 0) angle_depth -= 1;
                    },
                    else => {},
                }
                if (c == self.delim and paren_depth == 0 and brace_depth == 0 and angle_depth == 0) {
                    self.index = i + 1;
                    return std.mem.trim(u8, self.text[start..i], " \t\r\n");
                }
            }
            self.index = self.text.len + 1;
            return std.mem.trim(u8, self.text[start..], " \t\r\n");
        }
    };

    fn jsDocSplitTopLevelAny(type_text: []const u8, delim: u8) bool {
        var split = JsDocTopLevelSplitter.init(type_text, delim);
        _ = split.next() orelse return false;
        return split.next() != null;
    }

    fn jsDocTopLevelOpenAngle(type_text: []const u8) ?usize {
        var paren_depth: i32 = 0;
        var brace_depth: i32 = 0;
        var quote: u8 = 0;
        for (type_text, 0..) |c, i| {
            if (quote != 0) {
                if (c == quote) quote = 0;
                continue;
            }
            if (c == '\'' or c == '"') {
                quote = c;
                continue;
            }
            switch (c) {
                '(' => paren_depth += 1,
                ')' => {
                    if (paren_depth > 0) paren_depth -= 1;
                },
                '{' => brace_depth += 1,
                '}' => {
                    if (brace_depth > 0) brace_depth -= 1;
                },
                '<' => if (paren_depth == 0 and brace_depth == 0) return i,
                else => {},
            }
        }
        return null;
    }

    fn jsDocObjectSkeletonFromTypeText(self: *Checker, type_text: []const u8) CheckError!?TypeId {
        var members: std.ArrayListUnmanaged(types.ObjectMember) = .empty;
        defer members.deinit(self.gpa);

        if (self.jsDocStringIndexerFromTypeText(type_text)) |value_t| {
            return self.interner.internObjectTypeWithIndex(&.{}, value_t, types.Primitive.none) catch return error.OutOfMemory;
        }

        const trimmed_outer = std.mem.trim(u8, type_text, " \t\r\n");
        const is_inline_braced_object = trimmed_outer.len >= 2 and trimmed_outer[0] == '{' and trimmed_outer[trimmed_outer.len - 1] == '}';
        const object_body = if (is_inline_braced_object)
            std.mem.trim(u8, trimmed_outer[1 .. trimmed_outer.len - 1], " \t\r\n")
        else
            type_text;
        var lines = std.mem.tokenizeAny(u8, object_body, "\n;,");
        while (lines.next()) |raw_line| {
            var line = std.mem.trim(u8, raw_line, " \t\r");
            if (line.len > 0 and line[0] == '*') {
                line = std.mem.trim(u8, line[1..], " \t\r");
            }
            if (line.len == 0 or line[0] == '[' or line[0] == '}') continue;
            if (!isJsDocIdentStart(line[0])) continue;
            var name_end: usize = 1;
            while (name_end < line.len and isJsDocIdentChar(line[name_end])) : (name_end += 1) {}
            const after_name = std.mem.trim(u8, line[name_end..], " \t");
            if (after_name.len == 0) continue;
            if (std.mem.startsWith(u8, after_name, "?:")) continue;
            if (after_name[0] != ':') continue;
            const member_type_text = std.mem.trim(u8, after_name[1..], " \t\r");
            const name = self.string_interner.intern(line[0..name_end]) catch return error.OutOfMemory;
            const prop_t = if (is_inline_braced_object and member_type_text.len > 0)
                (try self.jsDocTypeTextToType(self.source orelse "", member_type_text)) orelse types.Primitive.unknown
            else
                types.Primitive.unknown;
            try members.append(self.gpa, .{
                .name = name,
                .type = prop_t,
                .is_optional = false,
                .is_readonly = false,
                .is_method = false,
            });
        }

        if (members.items.len == 0) return null;
        const obj_t = self.interner.internObjectType(members.items) catch return error.OutOfMemory;
        if (is_inline_braced_object) {
            const inner = std.mem.trim(u8, trimmed_outer[1 .. trimmed_outer.len - 1], " \t\r\n");
            const display = try std.fmt.allocPrint(self.diag_arena.allocator(), "{{ {s}; }}", .{inner});
            try self.registerAliasDisplayText(obj_t, display);
        }
        return obj_t;
    }

    fn jsDocStringIndexerFromTypeText(self: *Checker, type_text: []const u8) ?TypeId {
        _ = self;
        const compact = struct {
            fn containsNeedle(haystack: []const u8, needle: []const u8) bool {
                return std.mem.indexOf(u8, haystack, needle) != null;
            }
        }.containsNeedle;
        if (compact(type_text, "Object.<string,string>") or
            compact(type_text, "Object.<string, string>") or
            compact(type_text, "Object<string,string>") or
            compact(type_text, "Object<string, string>") or
            compact(type_text, "Record<string,string>") or
            compact(type_text, "Record<string, string>"))
        {
            return types.Primitive.string_t;
        }
        if (compact(type_text, "Object.<string,number>") or
            compact(type_text, "Object.<string, number>") or
            compact(type_text, "Object<string,number>") or
            compact(type_text, "Object<string, number>") or
            compact(type_text, "Record<string,number>") or
            compact(type_text, "Record<string, number>"))
        {
            return types.Primitive.number_t;
        }
        return null;
    }

    fn isJsDocIdentStart(c: u8) bool {
        return (c >= 'a' and c <= 'z') or (c >= 'A' and c <= 'Z') or c == '_' or c == '$';
    }

    fn isJsDocIdentChar(c: u8) bool {
        return isJsDocIdentStart(c) or (c >= '0' and c <= '9');
    }

    /// Returns true when `name` is a private-identifier (a leading `#`
    /// followed by a valid identifier body, e.g. `#foo`, `#_bar`).
    /// Used wherever a diagnostic rule applies to both public and
    /// private class members.
    fn isPrivateIdentifierName(name: []const u8) bool {
        if (name.len < 2 or name[0] != '#') return false;
        return isJsIdentifier(name[1..]);
    }

    /// Returns true when `name` is a valid ECMAScript identifier
    /// (ASCII subset that covers everything tsc renders unquoted in
    /// diagnostics like `Property 'X' is missing in type ...`).
    fn isJsIdentifier(name: []const u8) bool {
        if (name.len == 0) return false;
        if (!isJsDocIdentStart(name[0])) return false;
        var i: usize = 1;
        while (i < name.len) : (i += 1) {
            if (!isJsDocIdentChar(name[i])) return false;
        }
        return true;
    }

    fn isAllDigits(name: []const u8) bool {
        if (name.len == 0) return false;
        for (name) |c| {
            if (c < '0' or c > '9') return false;
        }
        return true;
    }

    fn checkRepeatedVarDeclaration(self: *Checker, node: NodeId, final_type: TypeId) CheckError!void {
        if (self.hir.kindOf(node) != .var_decl) return;
        const v = hir_mod.varDeclOf(self.hir, node);
        if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) return;
        if (final_type == types.Primitive.none) return;
        const id = hir_mod.identifierOf(self.hir, v.name);
        // `var` bindings hoist to the enclosing function-like (or
        // module / namespace / source-file) scope, so we walk past
        // intervening block/if/for/while/switch/try statements when
        // selecting the dedup key. Without this, sibling `var x`
        // declarations in distinct then/else blocks (and other
        // statement bodies) failed to flag TS2403 because their
        // parentOf() was the block — not the hoist scope. See
        // typeGuardOfFormTypeOfEqualEqualHasNoEffect.ts and the rest
        // of the typeGuards conformance cluster.
        const scope = self.enclosingVarDeclScope(node);
        if (scope == hir_mod.none_node_id) return;
        const key: VarDeclKey = .{
            .scope = scope,
            .name = id.name,
            .virtual_section_start = self.virtualSectionStartForNode(node),
        };
        const has_annotation = v.type_annotation != hir_mod.none_node_id;
        if (self.var_decl_types.get(key)) |prior| {
            const prior_explicit = self.var_decl_explicit.get(key) orelse false;
            if (final_type == types.Primitive.any and (!has_annotation or self.varDeclAnnotationIsQualifiedName(v.type_annotation))) return;
            if (prior == types.Primitive.any and !prior_explicit and has_annotation) return;
            // Historically we bailed when neither declaration had an
            // explicit annotation (unless the prior was enum-nominal).
            // Upstream tsc emits TS2403 whenever the inferred types
            // disagree under control-flow narrowing — e.g. sibling
            // `var r1 = strOrNum` declarations in different then/else
            // branches that narrow to `string` / `number`. The
            // compatibility check below already handles the common
            // `var x = 1; var x = 2;` case (both widen to `number` →
            // identical → no diag), so unconditionally falling through
            // is safe and unlocks the typeGuards conformance cluster.
            const compatible = blk: {
                if (self.isThisTypeParameter(prior) or self.isThisTypeParameter(final_type)) break :blk false;
                if (self.typeContainsUnknown(final_type)) break :blk true;
                if ((prior == types.Primitive.any or final_type == types.Primitive.any) and prior != final_type) break :blk false;
                if (self.engine.isIdenticalTo(prior, final_type) catch true) break :blk true;
                if (self.exactlyOneTypeIsUnion(prior, final_type)) break :blk false;
                break :blk (self.engine.isAssignableTo(prior, final_type) catch true) and
                    (self.engine.isAssignableTo(final_type, prior) catch true);
            };
            const namespace_fn_static_name = self.varInitNamespaceMergedFunctionName(node);
            const forced_namespace_fn_static_mismatch = namespace_fn_static_name != null and prior_explicit;
            if (!compatible) {
                const name = self.string_interner.get(id.name);
                // Suppress TS2403 when this variable already has a
                // TS2502 (`'X' is referenced directly or indirectly in
                // its own type annotation.`) emitted in this run —
                // mirrors upstream tsc which emits only the more
                // fundamental TS2502 for recursive `typeof` chains
                // like `var f: typeof g; var g: typeof f;`. See
                // `recursiveTypesWithTypeof.ts`.
                if (self.varNameHasSelfReferencedTypeAnnotation(name)) return;
                const msg = try self.formatSubsequentVarTypeMismatch(name, prior, final_type);
                try self.diagnostics.append(self.gpa, .{
                    .node = v.name,
                    .code = TsCodes.subsequent_var_type_mismatch,
                    .message = msg,
                });
            } else if (forced_namespace_fn_static_mismatch) {
                const name = self.string_interner.get(id.name);
                const static_name = namespace_fn_static_name.?;
                const current_text = try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "typeof {s}",
                    .{self.string_interner.get(static_name)},
                );
                const msg = try self.formatSubsequentVarTypeMismatchWithCurrentText(name, prior, current_text);
                try self.diagnostics.append(self.gpa, .{
                    .node = v.name,
                    .code = TsCodes.subsequent_var_type_mismatch,
                    .message = msg,
                });
            }
            return;
        }
        if (!has_annotation and
            final_type != types.Primitive.unknown and
            final_type != types.Primitive.any and
            !self.isThisTypeParameter(final_type) and
            !self.typeIsEnumNominal(final_type)) return;
        try self.var_decl_types.put(self.gpa, key, final_type);
        try self.var_decl_explicit.put(self.gpa, key, has_annotation);
    }

    fn varInitNamespaceMergedFunctionName(self: *Checker, node: NodeId) ?hir_mod.StringId {
        if (self.hir.kindOf(node) != .var_decl) return null;
        const v = hir_mod.varDeclOf(self.hir, node);
        if (v.init == hir_mod.none_node_id or self.hir.kindOf(v.init) != .member_access) return null;
        const m = hir_mod.memberOf(self.hir, v.init);
        if (m.object == hir_mod.none_node_id or self.hir.kindOf(m.object) != .identifier) return null;
        const ns_name = hir_mod.identifierOf(self.hir, m.object).name;
        const member_name = m.name;
        var has_fn = false;
        var has_runtime_namespace = false;
        const root = self.rootBlockFor(node);
        if (root == hir_mod.none_node_id or self.hir.kindOf(root) != .block_stmt) return null;
        for (hir_mod.blockStmts(self.hir, root)) |raw| {
            const ns_node = self.unwrapExportDecl(raw);
            if (self.hir.kindOf(ns_node) != .namespace_decl) continue;
            const ns = hir_mod.namespaceOf(self.hir, ns_node);
            if (ns.name == hir_mod.none_node_id or self.hir.kindOf(ns.name) != .identifier) continue;
            if (hir_mod.identifierOf(self.hir, ns.name).name != ns_name) continue;
            for (hir_mod.namespaceBody(self.hir, ns_node)) |member_raw| {
                if (self.hir.kindOf(member_raw) != .export_decl) continue;
                const member_node = self.unwrapExportDecl(member_raw);
                const decl_name = self.declarationName(member_node) orelse continue;
                if (decl_name != member_name) continue;
                switch (self.hir.kindOf(member_node)) {
                    .fn_decl, .fn_expr => has_fn = true,
                    .namespace_decl => {
                        if (self.namespaceHasRuntimeValue(member_node)) has_runtime_namespace = true;
                    },
                    else => {},
                }
            }
        }
        return if (has_fn and has_runtime_namespace) member_name else null;
    }

    /// Walk up the parent chain past control-flow statements
    /// (block / if / for / while / do-while / switch / try) until
    /// we hit a function-like, namespace/module, or source-file
    /// boundary. Matches `var` hoist semantics so two `var x`
    /// declarations in distinct then/else blocks dedup to the same
    /// key. Returns the immediate parent when no such boundary is
    /// reachable.
    fn enclosingVarDeclScope(self: *Checker, node: NodeId) NodeId {
        var cur = self.hir.parentOf(node);
        var last = cur;
        while (cur != hir_mod.none_node_id) {
            last = cur;
            switch (self.hir.kindOf(cur)) {
                .source_file,
                .fn_decl,
                .fn_expr,
                .arrow_fn,
                .namespace_decl,
                .module_decl,
                => return cur,
                .block_stmt,
                .if_stmt,
                .for_stmt,
                .for_in_stmt,
                .for_of_stmt,
                .while_stmt,
                .do_while_stmt,
                .switch_stmt,
                .try_stmt,
                .switch_case,
                => cur = self.hir.parentOf(cur),
                else => return cur,
            }
        }
        return last;
    }

    /// Scan accumulated diagnostics for a TS2502 whose message
    /// references `var_name`. Used to suppress TS2403 follow-on
    /// reports when the variable's own type annotation is already
    /// flagged as recursive — upstream tsc never emits the
    /// subsequent-declaration mismatch on top of TS2502.
    fn varNameHasSelfReferencedTypeAnnotation(self: *Checker, var_name: []const u8) bool {
        for (self.diagnostics.items) |d| {
            if (d.code != TsCodes.self_referenced_type_annotation) continue;
            // TS2502 message shape: `'<name>' is referenced directly
            // or indirectly in its own type annotation.`
            if (d.message.len < var_name.len + 4) continue;
            if (d.message[0] != '\'') continue;
            if (!std.mem.eql(u8, d.message[1 .. 1 + var_name.len], var_name)) continue;
            if (d.message[1 + var_name.len] != '\'') continue;
            return true;
        }
        return false;
    }

    fn varDeclAnnotationIsQualifiedName(self: *Checker, type_annotation: NodeId) bool {
        if (type_annotation == hir_mod.none_node_id or self.hir.kindOf(type_annotation) != .type_ref) return false;
        return hir_mod.typeRefOf(self.hir, type_annotation).qualifier_len != 0;
    }

    /// TS2403: format the message body. When both `prior` and `current`
    /// have a renderable simple type name (primitive, named class /
    /// interface, enum nominal, or literal), match upstream tsc
    /// verbatim — including the leading double-space after the period
    /// (`type.  Variable`). Otherwise fall back to the shorter
    /// conflicting-type form so we never half-render.
    fn formatSubsequentVarTypeMismatch(self: *Checker, name: []const u8, prior: TypeId, current: TypeId) ![]const u8 {
        // Prefer the simple primitive/enum/named-type renderer; fall
        // back to the richer `allocSimpleTypeName` to also pick up
        // tuple shapes (`[number]`, `[number, number]`) so fixtures
        // like `strictTupleLength.ts(11,5)` get the full upstream
        // wording rather than the conflicting-type fallback. Finally,
        // try `allocObjectTypeShape` so object-literal / union
        // mismatches (e.g. `spreadUnion2.ts` `{ a: number } | {}` vs
        // `{ a?: number | undefined; }`) render with the explicit
        // shape instead of the terse `conflicting type` fallback.
        const prior_text_opt = (try self.simpleDiagnosticTypeName(prior)) orelse
            (try self.allocSimpleTypeName(prior)) orelse
            (try self.allocObjectTypeShape(prior));
        const current_text_opt = (try self.simpleDiagnosticTypeName(current)) orelse
            (try self.allocSimpleTypeName(current)) orelse
            (try self.allocObjectTypeShape(current));
        if (prior_text_opt) |prior_text| {
            if (current_text_opt) |current_text| {
                return try std.fmt.allocPrint(
                    self.diag_arena.allocator(),
                    "Subsequent variable declarations must have the same type.  Variable '{s}' must be of type '{s}', but here has type '{s}'.",
                    .{ name, prior_text, current_text },
                );
            }
        }
        return try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Subsequent variable declarations must have the same type. Variable '{s}' has a conflicting type.",
            .{name},
        );
    }

    fn formatSubsequentVarTypeMismatchWithCurrentText(self: *Checker, name: []const u8, prior: TypeId, current_text: []const u8) ![]const u8 {
        const prior_text_opt = (try self.simpleDiagnosticTypeName(prior)) orelse
            (try self.allocSimpleTypeName(prior)) orelse
            (try self.allocObjectTypeShape(prior));
        if (prior_text_opt) |prior_text| {
            return try std.fmt.allocPrint(
                self.diag_arena.allocator(),
                "Subsequent variable declarations must have the same type.  Variable '{s}' must be of type '{s}', but here has type '{s}'.",
                .{ name, prior_text, current_text },
            );
        }
        return try std.fmt.allocPrint(
            self.diag_arena.allocator(),
            "Subsequent variable declarations must have the same type. Variable '{s}' has a conflicting type.",
            .{name},
        );
    }

    fn checkRepeatedObjectRestVarBinding(
        self: *Checker,
        pattern_node: NodeId,
        name_node: NodeId,
        name: hir_mod.StringId,
        final_type: TypeId,
    ) CheckError!void {
        const decl = self.hir.parentOf(pattern_node);
        if (decl == hir_mod.none_node_id or self.hir.kindOf(decl) != .var_decl) return;
        const scope = self.hir.parentOf(decl);
        if (scope == hir_mod.none_node_id) return;
        const prior = self.previousVarDeclTypeInScope(scope, decl, name) orelse return;
        if (self.repeatedVarTypesCompatible(prior, final_type)) return;
        const name_text = self.string_interner.get(name);
        const msg = try self.formatSubsequentVarTypeMismatch(name_text, prior, final_type);
        try self.diagnostics.append(self.gpa, .{
            .node = name_node,
            .code = TsCodes.subsequent_var_type_mismatch,
            .message = msg,
        });
    }

    fn previousVarDeclTypeInScope(self: *Checker, scope: NodeId, before_decl: NodeId, name: hir_mod.StringId) ?TypeId {
        const stmts: []const NodeId = switch (self.hir.kindOf(scope)) {
            .block_stmt => hir_mod.blockStmts(self.hir, scope),
            .namespace_decl => hir_mod.namespaceBody(self.hir, scope),
            else => return null,
        };
        for (stmts) |stmt| {
            if (stmt == before_decl) return null;
            const decl = if (self.hir.kindOf(stmt) == .export_decl) hir_mod.exportOf(self.hir, stmt).decl else stmt;
            if (decl == hir_mod.none_node_id) continue;
            const dk = self.hir.kindOf(decl);
            if (dk != .var_decl and dk != .let_decl and dk != .const_decl) continue;
            const v = hir_mod.varDeclOf(self.hir, decl);
            if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) continue;
            const id = hir_mod.identifierOf(self.hir, v.name);
            if (id.name != name) continue;
            const t = self.hir.typeOf(decl);
            if (t != types.Primitive.none) return t;
        }
        return null;
    }

    fn repeatedVarTypesCompatible(self: *Checker, prior: TypeId, final_type: TypeId) bool {
        if (self.isThisTypeParameter(prior) or self.isThisTypeParameter(final_type)) return false;
        if (self.typeContainsUnknown(final_type)) return true;
        if ((prior == types.Primitive.any or final_type == types.Primitive.any) and prior != final_type) return false;
        if (self.engine.isIdenticalTo(prior, final_type) catch true) return true;
        if (self.exactlyOneTypeIsUnion(prior, final_type)) return false;
        return (self.engine.isAssignableTo(prior, final_type) catch true) and
            (self.engine.isAssignableTo(final_type, prior) catch true);
    }

    fn exactlyOneTypeIsUnion(self: *Checker, a: TypeId, b: TypeId) bool {
        return self.typeIsUnion(a) != self.typeIsUnion(b);
    }

    fn typeIsUnion(self: *Checker, t: TypeId) bool {
        if (t < types.Primitive.first_dynamic or t >= self.interner.pool.typeCount()) return false;
        return self.interner.pool.flagsOf(t).is_union;
    }

    fn typeIsEnumNominal(self: *Checker, t: TypeId) bool {
        return self.enumNameFromNominal(t) != null;
    }

    fn enumNameFromNominal(self: *Checker, t: TypeId) ?hir_mod.StringId {
        if (t >= self.interner.pool.typeCount()) return null;
        const flags = self.interner.pool.flagsOf(t);
        if (!flags.is_intersection) return null;
        if (flags.is_union) return null;
        const payload_idx = self.interner.pool.payloadOf(t);
        if (payload_idx >= self.interner.pool.intersection_payloads.items.len) return null;
        var saw_number = false;
        var enum_name: ?hir_mod.StringId = null;
        for (self.interner.intersectionMembers(t)) |member| {
            if (member == types.Primitive.number_t) {
                saw_number = true;
                continue;
            }
            if (member >= self.interner.pool.typeCount()) continue;
            if (!self.interner.pool.flagsOf(member).is_object_type) continue;
            for (self.interner.objectMembers(member)) |om| {
                const name = self.string_interner.getOptional(om.name) orelse continue;
                if (std.mem.startsWith(u8, name, "__enum:")) {
                    enum_name = self.string_interner.intern(name["__enum:".len..]) catch return null;
                    break;
                }
            }
        }
        return if (saw_number) enum_name else null;
    }

    fn enumValueAssignableToTarget(self: *Checker, enum_name: hir_mod.StringId, target_t: TypeId) bool {
        if (target_t == types.Primitive.any or
            target_t == types.Primitive.unknown or
            target_t == types.Primitive.number_t or
            target_t == types.Primitive.object_t)
        {
            return true;
        }
        if (self.enumNameFromNominal(target_t)) |target_enum| {
            return target_enum == enum_name;
        }
        if (self.namedTypeForId(target_t)) |target_name| {
            const raw = self.string_interner.get(target_name);
            if (std.mem.eql(u8, raw, "Object") or std.mem.eql(u8, raw, "Number")) return true;
        }
        if (target_t >= types.Primitive.first_dynamic and target_t < self.interner.pool.typeCount()) {
            const flags = self.interner.pool.flagsOf(target_t);
            if (flags.is_object_type and self.interner.objectMembers(target_t).len == 0 and
                self.interner.objectStringIndex(target_t) == types.Primitive.none and
                self.interner.objectNumberIndex(target_t) == types.Primitive.none)
            {
                return true;
            }
        }
        return false;
    }

    fn appendNumericEnumRecordMembers(
        self: *Checker,
        enum_name: hir_mod.StringId,
        value_t: TypeId,
        out: *std.ArrayListUnmanaged(types.ObjectMember),
    ) CheckError!void {
        var it = self.enum_member_values.iterator();
        while (it.next()) |entry| {
            if (entry.key_ptr.obj_name != enum_name) continue;
            const value = entry.value_ptr.*;
            const key_text = if (value == @floor(value))
                try std.fmt.allocPrint(self.gpa, "{d}", .{@as(i64, @intFromFloat(value))})
            else
                try std.fmt.allocPrint(self.gpa, "{d}", .{value});
            defer self.gpa.free(key_text);
            const key_name = self.string_interner.intern(key_text) catch return error.OutOfMemory;
            try out.append(self.gpa, .{
                .name = key_name,
                .type = value_t,
                .is_optional = false,
                .is_readonly = false,
                .is_method = false,
            });
        }
    }

    fn isThisTypeParameter(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (!flags.is_type_parameter) return false;
        const payload_idx = self.interner.pool.payloadOf(t);
        if (payload_idx >= self.interner.pool.type_parameter_payloads.items.len) return false;
        const tp = self.interner.pool.type_parameter_payloads.items[payload_idx];
        const name = tp.name;
        return std.mem.eql(u8, self.string_interner.get(name), "this");
    }

    fn freshThisTypeParameter(self: *Checker, name: hir_mod.StringId) CheckError!TypeId {
        return self.interner.internFreshTypeParameterWithFlags(
            name,
            types.Primitive.unknown,
            types.Primitive.none,
            .bivariant,
            false,
        ) catch return error.OutOfMemory;
    }

    fn typeContainsUnknown(self: *Checker, t: TypeId) bool {
        if (t == types.Primitive.unknown) return true;
        if (t < types.Primitive.first_dynamic) return false;
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |m| if (self.typeContainsUnknown(m)) return true;
            return false;
        }
        if (flags.is_intersection) {
            for (self.interner.intersectionMembers(t)) |m| if (self.typeContainsUnknown(m)) return true;
            return false;
        }
        if (flags.is_object_type) {
            for (self.interner.objectMembers(t)) |m| if (self.typeContainsUnknown(m.type)) return true;
            const string_idx = self.interner.objectStringIndex(t);
            if (string_idx != types.Primitive.none and self.typeContainsUnknown(string_idx)) return true;
            const number_idx = self.interner.objectNumberIndex(t);
            if (number_idx != types.Primitive.none and self.typeContainsUnknown(number_idx)) return true;
            return false;
        }
        if (flags.is_signature) {
            for (self.interner.signatureParams(t)) |p| if (self.typeContainsUnknown(p)) return true;
            if (self.interner.signatureReturn(t)) |r| if (self.typeContainsUnknown(r)) return true;
            return false;
        }
        if (flags.is_tuple) {
            const payload_idx = self.interner.pool.payloadOf(t);
            if (payload_idx >= self.interner.pool.tuple_payloads.items.len) return false;
            const payload = self.interner.pool.tuple_payloads.items[payload_idx];
            const elems = self.interner.pool.tuple_element_pool.items[payload.elements_start .. payload.elements_start + payload.elements_len];
            for (elems) |elem| if (self.typeContainsUnknown(elem.type)) return true;
            return false;
        }
        return false;
    }

    fn isThisParameter(self: *Checker, param_node: NodeId) bool {
        if (self.hir.kindOf(param_node) != .parameter) return false;
        const p = hir_mod.parameterOf(self.hir, param_node);
        if (p.name == hir_mod.none_node_id or self.hir.kindOf(p.name) != .identifier) return false;
        const id = hir_mod.identifierOf(self.hir, p.name);
        return std.mem.eql(u8, self.string_interner.get(id.name), "this");
    }

    fn broadObjectPrototypeMember(self: *Checker, name: hir_mod.StringId) CheckError!?TypeId {
        const text = self.string_interner.get(name);
        if (std.mem.eql(u8, text, "toString")) {
            return self.interner.internSignature(&.{}, types.Primitive.string_t, false) catch return error.OutOfMemory;
        }
        if (std.mem.eql(u8, text, "valueOf")) {
            return self.interner.internSignature(&.{}, types.Primitive.object_t, false) catch return error.OutOfMemory;
        }
        if (std.mem.eql(u8, text, "hasOwnProperty") or
            std.mem.eql(u8, text, "propertyIsEnumerable"))
        {
            return self.interner.internSignature(&.{types.Primitive.string_t}, types.Primitive.boolean_t, false) catch return error.OutOfMemory;
        }
        return null;
    }

    /// True when `t` is the instance type produced for a `class X { … }`
    /// declaration (i.e. is registered in `class_name_by_instance`).
    /// Used as a gate for inheriting `Object.prototype` members
    /// (`toString`, `hasOwnProperty`, …) so plain object literals
    /// stay strict but class instances pick up the inherited shape.
    fn typeIsClassInstance(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        return self.class_name_by_instance.contains(t);
    }

    fn declaredInterfaceMember(self: *Checker, interface_name: []const u8, member_name: hir_mod.StringId) CheckError!?TypeId {
        const id = self.string_interner.intern(interface_name) catch return error.OutOfMemory;
        const iface_t = self.type_names.get(id) orelse return null;
        return self.lookupObjectMember(iface_t, member_name);
    }

    fn primitivePrototypeMember(self: *Checker, receiver_t: TypeId, member_name: hir_mod.StringId) CheckError!?TypeId {
        if (self.typeHasStringPrimitivePart(receiver_t)) {
            if (try self.declaredInterfaceMember("String", member_name)) |t| return t;
            if (lib.stringProto(&self.lib_cache, self.interner, self.string_interner)) |proto| {
                if (self.interner.objectMember(proto, member_name)) |t| return t;
            } else |_| {}
            if (try self.broadObjectPrototypeMember(member_name)) |t| return t;
            return null;
        }
        if (self.typeHasNumericPrimitivePart(receiver_t)) {
            if (try self.declaredInterfaceMember("Number", member_name)) |t| return t;
            if (lib.numberProto(&self.lib_cache, self.interner, self.string_interner)) |proto| {
                if (self.interner.objectMember(proto, member_name)) |t| return t;
            } else |_| {}
            if (try self.broadObjectPrototypeMember(member_name)) |t| return t;
            return null;
        }
        return null;
    }

    fn lookupObjectMember(self: *Checker, obj_t: TypeId, name: hir_mod.StringId) CheckError!?TypeId {
        const flags = self.interner.pool.flagsOf(obj_t);
        if (flags.is_type_parameter) {
            const constraint = self.typeParameterConstraint(obj_t) orelse return null;
            if (constraint == obj_t) return null;
            return try self.lookupObjectMember(constraint, name);
        }
        if (flags.is_union) {
            const members = self.interner.unionMembers(obj_t);
            var resolved: std.ArrayListUnmanaged(TypeId) = .empty;
            defer resolved.deinit(self.gpa);
            for (members) |member_t| {
                if (self.interner.objectMember(member_t, name)) |t| {
                    try resolved.append(self.gpa, t);
                } else {
                    return null;
                }
            }
            if (resolved.items.len == 0) return null;
            return self.interner.internUnion(resolved.items) catch return error.OutOfMemory;
        }
        if (flags.is_intersection) {
            const members = self.interner.intersectionMembers(obj_t);
            var resolved: std.ArrayListUnmanaged(TypeId) = .empty;
            defer resolved.deinit(self.gpa);
            for (members) |member_t| {
                if (try self.lookupObjectMember(member_t, name)) |t| {
                    try resolved.append(self.gpa, t);
                }
            }
            if (resolved.items.len == 0) return null;
            if (resolved.items.len == 1) return resolved.items[0];
            return self.interner.internIntersection(resolved.items) catch return error.OutOfMemory;
        }
        return self.interner.objectMember(obj_t, name);
    }

    fn objectHasCallOrConstructSignature(self: *Checker, obj_t: TypeId) bool {
        if (obj_t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(obj_t);
        if (flags.is_signature) return true;
        if (!flags.is_object_type) return false;
        const call_id = self.string_interner.intern("__call") catch return false;
        const construct_id = self.string_interner.intern("__construct") catch return false;
        for (self.interner.objectMembers(obj_t)) |member| {
            if (member.name != call_id and member.name != construct_id) continue;
            if (self.interner.isSignature(member.type)) return true;
        }
        return false;
    }

    /// Recursively check whether `t` is a union (or intersection)
    /// whose every constituent carries a call signature. Used to
    /// suppress TS2349 on `(typeof f1 | typeof f2)("")` style call
    /// sites — tsc treats the union as callable when every branch
    /// is. Returns `false` for bare callables; the caller already
    /// has dedicated paths for those.
    ///
    /// For intersections, additionally guards against the case where
    /// a shared property's constituent types are mutually disjoint
    /// and collapse to `never` (e.g. `{ (x): number, a: "" } & { a:
    /// number }`). tsc reduces such an intersection to `never` and
    /// emits TS2349 with "Type 'never' has no call signatures" —
    /// see `neverIntersectionNotCallable.errors.txt`.
    fn typeUnionAllCallable(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_union) {
            const members = self.interner.unionMembers(t);
            if (members.len == 0) return false;
            for (members) |m| {
                if (!self.objectHasCallOrConstructSignature(m) and !self.typeUnionAllCallable(m)) return false;
            }
            return true;
        }
        if (flags.is_intersection) {
            if (self.intersectionHasDisjointSharedProperty(t)) return false;
            for (self.interner.intersectionMembers(t)) |m| {
                if (self.objectHasCallOrConstructSignature(m)) return true;
                if (self.typeUnionAllCallable(m)) return true;
            }
            return false;
        }
        return false;
    }

    /// Returns `true` when intersection `t` has a property name that
    /// appears in two or more object constituents with types that
    /// are mutually non-assignable in both directions (i.e. the
    /// property's intersected type collapses to `never`). Mirrors
    /// tsc's reduction of `{ a: "" } & { a: number }` whose `a`
    /// becomes `never`, which in turn makes the intersection itself
    /// uncallable.
    fn intersectionHasDisjointSharedProperty(self: *Checker, t: TypeId) bool {
        const members = self.interner.intersectionMembers(t);
        if (members.len < 2) return false;
        for (members, 0..) |a, ai| {
            if (a >= self.interner.pool.typeCount()) continue;
            if (!self.interner.pool.flagsOf(a).is_object_type) continue;
            // Snapshot a's members before the inner `heritageAssignable()`
            // calls can grow object_member_pool and invalidate the borrowed
            // slice (HIGH-RISK dangling-slice fix per
            // DANGLING_SLICE_AUDIT_2026-05-19.md).
            const a_members = self.gpa.dupe(types.ObjectMember, self.interner.objectMembers(a)) catch return false;
            defer self.gpa.free(a_members);
            for (a_members) |a_member| {
                for (members[ai + 1 ..]) |b| {
                    if (b >= self.interner.pool.typeCount()) continue;
                    if (!self.interner.pool.flagsOf(b).is_object_type) continue;
                    const b_t = self.interner.objectMember(b, a_member.name) orelse continue;
                    if (a_member.type == b_t) continue;
                    if (a_member.type == types.Primitive.any or a_member.type == types.Primitive.unknown) continue;
                    if (b_t == types.Primitive.any or b_t == types.Primitive.unknown) continue;
                    const ab = self.heritageAssignable(a_member.type, b_t) catch true;
                    const ba = self.heritageAssignable(b_t, a_member.type) catch true;
                    if (!ab and !ba) return true;
                }
            }
        }
        return false;
    }

    /// True when the callable shape exposes only construct signatures
    /// (e.g. `new () => string` or `{ new (): T }`) and no callable
    /// signatures. Mirrors upstream TS so TS2348 (with the
    /// "Did you mean to include 'new'?" hint) fires in place of the
    /// generic TS2349.
    /// True when the call expression `node` was parsed from a
    /// tagged-template literal (`tag\`...\``). The parser desugars
    /// these into `call(tag, [stringsArr, ...values])`, losing the
    /// distinction at HIR level — but the source span still contains
    /// the backtick. We detect that by scanning the bytes between the
    /// callee's end and the call's end for a leading backtick after
    /// whitespace. Used to suppress the "Did you mean 'new'?" hint
    /// (TS2348) — tagged-template calls cannot be expressed with `new`
    /// and tsc emits the bare TS2349 "not callable" instead.
    fn callExprIsTaggedTemplate(self: *Checker, node: NodeId) bool {
        const src = self.source orelse return false;
        const k = self.hir.kindOf(node);
        if (k != .call_expr) return false;
        const c = hir_mod.callOf(self.hir, node);
        if (c.callee == hir_mod.none_node_id) return false;
        const callee_end = self.hir.spanOf(c.callee).end;
        const call_end = self.hir.spanOf(node).end;
        if (callee_end >= call_end or call_end > src.len) return false;
        var i: usize = callee_end;
        while (i < call_end) : (i += 1) {
            const ch = src[i];
            if (ch == ' ' or ch == '\t' or ch == '\n' or ch == '\r') continue;
            if (ch == '<') {
                var depth: usize = 1;
                i += 1;
                while (i < call_end) : (i += 1) {
                    const inner = src[i];
                    if (inner == '<') {
                        depth += 1;
                    } else if (inner == '>') {
                        depth -= 1;
                        if (depth == 0) break;
                    }
                }
                continue;
            }
            return ch == '`';
        }
        return false;
    }

    fn callableObjectHasOnlyConstructSignatures(self: *Checker, obj_t: TypeId) bool {
        if (obj_t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(obj_t);
        if (flags.is_signature and self.interner.isSignature(obj_t)) {
            const sig_payload_idx = self.interner.pool.payloadOf(obj_t);
            if (sig_payload_idx >= self.interner.pool.signature_payloads.items.len) return false;
            return self.interner.pool.signature_payloads.items[sig_payload_idx].is_construct;
        }
        if (!flags.is_object_type) return false;
        const call_id = self.string_interner.intern("__call") catch return false;
        const construct_id = self.string_interner.intern("__construct") catch return false;
        var saw_construct = false;
        for (self.interner.objectMembers(obj_t)) |member| {
            if (member.name == call_id and self.interner.isSignature(member.type)) return false;
            if (member.name == construct_id and self.interner.isSignature(member.type)) saw_construct = true;
        }
        return saw_construct;
    }

    /// True when `t` is a union whose every member is itself callable
    /// (a function signature, or an object type carrying a `__call`
    /// member). Used by the call-expression handler to suppress the
    /// spurious TS2349 ("This expression is not callable") on
    /// `(F1 | F2)(...)` call sites — the exact-mode resolver doesn't
    /// model union-of-callable reduction yet, but the call IS valid
    /// upstream and should not error. Returns false for non-unions
    /// and for unions with any non-callable member.
    fn unionAllMembersCallable(self: *Checker, t: TypeId) bool {
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (!flags.is_union) return false;
        const members = self.interner.unionMembers(t);
        if (members.len == 0) return false;
        const call_id = self.string_interner.intern("__call") catch return false;
        for (members) |m| {
            if (m >= self.interner.pool.typeCount()) return false;
            const mf = self.interner.pool.flagsOf(m);
            if (mf.is_signature and self.interner.isSignature(m)) {
                const sig_payload_idx = self.interner.pool.payloadOf(m);
                if (sig_payload_idx >= self.interner.pool.signature_payloads.items.len) return false;
                // Construct-only signatures (`new () => T`) aren't
                // callable; require a call signature.
                if (self.interner.pool.signature_payloads.items[sig_payload_idx].is_construct) return false;
                continue;
            }
            if (!mf.is_object_type) return false;
            var saw_call = false;
            for (self.interner.objectMembers(m)) |om| {
                if (om.name == call_id and self.interner.isSignature(om.type)) {
                    const sig_payload_idx = self.interner.pool.payloadOf(om.type);
                    if (sig_payload_idx >= self.interner.pool.signature_payloads.items.len) continue;
                    if (self.interner.pool.signature_payloads.items[sig_payload_idx].is_construct) continue;
                    saw_call = true;
                    break;
                }
            }
            if (!saw_call) return false;
        }
        return true;
    }

    fn functionInterfaceMemberForCallableObject(self: *Checker, obj_t: TypeId, name: hir_mod.StringId) CheckError!?TypeId {
        if (!self.objectHasCallOrConstructSignature(obj_t)) return null;
        const function_name = self.string_interner.intern("Function") catch return error.OutOfMemory;
        if (self.type_names.get(function_name)) |function_t| {
            if (try self.lookupObjectMember(function_t, name)) |member_t| return member_t;
            const string_idx = self.interner.objectStringIndex(function_t);
            return if (string_idx != types.Primitive.none) string_idx else null;
        }
        // Hardcoded fallback for fixtures without a real `lib.d.ts`
        // backing — every Function-prototype member that upstream tsc
        // resolves to here, typed as `any`. Without this, simple
        // `i.apply` / `b.arguments` lookups on callable / constructable
        // object types would spuriously fire TS2339. Mirrors
        // `objectTypeWithCallSignatureAppearsToBeFunctionType` and
        // `objectTypeWithCallSignatureHidingMembersOfFunction`.
        const raw = self.string_interner.get(name);
        const function_proto_members = [_][]const u8{
            "apply",     "call",        "bind",   "toString",
            "arguments", "caller",      "length", "name",
            "prototype", "constructor",
        };
        for (function_proto_members) |m| {
            if (std.mem.eql(u8, raw, m)) return types.Primitive.any;
        }
        return null;
    }

    fn functionInterfaceStringIndexForCallableObject(self: *Checker, obj_t: TypeId) CheckError!?TypeId {
        if (!self.objectHasCallOrConstructSignature(obj_t)) return null;
        const function_name = self.string_interner.intern("Function") catch return error.OutOfMemory;
        const function_t = self.type_names.get(function_name) orelse return null;
        const string_idx = self.interner.objectStringIndex(function_t);
        return if (string_idx != types.Primitive.none) string_idx else null;
    }

    fn typeOfDottedValueReference(self: *Checker, raw: []const u8, at_node: NodeId) CheckError!?TypeId {
        var parts = std.mem.splitScalar(u8, raw, '.');
        const root_raw = parts.next() orelse return null;
        if (root_raw.len == 0) return null;
        const root_name = self.string_interner.intern(root_raw) catch return error.OutOfMemory;
        var current = self.lookupNarrow(root_name) orelse (try self.typeOfVisibleNameNoDiag(at_node, root_name)) orelse {
            if (std.mem.eql(u8, root_raw, "this")) return types.Primitive.any;
            return null;
        };
        var root_for_narrow: ?hir_mod.StringId = root_name;
        while (parts.next()) |part| {
            if (part.len == 0) return null;
            const prop_name = self.string_interner.intern(part) catch return error.OutOfMemory;
            if (root_for_narrow) |obj_name| {
                if (std.mem.eql(u8, part, "prototype")) {
                    if (self.class_instance_types.get(obj_name)) |instance_t| {
                        current = instance_t;
                        root_for_narrow = null;
                        continue;
                    }
                }
            }
            if (root_for_narrow) |obj_name| {
                const key: MemberKey = .{ .obj_name = obj_name, .prop_name = prop_name };
                if (self.lookupMemberNarrow(key)) |nt| {
                    current = nt;
                    root_for_narrow = null;
                    continue;
                }
            }
            current = (try self.lookupObjectMember(current, prop_name)) orelse blk: {
                if (std.mem.eql(u8, root_raw, "this") and self.class_name_by_instance.get(current) != null) {
                    if (try self.allocPropertyMissingTargetTypeName(current)) |target_text| {
                        const msg = try std.fmt.allocPrint(
                            self.diag_arena.allocator(),
                            "Property '{s}' does not exist on type '{s}'.",
                            .{ part, target_text },
                        );
                        try self.diagnostics.append(self.gpa, .{
                            .node = at_node,
                            .pos = self.qualifiedTypeRefLeafNamePos(at_node),
                            .code = TsCodes.property_does_not_exist,
                            .message = msg,
                        });
                        break :blk types.Primitive.any;
                    }
                }
                return null;
            };
            root_for_narrow = null;
        }
        return current;
    }

    fn typeOfVisibleNameNoDiag(self: *Checker, at_node: NodeId, name: hir_mod.StringId) CheckError!?TypeId {
        if (self.lookupNarrow(name)) |t| return t;
        var cur: hir_mod.NodeId = self.hir.parentOf(at_node);
        while (cur != hir_mod.none_node_id) : (cur = self.hir.parentOf(cur)) {
            const k = self.hir.kindOf(cur);
            if (k == .fn_decl or k == .fn_expr or k == .arrow_fn) {
                for (hir_mod.fnParams(self.hir, cur)) |p| {
                    if (self.hir.kindOf(p) != .parameter) continue;
                    const pp = hir_mod.parameterOf(self.hir, p);
                    if (pp.name == hir_mod.none_node_id or self.hir.kindOf(pp.name) != .identifier) continue;
                    const pid = hir_mod.identifierOf(self.hir, pp.name);
                    if (pid.name == name and self.hir.typeOf(p) != types.Primitive.none) return self.hir.typeOf(p);
                }
            }
            if (k == .block_stmt or k == .namespace_decl) {
                const stmts = if (k == .block_stmt)
                    hir_mod.blockStmts(self.hir, cur)
                else
                    hir_mod.namespaceBody(self.hir, cur);
                for (stmts) |raw_s| {
                    // `export var`, `export function`, `export class`,
                    // `export import Z = M` etc. wrap the inner decl in
                    // an `.export_decl`. Unwrap so the visibility walk
                    // sees the bound identifier directly — without this
                    // step `typeof Z` for an `export import Z = M` would
                    // miss the binding and emit a spurious TS2304.
                    const s = self.unwrapExportDecl(raw_s);
                    const sk = self.hir.kindOf(s);
                    if (sk == .var_decl or sk == .let_decl or sk == .const_decl) {
                        const v = hir_mod.varDeclOf(self.hir, s);
                        if (v.name == hir_mod.none_node_id or self.hir.kindOf(v.name) != .identifier) continue;
                        const vid = hir_mod.identifierOf(self.hir, v.name);
                        if (vid.name != name) continue;
                        const existing = self.hir.typeOf(s);
                        if (existing != types.Primitive.none) return existing;
                        if (v.type_annotation != hir_mod.none_node_id) {
                            const declared_t = self.lowerValueTypeAnnotation(vid.name, v.type_annotation) catch types.Primitive.any;
                            self.hir.setType(s, declared_t);
                            self.hir.setType(v.name, declared_t);
                            return declared_t;
                        }
                    } else if (sk == .fn_decl or sk == .fn_expr) {
                        const fp = hir_mod.fnDeclOf(self.hir, s);
                        if (fp.name == hir_mod.none_node_id or self.hir.kindOf(fp.name) != .identifier) continue;
                        const fid = hir_mod.identifierOf(self.hir, fp.name);
                        if (fid.name == name and self.hir.typeOf(s) != types.Primitive.none) return self.hir.typeOf(s);
                    } else if (sk == .class_decl or sk == .class_expr) {
                        const cp = hir_mod.classOf(self.hir, s);
                        if (cp.name == hir_mod.none_node_id or self.hir.kindOf(cp.name) != .identifier) continue;
                        const cid = hir_mod.identifierOf(self.hir, cp.name);
                        if (cid.name == name) {
                            if (self.class_static_types.get(name)) |static_t| return static_t;
                            if (self.hir.typeOf(s) != types.Primitive.none) return self.hir.typeOf(s);
                        }
                    } else if (sk == .import_decl) {
                        if (self.importDeclBindsLocal(s, name)) {
                            if (self.moduleNamespaceTypeForLocalImport(name, at_node) catch null) |ns_t| return ns_t;
                            return types.Primitive.any;
                        }
                    }
                }
            }
        }
        if (self.module) |module| {
            if (module.root.lookup(name)) |sym| {
                if (sym.decls.items.len > 0) {
                    const decl = sym.decls.items[0];
                    if (self.hir.typeOf(decl) != types.Primitive.none) return self.hir.typeOf(decl);
                }
            }
        }
        return null;
    }

    fn predicateTargetIsBroadObject(self: *Checker, target: TypeId) bool {
        _ = self;
        return target == types.Primitive.object_t;
    }

    fn predicateTargetIsFunctionObject(self: *Checker, target: TypeId) bool {
        const function_t = self.lowerBuiltinObjectType("Function") orelse return false;
        return target == function_t;
    }

    fn typeMatchesPredicateTarget(self: *Checker, member: TypeId, target: TypeId) bool {
        if (member == target) return true;
        if (target < self.interner.pool.typeCount() and self.interner.pool.flagsOf(target).is_union) {
            for (self.interner.unionMembers(target)) |target_member| {
                if (self.typeMatchesPredicateTarget(member, target_member)) return true;
            }
            return false;
        }
        if (self.predicateTargetIsBroadObject(target) and self.typeIsObjectLikePredicateMember(member)) return true;
        if (self.predicateTargetIsFunctionObject(target) and self.objectHasCallOrConstructSignature(member)) return true;
        if (self.typeParameterConstraintAssignableTo(member, target)) return true;
        return self.engine.isAssignableTo(member, target) catch false;
    }

    fn typeIsObjectLikePredicateMember(self: *Checker, t: TypeId) bool {
        if (self.typeIsAnyLike(t)) return false;
        const flags = self.interner.pool.flagsOf(t);
        return flags.is_object or
            flags.is_object_type or
            flags.is_signature or
            flags.is_tuple or
            flags.is_intersection;
    }

    fn objectOrNullType(self: *Checker) TypeId {
        return self.interner.internUnion(&.{ types.Primitive.object_t, types.Primitive.null_t }) catch types.Primitive.object_t;
    }

    fn narrowTypeByPredicate(self: *Checker, current: TypeId, target: TypeId) CheckError!TypeId {
        if (current == target or self.typeIsAnyLike(current)) return target;
        if (self.typeIsAnyLike(target)) return current;
        const current_flags = self.interner.pool.flagsOf(current);
        if (current_flags.is_union) {
            var kept: std.ArrayListUnmanaged(TypeId) = .empty;
            defer kept.deinit(self.gpa);
            for (self.interner.unionMembers(current)) |member| {
                const member_flags = self.interner.pool.flagsOf(member);
                if ((member_flags.is_null and !self.typeIncludesNull(target)) or
                    (member_flags.is_undefined and !self.typeIncludesUndefined(target)))
                {
                    continue;
                }
                const member_to_target = self.typeMatchesPredicateTarget(member, target);
                const target_to_member = target == member or (self.engine.isAssignableTo(target, member) catch false);
                if (member_to_target) {
                    try kept.append(self.gpa, member);
                } else if (target_to_member) {
                    if (self.predicateTargetIsFunctionObject(target) and !self.objectHasCallOrConstructSignature(member)) continue;
                    try kept.append(self.gpa, target);
                }
            }
            if (kept.items.len == 0) {
                return self.interner.internIntersection(&.{ current, target }) catch return error.OutOfMemory;
            }
            if (kept.items.len == 1) return kept.items[0];
            return self.interner.internUnion(kept.items) catch return error.OutOfMemory;
        }
        const current_to_target = self.engine.isAssignableTo(current, target) catch false;
        const target_to_current = self.engine.isAssignableTo(target, current) catch false;
        if (current_to_target and !target_to_current) return current;
        if (target_to_current) return target;
        return self.interner.internIntersection(&.{ current, target }) catch return error.OutOfMemory;
    }

    fn subtractTypeByPredicate(self: *Checker, current: TypeId, target: TypeId) CheckError!TypeId {
        if (current == target) return types.Primitive.never;
        const current_flags = self.interner.pool.flagsOf(current);
        if (current_flags.is_union) {
            var kept: std.ArrayListUnmanaged(TypeId) = .empty;
            defer kept.deinit(self.gpa);
            for (self.interner.unionMembers(current)) |member| {
                const remove = self.typeMatchesPredicateTarget(member, target);
                if (!remove) try kept.append(self.gpa, member);
            }
            if (kept.items.len == 0) return types.Primitive.never;
            if (kept.items.len == 1) return kept.items[0];
            return self.interner.internUnion(kept.items) catch return error.OutOfMemory;
        }
        return current;
    }

    fn propertyAllowsDelete(self: *Checker, obj_t: TypeId, name: hir_mod.StringId) bool {
        if (self.typeIsAnyLike(obj_t)) return true;
        const non_null_obj = self.subtractNullUndefined(obj_t) catch obj_t;
        const flags = self.interner.pool.flagsOf(non_null_obj);
        if (flags.is_union) {
            for (self.interner.unionMembers(non_null_obj)) |member_t| {
                if (!self.propertyAllowsDelete(member_t, name)) return false;
            }
            return true;
        }
        if (!flags.is_object_type) return true;
        const info = self.interner.objectMemberInfo(non_null_obj, name) orelse return true;
        return info.is_optional or self.typeIncludesUndefined(info.type);
    }

    fn namespaceMemberAllowsDelete(self: *Checker, object: NodeId, name: hir_mod.StringId, anchor: NodeId) CheckError!?bool {
        if (self.hir.kindOf(object) != .identifier) return null;
        const obj_id = hir_mod.identifierOf(self.hir, object);
        const member_t = (try self.mergedNamespaceValueMemberType(obj_id.name, name, anchor)) orelse return null;
        return self.typeIncludesUndefined(member_t);
    }

    fn deleteOperandAllowed(self: *Checker, operand: NodeId) CheckError!bool {
        return switch (self.hir.kindOf(operand)) {
            .member_access => blk: {
                const m = hir_mod.memberOf(self.hir, operand);
                if (try self.namespaceMemberAllowsDelete(m.object, m.name, operand)) |allowed| break :blk allowed;
                const obj_t = self.hir.typeOf(m.object);
                if (obj_t == types.Primitive.none) break :blk true;
                break :blk self.propertyAllowsDelete(obj_t, m.name);
            },
            .element_access => blk: {
                const e = hir_mod.elementOf(self.hir, operand);
                if (self.hir.kindOf(e.index) != .literal_string) break :blk true;
                const key = hir_mod.literalStringOf(self.hir, e.index).value;
                if (try self.namespaceMemberAllowsDelete(e.object, key, operand)) |allowed| break :blk allowed;
                const obj_t = self.hir.typeOf(e.object);
                if (obj_t == types.Primitive.none) break :blk true;
                break :blk self.propertyAllowsDelete(obj_t, key);
            },
            else => true,
        };
    }

    /// True when the property `name` on `obj_t` is declared read-only
    /// (e.g. `Symbol.iterator`, `String.prototype.length`). Used to
    /// pick TS2704 over TS2790 in the `delete` operand check. Mirrors
    /// `symbolType3.ts(2,8)`. Returns false for any-like types and
    /// for union members where any branch is non-readonly.
    fn propertyIsReadOnly(self: *Checker, obj_t: TypeId, name: hir_mod.StringId) bool {
        if (self.typeIsAnyLike(obj_t)) return false;
        const non_null_obj = self.subtractNullUndefined(obj_t) catch obj_t;
        const flags = self.interner.pool.flagsOf(non_null_obj);
        if (flags.is_union) {
            for (self.interner.unionMembers(non_null_obj)) |member_t| {
                if (!self.propertyIsReadOnly(member_t, name)) return false;
            }
            return true;
        }
        if (!flags.is_object_type) return false;
        const info = self.interner.objectMemberInfo(non_null_obj, name) orelse return false;
        return info.is_readonly;
    }

    fn deleteOperandIsReadOnly(self: *Checker, operand: NodeId) bool {
        return switch (self.hir.kindOf(operand)) {
            .member_access => blk: {
                const m = hir_mod.memberOf(self.hir, operand);
                const obj_t = self.hir.typeOf(m.object);
                // Enum members are read-only (`enum E { A }; delete E.A`
                // → TS2704). Mirrors deleteOperatorWithEnumType.ts.
                if (self.identifierReferencesEnum(m.object)) break :blk true;
                if (obj_t == types.Primitive.none) break :blk false;
                if (self.enumNameFromNominal(obj_t) != null) break :blk true;
                break :blk self.propertyIsReadOnly(obj_t, m.name);
            },
            .element_access => blk: {
                const e = hir_mod.elementOf(self.hir, operand);
                if (self.hir.kindOf(e.index) != .literal_string) break :blk false;
                if (self.identifierReferencesEnum(e.object)) break :blk true;
                const obj_t = self.hir.typeOf(e.object);
                if (obj_t == types.Primitive.none) break :blk false;
                if (self.enumNameFromNominal(obj_t) != null) break :blk true;
                const key = hir_mod.literalStringOf(self.hir, e.index).value;
                break :blk self.propertyIsReadOnly(obj_t, key);
            },
            else => false,
        };
    }

    /// True when `node` is an identifier whose name binds to an enum
    /// declaration in the current scope. Used by delete-operand
    /// read-only detection for `delete E.A` / `delete E["A"]`.
    fn identifierReferencesEnum(self: *Checker, node: NodeId) bool {
        if (self.hir.kindOf(node) != .identifier) return false;
        const name = hir_mod.identifierOf(self.hir, node).name;
        return self.enumDeclForName(name) != null;
    }

    fn deleteOperandOptionalityAnchorPos(self: *Checker, operand: NodeId) ?u32 {
        if (self.hir.kindOf(operand) != .member_access) return null;
        const m = hir_mod.memberOf(self.hir, operand);
        if (!m.optional) return null;
        const src = self.source orelse return null;
        const object_span = self.hir.spanOf(m.object);
        if (object_span.end >= src.len or src[object_span.end] != ')') return null;
        return self.symbolOperandAnchorPos(m.object);
    }

    /// True when `t` looks array-like enough to destructure with an
    /// array binding pattern: an array/tuple object type whose number
    /// index resolves, or `any`/`unknown` (treated as opaque). Falls
    /// back to checking iterable-like for primitives like `string`.
    fn elemIsArrayLikeForForOfDestructure(self: *Checker, t: TypeId) bool {
        if (t == types.Primitive.any or t == types.Primitive.unknown) return true;
        if (t == types.Primitive.string_t) return true;
        if (t >= self.interner.pool.typeCount()) return false;
        const flags = self.interner.pool.flagsOf(t);
        if (flags.is_object_type) {
            if (self.interner.objectNumberIndex(t) != types.Primitive.none) return true;
            // Tuple shapes expose positional members but no number
            // indexer — treat presence of any `0`/`1`/... member as
            // array-like for destructure purposes.
            return self.isTupleShapedTarget(t);
        }
        if (flags.is_union) {
            for (self.interner.unionMembers(t)) |m| {
                if (!self.elemIsArrayLikeForForOfDestructure(m)) return false;
            }
            return true;
        }
        return false;
    }

    fn arrayElementType(self: *Checker, obj_t: TypeId) CheckError!TypeId {
        const flags = self.interner.pool.flagsOf(obj_t);
        if (flags.is_union) {
            const members = self.interner.unionMembers(obj_t);
            var elems: std.ArrayListUnmanaged(TypeId) = .empty;
            defer elems.deinit(self.gpa);
            for (members) |member_t| {
                const elem_t = self.interner.objectNumberIndex(member_t);
                if (elem_t == types.Primitive.none) return types.Primitive.none;
                try elems.append(self.gpa, elem_t);
            }
            if (elems.items.len == 0) return types.Primitive.none;
            return self.interner.internUnion(elems.items) catch return error.OutOfMemory;
        }
        return self.interner.objectNumberIndex(obj_t);
    }

    fn signaturePrototypeMember(self: *Checker, sig: TypeId, name: hir_mod.StringId) CheckError!?TypeId {
        if (!self.interner.isSignature(sig)) return null;
        const name_str = self.string_interner.get(name);
        if (!std.mem.eql(u8, name_str, "call") and
            !std.mem.eql(u8, name_str, "bind") and
            !std.mem.eql(u8, name_str, "apply"))
        {
            return null;
        }

        const params = self.interner.signatureParams(sig);
        const ret = self.interner.signatureReturn(sig) orelse types.Primitive.any;

        if (std.mem.eql(u8, name_str, "call")) {
            var call_params: std.ArrayListUnmanaged(TypeId) = .empty;
            defer call_params.deinit(self.gpa);
            try call_params.append(self.gpa, types.Primitive.any);
            try call_params.appendSlice(self.gpa, params);
            return try self.interner.internSignature(call_params.items, ret, false);
        }

        if (std.mem.eql(u8, name_str, "bind")) {
            var bind_params: std.ArrayListUnmanaged(TypeId) = .empty;
            defer bind_params.deinit(self.gpa);
            try bind_params.append(self.gpa, types.Primitive.any);
            try bind_params.appendSlice(self.gpa, params);
            const bind_sig = try self.interner.internSignature(bind_params.items, types.Primitive.any, false);
            var omittable: std.ArrayListUnmanaged(bool) = .empty;
            defer omittable.deinit(self.gpa);
            try omittable.append(self.gpa, false);
            var i: usize = 0;
            while (i < params.len) : (i += 1) try omittable.append(self.gpa, true);
            try self.recordSignatureMinArgs(bind_sig, omittable.items);
            return bind_sig;
        }

        var apply_params: [2]TypeId = undefined;
        apply_params[0] = types.Primitive.any;
        const rest_tuple = if (params.len == 0)
            self.interner.internArrayType(self.string_interner, types.Primitive.any) catch types.Primitive.any
        else blk: {
            const members = try self.gpa.alloc(TypeId, params.len);
            defer self.gpa.free(members);
            @memcpy(members, params);
            const union_t = self.interner.internUnion(members) catch types.Primitive.any;
            break :blk self.interner.internArrayType(self.string_interner, union_t) catch types.Primitive.any;
        };
        apply_params[1] = rest_tuple;
        return try self.interner.internSignature(&apply_params, ret, false);
    }

    fn lookupDeclaredArrayMember(self: *Checker, elem_t: TypeId, name: hir_mod.StringId) CheckError!?TypeId {
        const array_names = [_][]const u8{ "Array", "ReadonlyArray" };
        for (array_names) |array_name| {
            const array_id = self.string_interner.intern(array_name) catch return error.OutOfMemory;
            const info = self.generic_aliases.get(array_id) orelse continue;
            var inst_t = info.body;
            if (info.params.len > 0) {
                var subs: std.AutoHashMapUnmanaged(TypeId, TypeId) = .empty;
                defer subs.deinit(self.gpa);
                try subs.put(self.gpa, info.params[0], elem_t);
                var i: usize = 1;
                while (i < info.params.len) : (i += 1) {
                    const p = info.params[i];
                    if (!self.interner.pool.flagsOf(p).is_type_parameter) continue;
                    const tp = self.interner.pool.type_parameter_payloads.items[self.interner.pool.payloadOf(p)];
                    if (tp.default != types.Primitive.none) try subs.put(self.gpa, p, tp.default);
                }
                inst_t = try self.substituteType(info.body, &subs);
            }
            if (self.interner.objectMember(inst_t, name)) |member_t| return member_t;
        }
        return null;
    }

    fn constructorPrototypeAccess(self: *Checker, obj_name: hir_mod.StringId, prop_name: hir_mod.StringId) CheckError!?TypeId {
        if (!std.mem.eql(u8, self.string_interner.get(prop_name), "prototype")) return null;
        if (self.class_instance_types.get(obj_name)) |instance_t| return instance_t;
        var has_runtime_prototype = false;
        if (!has_runtime_prototype) {
            if (self.module) |module| {
                if (module.root.lookup(obj_name)) |sym| {
                    has_runtime_prototype = sym.flags.is_function or sym.flags.is_class;
                }
            }
        }
        if (!has_runtime_prototype) return null;
        return self.interner.internObjectTypeWithIndex(&.{}, types.Primitive.any, types.Primitive.none) catch return error.OutOfMemory;
    }

    /// Type an expression. Returns its TypeId and also records it
    /// in the HIR's types column.
    pub fn checkExpression(self: *Checker, node: NodeId) CheckError!TypeId {
        const t: TypeId = switch (self.hir.kindOf(node)) {
            .literal_string => types.Primitive.string_t,
            .template_literal => try self.checkTemplateLiteralExpression(node),
            .literal_number => types.Primitive.number_t,
            .literal_bigint => types.Primitive.bigint_t,
            .literal_bool => types.Primitive.boolean_t,
            .literal_null => types.Primitive.null_t,
            .literal_undefined => types.Primitive.undefined_t,
            .literal_regex => blk_regex: {
                try self.checkRegexFlagsForTarget(node);
                break :blk_regex self.lowerBuiltinObjectType("RegExp") orelse types.Primitive.object_t;
            },
            .identifier => self.typeOfIdentifier(node),
            .this_expr => try self.checkThisExpression(node),
            .spread => blk: {
                const sp = hir_mod.spreadOf(self.hir, node);
                break :blk try self.checkExpression(sp.expression);
            },
            .binary_op => try self.checkBinop(node),
            .unary_op => try self.checkUnary(node),
            .logical_op => try self.checkLogical(node),
            .conditional => try self.checkConditional(node),
            .assignment => blk: {
                const a = hir_mod.assignmentOf(self.hir, node);
                const target_kind = self.hir.kindOf(a.target);
                const is_synth_update = self.assignmentIsSynthesizedUpdate(node, a);
                const target_is_eval = target_kind == .identifier and
                    std.mem.eql(u8, self.string_interner.get(hir_mod.identifierOf(self.hir, a.target).name), "eval");
                var target_t = if (target_is_eval)
                    types.Primitive.any
                else if (target_kind == .identifier)
                    self.typeOfIdentifierDeclared(a.target)
                else if (target_kind == .array_literal or target_kind == .object_literal)
                    types.Primitive.none
                else blk_target: {
                    const prev_update_target = self.checking_update_assignment_target;
                    self.checking_update_assignment_target = is_synth_update;
                    defer self.checking_update_assignment_target = prev_update_target;
                    break :blk_target try self.checkExpression(a.target);
                };
                if (target_kind == .identifier and self.nodeIsInsideLoop(node)) {
                    if (self.visibleAnnotatedIdentifierType(a.target)) |annotated_t| {
                        target_t = annotated_t;
                    }
                }
                // For synth-update expressions (`x++` / `x--` desugared to
                // `x += 1` / `x -= 1`) the arithmetic-operand check
                // downstream uses `target_t` to validate that the operand
                // is number/bigint/enum/any. The declared type alone
                // doesn't reflect narrowing — `if (typeof x === "number")
                // { x++; }` declares `x: number | string` but the narrow
                // scope says `number`. Consult the narrow so guarded
                // arithmetic updates type-check. Mirrors tsc.
                if (is_synth_update and target_kind == .identifier) {
                    const id = hir_mod.identifierOf(self.hir, a.target);
                    if (self.lookupNarrow(id.name)) |narrowed_t| {
                        target_t = narrowed_t;
                    }
                }
                if (a.op == null and target_kind == .identifier and self.sourceHasCheckJsDirective()) {
                    if (try self.jsDocTypeForPreviousIdentifierDecl(a.target)) |declared_t| {
                        target_t = declared_t;
                    }
                }
                // `.js` files with `// @ts-check` may annotate
                // `Ctor.prototype = expr` with a leading
                // `/** @type {T} */`, in which case T becomes the
                // declared type of the prototype slot — assigning a
                // non-T value should report TS2322. The member-access
                // checker normally returns an open object shape for
                // `Ctor.prototype`, which would accept anything, so
                // we override the assignment target type here.
                // Mirrors upstream tsc for `typeTagPrototypeAssignment`.
                if (a.op == null and target_kind == .member_access and
                    self.sourceHasCheckJsDirective())
                {
                    if (try self.jsDocTypeForPrototypeAssignmentTarget(node, a.target)) |overridden_t| {
                        target_t = overridden_t;
                    }
                    if (self.commonJsModuleExportsPropertyName(a.target)) |prop_name| {
                        if (self.lookupCommonJsExportNarrow(try self.commonJsModuleExportsDirectKey())) |exports_t| {
                            if (!self.typeCanReceiveCommonJsExportProperty(exports_t) and
                                (try self.lookupObjectMember(exports_t, prop_name)) == null)
                            {
                                try self.reportPropertyDoesNotExistOnType(a.target, prop_name, exports_t);
                            }
                        }
                    }
                }
                // Reassignment clears any prior conditional alias for
                // the variable: `let cond = isString(x); cond = false;
                // if (cond) ...` — the second branch shouldn't
                // narrow `x` because `cond` is no longer the original
                // guard expression.
                var assignment_target_diag_fired = false;
                if (self.hir.kindOf(a.target) == .identifier) {
                    const id = hir_mod.identifierOf(self.hir, a.target);
                    _ = self.cond_aliases.remove(id.name);
                    try self.removeCondAliasesReferencing(id.name);
                    if (target_is_eval) {
                        try self.report(a.target, TsCodes.cannot_assign_to_function, "Cannot assign to 'eval' because it is a function.");
                    }
                    if (std.mem.eql(u8, self.string_interner.get(id.name), "undefined")) {
                        try self.report(a.target, TsCodes.cannot_assign_undefined, "Cannot assign to 'undefined' because it is not a variable.");
                    }
                    // TS2588: `const x = 1; x = 2;` — assigning to
                    // a const-bound identifier is a hard error.
                    if (self.identifierResolvesToConst(a.target)) {
                        const name_str = self.string_interner.get(id.name);
                        const msg = try std.fmt.allocPrint(
                            self.diag_arena.allocator(),
                            "Cannot assign to '{s}' because it is a constant.",
                            .{name_str},
                        );
                        try self.diagnostics.append(self.gpa, .{
                            .node = node,
                            .code = TsCodes.cannot_assign_const,
                            .message = msg,
                        });
                    }
                    // TS2628/TS2629/TS2631: enum/class/namespace names
                    // are value declarations but cannot be assignment
                    // targets. For `++E` / `C++`, tsc reports this
                    // target diagnostic instead of the arithmetic
                    // operand diagnostic.
                    if (a.op == null or is_synth_update) {
                        assignment_target_diag_fired = try self.reportIdentifierAssignmentTargetKind(a.target);
                    }
                }
                if (target_kind == .literal_undefined or self.nodeSourceTextIs(a.target, "undefined") or
                    (is_synth_update and self.typeIsExactUndefined(target_t)))
                {
                    try self.report(a.target, TsCodes.cannot_assign_undefined, "Cannot assign to 'undefined' because it is not a variable.");
                    assignment_target_diag_fired = true;
                }
                if (is_synth_update and self.updateOperandRequiresVariableDiagnostic(a.target, target_t)) {
                    try self.reportUpdateOperandRequiresVariable(a.target);
                }
                if (self.expressionIsOptionalChain(a.target)) {
                    // Distinguish synthetic update expressions
                    // (`++obj?.a` / `obj?.a++`, which the parser
                    // desugars to `obj?.a -= 1` / `+= 1`) from real
                    // assignments. tsc emits TS2777 for the former
                    // and TS2779 for the latter — see
                    // `propertyAccessChain.3.ts` / `elementAccessChain.3.ts`.
                    if (self.assignmentIsSynthesizedUpdate(node, a)) {
                        try self.report(a.target, TsCodes.optional_chain_increment_target, "The operand of an increment or decrement operator may not be an optional property access.");
                    } else {
                        try self.report(a.target, TsCodes.optional_chain_assignment_target, "The left-hand side of an assignment expression may not be an optional property access.");
                    }
                }
                // TS2540: assigning to a property declared `readonly`.
                // Object/interface readonly fields are immutable;
                // class-field readonly is approximated by the
                // constructor exception inside the helper. When the
                // readonly check fires, suppress the assignment-value
                // TS2322 below — tsc reports only the readonly error
                // (see `intersectionTypeReadonly.errors.txt(23,15)`,
                // where the intersection `Base & DifferentType`
                // reduces `value` to `never` but tsc still prints
                // just TS2540, not an additional TS2322).
                //
                // Enum-member assignment fires through a sibling helper
                // first (`E.A = null` mirrors `validNullAssignments.ts(10,3)`)
                // — when it emits, we also flip the flag so the
                // cascading TS2322 stays suppressed.
                var readonly_target_fired = try self.checkEnumMemberAssignment(a.target);
                if (self.hir.kindOf(a.target) == .member_access) {
                    readonly_target_fired = (try self.checkReadonlyAssignment(a.target)) or readonly_target_fired;
                    // tsc also emits TS2542 for `C.bar = ...` when the
                    // class has a readonly index signature and no
                    // concrete static member named `bar`. Mirrors
                    // `staticIndexSignature2.ts(7,1)`.
                    if (!readonly_target_fired) {
                        try self.checkReadonlyIndexAssignment(a.target);
                    }
                }
                if (self.hir.kindOf(a.target) == .element_access) {
                    try self.checkReadonlyIndexAssignment(a.target);
                }
                if (target_kind == .member_access) {
                    _ = try self.reportCheckJsPrototypeThisMissingMemberAssignment(a.target);
                }
                var value_t = try self.checkExpression(a.value);
                var assignment_check_value_t = if (self.hir.kindOf(a.value) == .identifier) blk_assign_value: {
                    if (try self.jsDocTypeForPreviousIdentifierDecl(a.value)) |declared_t| break :blk_assign_value declared_t;
                    const value_id = hir_mod.identifierOf(self.hir, a.value);
                    if (self.lookupNarrow(value_id.name) != null) break :blk_assign_value value_t;
                    break :blk_assign_value self.typeOfIdentifierDeclared(a.value);
                } else value_t;
                if (a.op == null) {
                    if (try self.contextualGenericCallResult(a.value, assignment_check_value_t, target_t)) |contextual_t| {
                        value_t = contextual_t;
                        assignment_check_value_t = contextual_t;
                    }
                }
                const target_is_destructuring = a.op == null and
                    (self.hir.kindOf(a.target) == .array_literal or self.hir.kindOf(a.target) == .object_literal);
                const target_is_untyped_uninitialized_var =
                    self.hir.kindOf(a.target) == .identifier and
                    target_t == types.Primitive.undefined_t and
                    self.identifierIsUntypedUninitializedVar(a.target);
                const commonjs_export_key = if (a.op == null and target_kind == .member_access)
                    try self.commonJsExportMemberKey(a.target)
                else
                    null;
                const checkjs_object_expando_key = if (a.op == null and target_kind == .member_access)
                    try self.checkJsObjectLiteralExpandoMemberKey(a.target)
                else
                    null;
                const target_is_commonjs_export_assignment = commonjs_export_key != null;
                var assignment_result_t = value_t;
                if (a.op == null) {
                    assignment_result_t = try self.flowTypeForAssignmentValue(a.value, value_t);
                    if (target_kind == .member_access and
                        assignment_result_t != types.Primitive.none and
                        assignment_result_t != types.Primitive.any and
                        assignment_result_t != types.Primitive.unknown)
                    {
                        if (commonjs_export_key) |key| {
                            try self.recordCommonJsExportNarrow(key, assignment_result_t);
                        }
                        if (target_kind == .member_access and self.memberAccessIsModuleExports(a.target)) {
                            try self.recordCommonJsExportNarrow(
                                try self.commonJsModuleExportsDirectKey(),
                                try self.commonJsExportAssignmentValueType(a.value),
                            );
                        }
                        if (checkjs_object_expando_key) |key| {
                            try self.recordCheckJsObjectExpandoNarrow(key, assignment_result_t);
                        }
                    }
                    const has_active_target_narrow = if (self.hir.kindOf(a.target) == .identifier)
                        self.lookupNarrow(hir_mod.identifierOf(self.hir, a.target).name) != null
                    else
                        false;
                    if ((!self.nodeIsInsideFunctionLike(node) or has_active_target_narrow or target_is_untyped_uninitialized_var) and
                        !self.nodeIsInsideLoop(node) and
                        self.hir.kindOf(a.target) == .identifier and
                        assignment_result_t != types.Primitive.none and
                        assignment_result_t != types.Primitive.any and
                        assignment_result_t != types.Primitive.unknown and
                        target_t != types.Primitive.any and
                        target_t != types.Primitive.unknown and
                        (target_is_untyped_uninitialized_var or
                            (try self.literalExpressionAssignableToTarget(a.value, target_t)) or
                            (self.engine.isAssignableTo(assignment_result_t, target_t) catch true)))
                    {
                        const target_id = hir_mod.identifierOf(self.hir, a.target);
                        try self.recordNarrow(target_id.name, assignment_result_t);
                    }
                    if (target_is_untyped_uninitialized_var and
                        assignment_result_t != types.Primitive.none and
                        assignment_result_t != types.Primitive.unknown)
                    {
                        try self.recordUntypedUninitializedVarAssignment(a.target, assignment_result_t);
                    }
                }
                if (a.op) |op| {
                    switch (op) {
                        .add => {
                            // tsc reports `s++` / `s--` (parser-desugared
                            // to `s += 1` / `s -= 1`) as TS2356 on the
                            // target operand when it's symbol-typed,
                            // NOT as the generic TS2469 from
                            // `checkCompoundAdditionAssignment`. Mirrors
                            // `symbolType4.ts(2,1)` / `(3,1)`.
                            if (assignment_target_diag_fired) {
                                // Target-kind errors (class/enum/namespace
                                // names and `undefined`) win over the
                                // synthetic `+= 1` operand diagnostics.
                            } else if (is_synth_update and self.updateOperandIsEnumBinaryExpression(a.target)) {
                                try self.reportArithmeticOperand(a.target, TsCodes.arithmetic_operand_type, "An arithmetic operand must be of type 'any', 'number', 'bigint' or an enum type.");
                            } else if (is_synth_update and (self.hir.kindOf(a.target) == .literal_null or self.nodeSourceTextIs(a.target, "null"))) {
                                try self.reportNullishRelationalOperand(a.target, target_t);
                            } else if (is_synth_update and
                                !self.isArithmeticOperandAllowed(target_t))
                            {
                                try self.reportArithmeticOperand(a.target, TsCodes.arithmetic_operand_type, "An arithmetic operand must be of type 'any', 'number', 'bigint' or an enum type.");
                            } else {
                                try self.checkCompoundAdditionAssignment(node, a.target, a.value, target_t, value_t);
                            }
                        },
                        .sub, .mul, .div, .mod, .pow, .bit_and, .bit_or, .bit_xor, .shl, .shr, .shr_unsigned => {
                            // tsc reports `++x` / `x--` operand-type
                            // violations as TS2356 ("An arithmetic
                            // operand must be …"), not TS2362/TS2363
                            // ("The left/right-hand side …"). The
                            // parser desugars update expressions into
                            // `target -= 1` / `target += 1`; detect
                            // that synthetic shape here so the
                            // diagnostic shape matches.
                            const arith_code = if (is_synth_update)
                                TsCodes.arithmetic_operand_type
                            else
                                TsCodes.arithmetic_left_operand_type;
                            const arith_msg = if (is_synth_update)
                                "An arithmetic operand must be of type 'any', 'number', 'bigint' or an enum type."
                            else
                                "The left-hand side of an arithmetic operation must be of type 'any', 'number', 'bigint' or an enum type.";
                            // tsc prefers TS18050 over TS2362/TS2363
                            // when an operand is exact-nullish. Real
                            // assignments only — synthesized updates
                            // never have a literal-null RHS. Skip
                            // untyped-uninitialized-var references
                            // (e.g. `var v; x *= v;`) since tsc treats
                            // those as `any` and emits nothing.
                            const value_is_untyped_uninit = self.hir.kindOf(a.value) == .identifier and
                                self.identifierIsUntypedUninitializedVar(a.value);
                            if (is_synth_update and self.updateOperandIsEnumBinaryExpression(a.target)) {
                                try self.reportArithmeticOperand(a.target, TsCodes.arithmetic_operand_type, "An arithmetic operand must be of type 'any', 'number', 'bigint' or an enum type.");
                            } else if (is_synth_update and (self.hir.kindOf(a.target) == .literal_null or self.nodeSourceTextIs(a.target, "null"))) {
                                try self.reportNullishRelationalOperand(a.target, target_t);
                            } else if (!is_synth_update and self.typeIsExactNullish(target_t)) {
                                try self.reportNullishRelationalOperand(a.target, target_t);
                            } else if (!assignment_target_diag_fired and !self.isArithmeticOperandAllowed(target_t)) {
                                try self.reportArithmeticOperand(a.target, arith_code, arith_msg);
                            }
                            // Skip the right-hand-side check for
                            // synthesized updates — the `1` is a
                            // compiler-inserted constant and reporting
                            // it confuses the diagnostic baseline.
                            if (!is_synth_update and !value_is_untyped_uninit and self.typeIsExactNullish(value_t)) {
                                try self.reportNullishRelationalOperand(a.value, value_t);
                            } else if (!is_synth_update and !self.isArithmeticOperandAllowed(value_t)) {
                                try self.reportArithmeticOperand(a.value, TsCodes.arithmetic_right_operand_type, "The right-hand side of an arithmetic operation must be of type 'any', 'number', 'bigint' or an enum type.");
                            }
                        },
                        else => {},
                    }
                }
                if (a.op == null and self.hir.kindOf(a.target) == .array_literal) {
                    try self.checkArrayDestructuringAssignment(a.target, value_t, a.value, 0);
                }
                if (a.op == null and self.hir.kindOf(a.target) == .object_literal) {
                    try self.checkObjectDestructuringAssignment(a.target, value_t, a.value);
                }
                // Note: an `array-literal vs tuple-shape` mismatch used to
                // emit a generic `Type is not assignable to target type.`
                // here, but the broader assignment-typing path below
                // already produces a richer `Type 'X' is not assignable
                // to type 'Y'.` diagnostic for the same case, leading to
                // duplicate TS2322 reports at the same position. The
                // generic emit is therefore suppressed; see
                // `wideningTuples4.ts(3,9)` for the motivating case.
                if (!target_is_destructuring and !target_is_untyped_uninitialized_var and !target_is_commonjs_export_assignment and a.op == null and self.classPrivateStructuralMismatch(target_t, value_t)) {
                    // Render `Type 'X' is not assignable to type 'Y'.`
                    // when both type names resolve; otherwise fall
                    // back to the terse form. Mirrors
                    // `assignmentCompatWithObjectMembersAccessibility.ts`
                    // baseline prose for class-private overlap mismatches.
                    try self.reportTypeNotAssignable(node, value_t, target_t, "Type is not assignable to declared type.");
                }
                if (!target_is_destructuring and !target_is_untyped_uninitialized_var and !target_is_commonjs_export_assignment and a.op == null and
                    !readonly_target_fired and
                    !assignment_target_diag_fired and
                    target_t != types.Primitive.none and
                    target_t != types.Primitive.any and
                    target_t != types.Primitive.unknown)
                {
