test "checker: TS2454 fires for every use of unassigned typed var" {
    // tsc emits TS2454 once per use site (not just on the first read).
    // The §6.A exact-baseline ratchet pins this — keeping `pending`
    // populated after the first emit lets later reads also fire.
    const s = try newSetup(
        \\interface I { foo: number; bar: number; }
        \\var i: I;
        \\var x = i.foo;
        \\var y = i.bar;
        \\var z = i.foo;
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var count: usize = 0;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.used_before_assignment) count += 1;
    }
    try T.expect(count >= 3);
}

test "checker: TS2454 prunes dead branches for short-circuit constant conditions" {
    // `true || rhs` is a compile-time-constant `true`, so a TS2454
    // scan should suppress the else-arm read of `y`. Mirrors
    // `conditionalOperatorConditionIsBooleanType` (line 37: only the
    // then-arm fires for `true || false ? x : y`).
    const s = try newSetup(
        \\var x: Object;
        \\var y: Object;
        \\true || false ? x : y;
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var x_count: usize = 0;
    var y_count: usize = 0;
    for (s.checker.diagnostics.items) |d| {
        if (d.code != TsCodes.used_before_assignment) continue;
        if (std.mem.indexOf(u8, d.message, "'x'") != null) x_count += 1;
        if (std.mem.indexOf(u8, d.message, "'y'") != null) y_count += 1;
    }
    try T.expect(x_count >= 1);
    try T.expectEqual(@as(usize, 0), y_count);
}

test "checker: TS2454 fires for both target receiver and rhs of assignment" {
    // tsc emits TS2454 for `c` on both sides of `c.x = c.y` (target's
    // member-access receiver and the rhs identifier). Source ordering
    // matters for the exact-baseline diff so the target's receiver
    // walks first.
    const s = try newSetup(
        \\interface I { x: number; y: number; }
        \\var c: I;
        \\c.x = c.y;
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var count: usize = 0;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.used_before_assignment) count += 1;
    }
    try T.expect(count >= 2);
}

