    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.missing_override);
        try T.expect(d.code != TsCodes.override_not_in_base);
        try T.expect(d.code != TsCodes.override_not_in_base_did_you_mean);
    }
}

