test "checker: TS2564 fires on uninitialized private (#name) fields" {
    // Mirrors upstream tsc: `class { #foo: string; }` without an
    // initializer or constructor assignment must report TS2564, the
    // same as ordinary identifier-named fields. Regression for
    // `privateNameDeclaration` conformance baseline.
    const s = try newSetup(
        \\class A {
        \\    #foo: string;
        \\    baz: string;
        \\}
    );
    defer destroySetup(s);
    s.checker.setStrictFlags(.{ .strict_property_initialization = true, .strict_null_checks = true });
    try s.checker.checkSourceFile(s.root);
    var private_count: usize = 0;
    var public_count: usize = 0;
    for (s.checker.diagnostics.items) |d| {
        if (d.code != TsCodes.property_not_initialized) continue;
        if (std.mem.indexOf(u8, d.message, "'#foo'") != null) private_count += 1;
        if (std.mem.indexOf(u8, d.message, "'baz'") != null) public_count += 1;
    }
    try T.expectEqual(@as(usize, 1), private_count);
    try T.expectEqual(@as(usize, 1), public_count);
}

test "checker: noImplicitAny skips TS7008 on ambient `declare class` members" {
    // Mirrors upstream tsc: a `declare class` member without an annotation
    // is intentionally implicit-any in the ambient world and must not raise
    // TS7008. Only the checked, non-ambient sibling class should report.
    // Regression for conformance fixture `privateNameAmbientNoImplicitAny`,
    // including the private-name (`#prop`) shape the upstream fixture uses.
    const s = try newSetup(
        \\declare class A {
        \\    #prop;
        \\}
        \\class B {
        \\    #prop;
        \\}
    );
    defer destroySetup(s);
    s.checker.setStrictFlags(.{ .no_implicit_any = true });
    try s.checker.checkSourceFile(s.root);
    var count: usize = 0;
    var declare_count: usize = 0;
    for (s.checker.diagnostics.items) |d| {
        if (d.code != TsCodes.member_implicitly_any) continue;
        count += 1;
        // Crude positional heuristic: the diagnostic node lives inside
        // the `declare class A` body when its source position falls
        // before the second `class` keyword in the fixture.
        const src = "declare class A {\n    #prop;\n}\nclass B {\n    #prop;\n}";
        const pos = d.pos orelse s.hir.spanOf(d.node).start;
        const second_class = std.mem.indexOfPos(u8, src, 1, "class B") orelse src.len;
        if (pos < second_class) declare_count += 1;
    }
    try T.expectEqual(@as(usize, 1), count);
    try T.expectEqual(@as(usize, 0), declare_count);
}

test "checker: TS2610 on parameter-property anchors at property name" {
    // For `constructor(public p: string)`, tsc anchors TS2610 at the
    // property name `p` (column 24 in the upstream fixture), not at
    // the leading `public` modifier. Regression for
    // `propertyOverridesAccessors5` conformance baseline.
    const src =
        \\class A {
        \\    get p() { return 'oh no' }
        \\}
        \\class B extends A {
        \\    constructor(public p: string) {
        \\        super()
        \\    }
        \\}
    ;
    const s = try newSetup(src);
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var found_pos: ?u32 = null;
    for (s.checker.diagnostics.items) |d| {
        if (d.code != TsCodes.property_overrides_accessor) continue;
        found_pos = d.pos orelse s.hir.spanOf(d.node).start;
    }
    const pos = found_pos orelse return error.TestExpectedEqual;
    // The expected anchor is the `p` immediately after `public `.
    const expected = std.mem.indexOf(u8, src, "public p:").? + "public ".len;
    try T.expectEqual(@as(u32, @intCast(expected)), pos);
}

test "checker: TS7010 skips setter accessor (always returns void)" {
    // Setters always return void; tsc never emits TS7010 for them
    // (`'sound', which lacks return-type annotation, implicitly has
    // an 'any' return type.`). Regression for conformance fixture
    // `propertyOverridesAccessors4`, which contains a bodyless
    // `set sound(val: string)` inside `declare class`.
    const s = try newSetup(
        \\declare class Animal {
        \\    get sound(): string
        \\    set sound(val: string)
        \\}
    );
    defer destroySetup(s);
    s.checker.setStrictFlags(.{ .no_implicit_any = true });
    try s.checker.checkSourceFile(s.root);
    for (s.checker.diagnostics.items) |d| {
