    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var ts2353 = false;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.object_literal_excess_property) ts2353 = true;
    }
    try T.expect(ts2353);
}

