test "checker: TS2724 single-char typo skips spelling suggestion" {
    // Threshold mirrors tsc's `getSpellingSuggestion`
    // `min(floor(name.length * 0.4), 4)`. For a 1-char typo the
    // threshold collapses to 0, so a 1-char export like `_` is
    // never proposed as a fix for `A`, `B`, `C`. Baseline shape
    // is bare TS2305, not TS2724.
    const s = try newSetup(
        \\// @filename: c.ts
        \\export const _ = 1;
        \\// @filename: d.ts
        \\import { A, B, C } from "./c";
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.no_exported_member_suggestion);
    }
}

test "checker: TS2724 short typo with far candidate is suppressed" {
    // 2-char typo `xy` vs candidate `abc` is distance 3;
    // threshold for length 2 is floor(2 * 0.4) = 0 so the
    // suggestion is suppressed. The old `max(2, len/4)` gate
    // would have accepted distance up to 2 here.
    const s = try newSetup(
        \\// @filename: a.ts
        \\export const abc = 1;
        \\// @filename: b.ts
        \\import { xy } from "./a";
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.no_exported_member_suggestion);
    }
}

test "checker: TS2724 suggests close-spelled relative virtual export" {
    // Mirrors `exportSpellingSuggestion.ts`: importing the typo
    // `assertNevar` from a sibling file that exports `assertNever`
    // must yield TS2724 with the "Did you mean" suggestion form,
    // not the bare TS2305. The wrapping in the message is
    // `'"./a"'` to match the conformance baseline shape.
    const s = try newSetup(
        \\// @module: commonjs
        \\// @target: es2015
        \\// @filename: a.ts
        \\export function assertNever(x: never, msg: string) {
        \\    throw new Error("Unexpected " + msg);
        \\}
        \\
        \\// @filename: b.ts
        \\import { assertNevar } from "./a";
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var found = false;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.no_exported_member_suggestion and
            std.mem.indexOf(u8, d.message, "'\"./a\"'") != null and
            std.mem.indexOf(u8, d.message, "'assertNevar'") != null and
            std.mem.indexOf(u8, d.message, "Did you mean 'assertNever'") != null)
        {
            found = true;
        }
    }
    try T.expect(found);
}

