    var found = false;
    for (s.checker.diagnostics.items) |d| {
        if (d.code != TsCodes.yield_star_not_iterable) continue;
        if (std.mem.indexOf(u8, d.message, "Type 'SymbolIterator' must have") == null) continue;
        found = true;
        break;
    }
    try T.expect(found);
}

