    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.type_not_assignable);
    }
}

test "checker: conditional then-branch narrows optional member" {
    // `obj.x ? obj.x.length : 0` — the then-branch picks up
