    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var count: usize = 0;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.top_level_await_target_module) count += 1;
    }
    try T.expectEqual(@as(usize, 2), count);
}

