        \\    var y: this;
        \\    return this;
        \\}
        \\
        \\interface I1 {
        \\    a: { x: this };
        \\    b: { (): this };
        \\    c: { new (): this };
        \\    d: { [x: string]: this };
        \\    e: { f(x: this): this };
        \\}
        \\
        \\class C1 {
        \\    a: { x: this };
        \\    b: { (): this };
        \\    c: { new (): this };
        \\    d: { [x: string]: this };
        \\    e: { f(x: this): this };
        \\}
        \\
        \\class C2 {
        \\    static x: this;
        \\    static y = <this>undefined;
        \\    static foo(x: this): this {
        \\        return undefined as any;
        \\    }
        \\}
    );
    defer destroyBoundSetup(b);
    try b.base.checker.checkSourceFile(b.base.root);
    var hits: usize = 0;
