}

test "checker: for-of excess declaration visits computed binding key" {
    // Mirrors `for-of-excess-declarations`: the parser preserves the
    // malformed extra declarator inside a synthetic for-of target block.
    // The checker should still visit its computed binding key after the
    // parser-owned TS1188.
    const s = try newSetup("for (const a, { [b]: c } of [1]) {}");
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var found_2304 = false;
    var found_2538 = false;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.cannot_find_name) found_2304 = true;
        if (d.code == TsCodes.type_cannot_be_used_as_index) found_2538 = true;
    }
    try T.expect(found_2304);
    try T.expect(found_2538);
}

test "checker: default export merging with namespace and interface anchors at name" {
    // Mirrors upstream `defaultExportsCannotMerge01`: a default
    // exported function + interface (type-only, doesn't conflict) +
    // namespace (instantiated, adds value-space) emits TS2652
    // anchored at the *function name* and at the *namespace name*,
    // skipping the interface (whose Type space doesn't intersect
    // the function's Value-only space).
    const s = try newSetup(
        \\export default function Decl() { return 0; }
        \\export interface Decl { p1: number; }
        \\export namespace Decl { export var x = 10; }
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var count_2652: usize = 0;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.default_export_merge) count_2652 += 1;
    }
    try T.expectEqual(@as(usize, 2), count_2652);
}

test "checker: default export merging with class and interface emits paired TS2652" {
    // Mirrors upstream `defaultExportsCannotMerge02`: default class
    // + interface + uninstantiated namespace. Class (Type|Value)
    // intersects interface (Type) on the Type space, so TS2652
    // fires on both — the namespace's Namespace-only space does
    // not intersect and is skipped.
    const s = try newSetup(
        \\export default class Decl {}
        \\export interface Decl { p1: number; }
        \\export namespace Decl { interface I {} }
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var count_2652: usize = 0;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.default_export_merge) count_2652 += 1;
    }
    try T.expectEqual(@as(usize, 2), count_2652);
}

test "checker: same-named declarations in different virtual sections do NOT trigger TS2395" {
    // Regression for upstream `importCallExpressionES{5,6}{AMD,CJS,System,UMD}`
    // and `importCallExpressionIn{AMD1,CJS1,System1,UMD1}`: multi-file
    // fixtures concatenate `export function foo()` in `0.ts` with a
    // sibling `function foo()` in `1.ts` (different modules). They
    // are distinct symbols and must NOT bucket into a single merge
    // candidate that fires TS2395 across the file boundary.
    const s = try newSetup(
        \\// @filename: 0.ts
        \\export function foo() { return "foo"; }
        \\// @filename: 1.ts
        \\function foo() {}
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    for (s.checker.diagnostics.items) |d| {
        try T.expect(d.code != TsCodes.declarations_must_all_be_exported_or_local);
    }
}

test "checker: default export merging with mixed export status emits TS2395 too" {
    // Mirrors upstream `defaultExportsCannotMerge04`: default fn +
    // namespace (Namespace|Value) yields paired TS2652, and the
    // two interfaces that disagree on `export` status yield paired
    // TS2395 ("all exported or all local").
    const s = try newSetup(
        \\export default function Foo() {}
        \\namespace Foo { export var x; }
        \\interface Foo {}
        \\export interface Foo {}
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var count_2652: usize = 0;
    var count_2395: usize = 0;
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.default_export_merge) count_2652 += 1;
        if (d.code == TsCodes.declarations_must_all_be_exported_or_local) count_2395 += 1;
    }
    try T.expectEqual(@as(usize, 2), count_2652);
    try T.expectEqual(@as(usize, 2), count_2395);
}

test "checker: TS1093 fires on constructor return-type annotation and TS2355 stays silent" {
    // Mirrors upstream `parserConstructorDeclaration10.ts(2,18)` — the
    // parser emits TS1093 anchored at the return-type node, and the
    // checker suppresses TS2355 ("must return a value") so the
    // baseline matches.
    const s = try newSetup(
        \\class C {
        \\  constructor(): number { }
        \\}
    );
    defer destroySetup(s);
    try s.checker.checkSourceFile(s.root);
    var count_1093: usize = 0;
    var count_2355: usize = 0;
    for (s.parser.diagnostics.items) |d| {
        if (d.code == 1093) count_1093 += 1;
    }
    for (s.checker.diagnostics.items) |d| {
        if (d.code == TsCodes.fn_must_return_value) count_2355 += 1;
    }
    try T.expectEqual(@as(usize, 1), count_1093);
    try T.expectEqual(@as(usize, 0), count_2355);
}
